{
  "name": "Dong-A AI Newsroom",
  "description": "An AI-powered assistant for journalists at Dong-A Ilbo, featuring AI writing, image generation, audio news, and headline optimization.",
  "requestFramePermissions": [
    "microphone"
  ]
}

export interface ArticleIdea {
  id: string;
  title: string;
  category: string;
  status: 'Draft' | 'Research' | 'Published';
  createdAt: string;
}

export interface AIArticleResponse {
  title: string;
  body: string[];
  keywords: string[];
}

export interface HeadlineOption {
  type: 'Formal' | 'Viral' | 'Emotional';
  text: string;
}

export interface NetizenReaction {
  user: string;
  comment: string;
  likes: number;
}

export type ViewType = 'dashboard' | 'writer' | 'illustrator' | 'headline' | 'netizen' | 'trot';

import { GoogleGenAI, Type, Modality } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY! });

export const generateArticle = async (prompt: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `주제: ${prompt}. 동아일보 기자 스타일로 정중하고 전문적인 기사 초안을 작성해주세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          body: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "3개의 문단으로 구성된 본문" 
          },
          keywords: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          },
        },
        required: ["title", "body", "keywords"],
      },
    },
  });
  return JSON.parse(response.text);
};

export const generateHeadlines = async (topic: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `기사 주제: ${topic}. 다음 3가지 스타일로 제목을 지어주세요: 1. 정론지(신뢰), 2. 바이럴(클릭 유도), 3. 감성(독자 공감).`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            type: { type: Type.STRING },
            text: { type: Type.STRING },
          },
        },
      },
    },
  });
  return JSON.parse(response.text);
};

export const generateComments = async (content: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `기사 내용: ${content}. 이 기사가 출고되었을 때 예상되는 네티즌의 반응(베스트 댓글) 5개를 생성해주세요.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            user: { type: Type.STRING },
            comment: { type: Type.STRING },
            likes: { type: Type.NUMBER },
          },
        },
      },
    },
  });
  return JSON.parse(response.text);
};

export const generateNewsImage = async (prompt: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [{ text: `A high-quality news editorial photo about: ${prompt}. Professional lighting, 8k resolution, journalistic style.` }]
    },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  return null;
};

export const generateTrotLyrics = async (article: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `다음 기사 내용을 흥겨운 '트로트 가사'로 바꿔주세요. 4/4박자의 느낌이 나도록 흥겹고 반복적인 문구를 섞어주세요: ${article}`,
  });
  return response.text;
};

export const speakTrot = async (lyrics: string) => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `Say this with a very high-energy, joyful, and slightly exaggerated trot singer tone: ${lyrics}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Puck' },
        },
      },
    },
  });
  return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
};

export const decodeAudio = async (base64: string, ctx: AudioContext) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const dataInt16 = new Int16Array(bytes.buffer);
  const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  return buffer;
};

