import React, { useState, useEffect } from 'react';
import { ArticleIdea } from '../types';
import { Plus, Search, MoreVertical, Clock, CheckCircle2, FileText } from 'lucide-react';

const Dashboard: React.FC = () => {
  const [ideas, setIdeas] = useState<ArticleIdea[]>([]);
  const [search, setSearch] = useState('');

  useEffect(() => {
    const saved = localStorage.getItem('article_ideas');
    if (saved) {
      setIdeas(JSON.parse(saved));
    } else {
      const initial: ArticleIdea[] = [
        { id: '1', title: '인공지능이 바꾸는 한국의 저널리즘', category: 'Tech', status: 'Draft', createdAt: '2024-03-20' },
        { id: '2', title: '청년층의 뉴스 소비 트렌드 변화', category: 'Society', status: 'Research', createdAt: '2024-03-19' },
        { id: '3', title: '글로벌 경제 위기와 반도체 시장', category: 'Economy', status: 'Published', createdAt: '2024-03-18' },
      ];
      setIdeas(initial);
      localStorage.setItem('article_ideas', JSON.stringify(initial));
    }
  }, []);

  const addIdea = () => {
    const newIdea: ArticleIdea = {
      id: Date.now().toString(),
      title: '새로운 기사 아이디어',
      category: 'General',
      status: 'Draft',
      createdAt: new Date().toISOString().split('T')[0],
    };
    const updated = [newIdea, ...ideas];
    setIdeas(updated);
    localStorage.setItem('article_ideas', JSON.stringify(updated));
  };

  const filteredIdeas = ideas.filter(i => i.title.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-3xl font-bold mb-2">기획실</h2>
          <p className="text-slate-400">당신의 혁신적인 뉴스 기획을 한눈에 관리하세요.</p>
        </div>
        <button 
          onClick={addIdea}
          className="flex items-center gap-2 blue-gradient px-6 py-3 rounded-xl font-bold text-white blue-glow transition-all"
        >
          <Plus size={20} />
          아이디어 추가
        </button>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
        <input 
          type="text" 
          placeholder="아이디어 검색..."
          className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-12 pr-4 focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredIdeas.map((idea) => (
          <div key={idea.id} className="glass-card rounded-2xl p-6 group hover:border-blue-500/30 transition-all cursor-pointer">
            <div className="flex justify-between items-start mb-4">
              <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                idea.status === 'Published' ? 'bg-green-500/10 text-green-400' :
                idea.status === 'Research' ? 'bg-amber-500/10 text-amber-400' :
                'bg-blue-500/10 text-blue-400'
              }`}>
                {idea.status}
              </span>
              <button className="text-slate-600 hover:text-slate-400 transition-colors">
                <MoreVertical size={18} />
              </button>
            </div>
            <h3 className="font-bold text-lg mb-4 line-clamp-2 group-hover:text-blue-400 transition-colors">
              {idea.title}
            </h3>
            <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-800 text-slate-500 text-xs">
              <div className="flex items-center gap-1">
                <Clock size={14} />
                {idea.createdAt}
              </div>
              <div className="flex items-center gap-1">
                <FileText size={14} />
                {idea.category}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { generateArticle } from '../services/gemini';
import { AIArticleResponse } from '../types';
import { Sparkles, Loader2, Copy, Send } from 'lucide-react';

const AIWriter: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<AIArticleResponse | null>(null);

  const handleGenerate = async () => {
    if (!topic) return;
    setLoading(true);
    try {
      const data = await generateArticle(topic);
      setResult(data);
    } catch (error) {
      console.error(error);
      alert('기사 생성 중 오류가 발생했습니다.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold mb-2">AI Writer</h2>
          <p className="text-slate-400">단 몇 초 만에 완성도 높은 뉴스 초안을 작성합니다.</p>
        </div>
      </div>

      <div className="glass-card rounded-3xl p-8 space-y-6">
        <div className="space-y-2">
          <label className="text-sm font-medium text-slate-400">기사 주제 또는 핵심 문구</label>
          <div className="flex gap-4">
            <input 
              type="text" 
              placeholder="예: 서울 도심 드론 택시 상용화 현장 취재..."
              className="flex-1 bg-slate-800 border border-slate-700 rounded-xl py-4 px-6 focus:outline-none focus:ring-2 focus:ring-blue-500/50"
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
            />
            <button 
              onClick={handleGenerate}
              disabled={loading || !topic}
              className="blue-gradient px-8 py-4 rounded-xl font-bold text-white flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed hover:blue-glow transition-all"
            >
              {loading ? <Loader2 className="animate-spin" size={20} /> : <Sparkles size={20} />}
              기사 생성
            </button>
          </div>
        </div>

        {result && (
          <div className="mt-8 space-y-6 animate-in fade-in duration-500">
            <div className="flex justify-between items-center border-b border-slate-800 pb-4">
              <h3 className="text-2xl font-black text-white">{result.title}</h3>
              <button className="text-slate-500 hover:text-blue-400 transition-colors">
                <Copy size={20} />
              </button>
            </div>

            <div className="space-y-6 text-slate-300 leading-relaxed text-lg">
              {result.body.map((para, idx) => (
                <p key={idx}>{para}</p>
              ))}
            </div>

            <div className="flex flex-wrap gap-2 pt-6">
              {result.keywords.map((kw, idx) => (
                <span key={idx} className="bg-blue-900/30 text-blue-400 border border-blue-800/50 px-3 py-1 rounded-lg text-sm font-medium">
                  #{kw}
                </span>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIWriter;

