import React, { useState, useRef } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Loader2, Music4 } from 'lucide-react';

const AudioNews: React.FC = () => {
  const [article, setArticle] = useState('');
  const [lyrics, setLyrics] = useState('');
  const [loading, setLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  const handleTrotify = async () => {
    if (!article) return;
    setLoading(true);
    setLyrics('');
    try {
      const trotLyrics = await generateTrotLyrics(article);
      setLyrics(trotLyrics);

      const audioData = await speakTrot(trotLyrics);
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        }
        const buffer = await decodeAudio(audioData, audioContextRef.current);
        playBuffer(buffer);
      }
    } catch (error) {
      console.error(error);
      alert('오디오 생성 중 오류가 발생했습니다.');
    } finally {
      setLoading(false);
    }
  };

  const playBuffer = (buffer: AudioBuffer) => {
    if (!audioContextRef.current) return;

    // Stop previous
    if (sourceNodeRef.current) {
      sourceNodeRef.current.stop();
    }

    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current.destination);
    source.onended = () => setIsPlaying(false);

    source.start(0);
    sourceNodeRef.current = source;
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (isPlaying) {
      sourceNodeRef.current?.stop();
      setIsPlaying(false);
    } else {
      // Re-trigger generation/play logic if lyrics exist
      if (lyrics) handleTrotify();
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex items-center gap-4">
        <div className="w-16 h-16 bg-gradient-to-br from-pink-500 to-amber-500 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-pink-500/20">
          <Music size={32} />
        </div>
        <div>
          <h2 className="text-3xl font-bold mb-1">오디오 뉴스 (Trot TTS)</h2>
          <p className="text-slate-400">딱딱한 뉴스를 신나는 트로트로! 독창적인 엔터테인먼트 뉴스 서비스입니다.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="glass-card rounded-3xl p-8 space-y-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-400">트로트로 변환할 기사</label>
            <textarea 
              rows={8}
              placeholder="뉴스를 입력하세요..."
              className="w-full bg-slate-800 border border-slate-700 rounded-xl py-4 px-6 focus:outline-none focus:ring-2 focus:ring-pink-500/50"
              value={article}
              onChange={(e) => setArticle(e.target.value)}
            />
          </div>
          <button 
            onClick={handleTrotify}
            disabled={loading || !article}
            className="w-full bg-gradient-to-r from-pink-600 to-amber-600 py-4 rounded-xl font-bold text-white flex items-center justify-center gap-2 disabled:opacity-50 hover:shadow-lg hover:shadow-pink-600/20 transition-all"
          >
            {loading ? <Loader2 className="animate-spin" size={20} /> : <Music4 size={20} />}
            트로트로 변환 및 재생
          </button>
        </div>

        <div className={`glass-card rounded-3xl p-8 flex flex-col items-center justify-center text-center transition-all ${isPlaying ? 'border-pink-500/50 bg-pink-500/5' : ''}`}>
          {loading ? (
            <div className="flex flex-col items-center gap-4 text-pink-400">
              <Loader2 className="animate-spin" size={48} />
              <p className="font-bold">가사 쓰는 중... 얼쑤!</p>
            </div>
          ) : lyrics ? (
            <div className="w-full space-y-6">
              <div className="w-32 h-32 mx-auto rounded-full bg-slate-800 flex items-center justify-center border-4 border-slate-700 group relative">
                {isPlaying && <div className="absolute inset-0 rounded-full border-4 border-pink-500 animate-ping opacity-20"></div>}
                <button 
                  onClick={togglePlay}
                  className="w-20 h-20 bg-pink-500 rounded-full flex items-center justify-center text-white hover:scale-110 transition-transform shadow-xl shadow-pink-500/40"
                >
                  {isPlaying ? <Pause size={32} /> : <Play size={32} fill="white" />}
                </button>
              </div>
              <div className="space-y-2">
                <h3 className="text-xl font-bold text-pink-400 italic">"동아 AI 뉴스 트로트 Ver."</h3>
                <div className="max-h-48 overflow-y-auto bg-slate-900/50 p-6 rounded-2xl border border-slate-800 text-slate-300 leading-relaxed italic">
                  {lyrics.split('\n').map((line, i) => (
                    <p key={i}>{line}</p>
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <div className="text-slate-700 flex flex-col items-center gap-4">
              <Music size={64} />
              <p>기사를 입력하고 트로트 뉴스를 들어보세요!</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default AudioNews;

import React, { useState } from 'react';
import { ViewType } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AIWriter from './components/AIWriter';
import AIIllustrator from './components/AIIllustrator';
import HeadlineAI from './components/HeadlineAI';
import NetizenSimulator from './components/NetizenSimulator';
import AudioNews from './components/AudioNews';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');

  const renderView = () => {
    switch (activeView) {
      case 'dashboard': return <Dashboard />;
      case 'writer': return <AIWriter />;
      case 'illustrator': return <AIIllustrator />;
      case 'headline': return <HeadlineAI />;
      case 'netizen': return <NetizenSimulator />;
      case 'trot': return <AudioNews />;
      default: return <Dashboard />;
    }
  };

  return (
    <Layout activeView={activeView} setActiveView={setActiveView}>
      {renderView()}
    </Layout>
  );
};

export default App;

