# 1. 기사 생성 (가짜 모드 - 0.5초 컷)
@require_POST
def generate_content(request):
    try:
        # 실제로는 여기서 Google API를 호출하지만, 속도를 위해 Mocking 처리
        fake_article = """
        **[속보] AI 뉴스룸 리뉴얼, '속도'와 '혁신' 두 마리 토끼 잡았다**

        동아일보의 차세대 AI 뉴스룸이 대대적인 리뉴얼을 마쳤다. 이번 업데이트의 핵심은 '경량화'다. 불필요한 리소스를 제거하고 핵심 엔진만 남겨, 기존 대비 300% 이상 빨라진 반응 속도를 자랑한다.

        **1. 기자의 시간을 아껴주는 '초고속 비서'**
        기존에 5초 이상 걸리던 기사 초안 생성이 이제 1초 미만으로 단축되었다. 기자가 아이디어만 입력하면, AI가 즉시 3가지 관점의 제목과 본문을 쏟아낸다. 이는 "기자의 직관을 기술로 뒷받침한다"는 개발 철학이 반영된 결과다.

        **2. 재미까지 잡았다... '트로트 모드' 화제**
        딱딱한 기사를 흥겨운 가락으로 바꿔주는 '뽕짝 뉴스' 기능은 사내 테스트에서 폭발적인 반응을 얻었다. 단순한 텍스트 변환을 넘어, 오디오 경험까지 확장한 이번 시도는 미디어 업계에 신선한 충격을 주고 있다.
        """
        return JsonResponse({'status': 'success', 'result': fake_article})
    except Exception as e:
        return JsonResponse({'status': 'error', 'message': str(e)}, status=500)

# 2. 제목 학원 (랜덤 추천)
@require_POST
def recommend_headlines(request):
    headlines = {
        "formal": "AI 뉴스룸 고도화... 미디어 DX의 새로운 표준 제시",
        "viral": "충격! 기자가 엔터키 치자마자 벌어진 일 (영상)",
        "emotional": "우리가 꿈꾸던 미래의 뉴스룸, 마침내 현실이 되다"
    }
    return JsonResponse({'status': 'success', 'headlines': headlines})

# 3. 댓글 예측 (랜덤 드립)
@require_POST
def simulate_comments(request):
    users = ["팩트폭격기", "주식물린개미", "동아구독자", "지나가던개발자", "AI신봉자"]
    texts = [
        "와... 진짜 세상 좋아졌다. 이게 된다고?",
        "기자님들 이제 AI한테 일 다 맡기고 칼퇴 하시겠네 ㅋㅋ",
        "그래서 이 기능 언제 정식 출시하나요? 저도 좀 씁시다.",
        "형들 이거 진짜야? 퀄리티 미쳤는데?",
        "테슬라 팔고 동아일보 주식 사고 싶다 (상장 안 함?)"
    ]
    comments = []
    for _ in range(5):
        comments.append({
            "user": random.choice(users) + "***",
            "text": random.choice(texts),
            "likes": random.randint(10, 1000)
        })
    comments.sort(key=lambda x: x['likes'], reverse=True)
    return JsonResponse({'status': 'success', 'comments': comments})

# 4. 트로트 가사 변환 (작사 기능)
@require_POST
def convert_to_trot(request):
    # 가사는 간단하게 템플릿으로 처리 (필요시 API 연결)
    lyrics = """
    **[제목: 야속한 마감시간]**
    **(쿵짝 쿵짝 쿵짜라 쿵짝)**

    **[1절]**
    기사 한 줄 쓰려하니 마감이 닥쳐오네 (어이!)
    데스크 불호령에 내 가슴만 타는구나
