import React, { useState } from 'react';

const AudioNews: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [lyrics, setLyrics] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  // 1. 트로트 변환 함수 (가짜 AI)
  const handleConvert = () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setLyrics(null); // 기존 가사 초기화

    // 0.8초 뒤에 결과가 짠! 하고 나타나는 연출
    setTimeout(() => {
      const mockLyrics = `
**(전주: 쿵짝 쿵짝 쿵짜라 쿵짝~)**

**[1절]**
${inputText.slice(0, 10)}... 소식 들었소 (어이!)
세상 돌아가는 꼴이 요지경일세
팩트 체크 해봤나 기자가 뛴다 (지화자!)

**[후렴]**
특종이다 특종이야~ 동아일보 특종이야~
오늘도 우리는 진실을 향해 달린다~
(얼쑤! 좋다!)
      `;
      setLyrics(mockLyrics);
      setIsLoading(false);
      setIsPlaying(true); // 변환 즉시 재생 상태로
    }, 800);
  };

  // 2. 재생 토글 함수
  const togglePlay = () => {
    setIsPlaying(!isPlaying);
  };

  return (
    <div className="container py-4">
      <div className="text-center mb-5">
        <h2 className="display-6 fw-bold text-white mb-2">
          <span className="text-gradient-primary">오디오 뉴스 (Trot TTS)</span>
        </h2>
        <p className="text-secondary">딱딱한 뉴스를 신나는 트로트로! 독창적인 엔터테인먼트 뉴스 서비스입니다.</p>
      </div>

      <div className="row g-4">
        {/* 입력 카드 */}
        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column">
            <label className="form-label text-white fw-bold mb-3">트로트로 변환할 기사</label>
            <textarea
              className="form-control bg-dark text-white border-secondary mb-3 flex-grow-1"
              style={{ resize: 'none', minHeight: '200px' }}
              placeholder="여기에 기사 내용을 입력하거나 붙여넣으세요..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            ></textarea>
            <button 
              className="btn btn-primary w-100 py-3 fw-bold fs-5 blue-glow"
              onClick={handleConvert}
              disabled={isLoading}
            >
              {isLoading ? (
                <span><span className="spinner-border spinner-border-sm me-2"></span>변환 중...</span>
              ) : (
                <span><i className="bi bi-music-note-beamed me-2"></i>트로트로 변환 및 재생</span>
              )}
            </button>
          </div>
        </div>

        {/* 결과 카드 */}
        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column align-items-center justify-content-center text-center">

            {!lyrics ? (
              // 결과가 없을 때 (대기 화면)
              <div className="text-secondary opacity-50">
                <i className="bi bi-music-player display-1 mb-3 d-block"></i>
                <p>기사를 입력하고 트로트 뉴스를 들어보세요!</p>
              </div>
            ) : (
              // 결과가 있을 때 (가사 및 재생 화면)
              <div className="w-100 animate-fade-in">
                <div className="mb-4">
                    {/* 재생 중일 때 돌아가는 LP판 애니메이션 효과 */}
                    <div 
                        className={`rounded-circle bg-gradient-to-br from-gray-800 to-black border border-secondary mx-auto d-flex align-items-center justify-content-center ${isPlaying ? 'spin-slow' : ''}`}
                        style={{ width: '120px', height: '120px', transition: 'all 0.5s' }}
                    >
                        <i className={`bi ${isPlaying ? 'bi-pause-fill' : 'bi-play-fill'} fs-1 text-white`}></i>
                    </div>
                </div>

                {/* 가사 출력 영역 */}
