import React, { useState, useRef } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Zap, Music } from 'lucide-react';

interface Props {
  isMockMode?: boolean;
}

const AudioNews: React.FC<Props> = ({ isMockMode = false }) => {
  const [inputText, setInputText] = useState('');
  const [lyrics, setLyrics] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setLyrics(null);
    setIsPlaying(false);

    // Stop current audio if any
    if (sourceNodeRef.current) {
      sourceNodeRef.current.stop();
      sourceNodeRef.current = null;
    }

    try {
      // 1. Generate Lyrics
      const generatedLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(generatedLyrics);

      // 2. Generate Audio via TTS
      const audioData = await speakTrot(generatedLyrics);
      if (audioData) {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        }
        const buffer = await decodeAudio(audioData, audioContextRef.current);
        playBuffer(buffer);
      }
    } catch (error) {
      console.error(error);
      alert('오디오 생성 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  };

  const playBuffer = (buffer: AudioBuffer) => {
    if (!audioContextRef.current) return;

    if (sourceNodeRef.current) {
      sourceNodeRef.current.stop();
    }

    const source = audioContextRef.current.createBufferSource();
    source.buffer = buffer;
    source.connect(audioContextRef.current.destination);
    source.onended = () => setIsPlaying(false);

    source.start(0);
    sourceNodeRef.current = source;
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (isPlaying) {
      sourceNodeRef.current?.stop();
      sourceNodeRef.current = null;
      setIsPlaying(false);
    } else {
      if (lyrics) {
        // Simple re-triggering of the process to simplify state management
        handleConvert();
      }
    }
  };

  return (
    <div className="container py-4 space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <div className="flex justify-between items-start">
        <div className="text-start">
