        </div>
        {isMockMode && (
          <div className="flex items-center gap-1.5 px-3 py-1 bg-amber-500/10 text-amber-400 border border-amber-500/20 rounded-lg text-xs font-bold uppercase tracking-wider mt-2">
            <Zap size={12} />
            Mock Mode Active
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* 입력 카드 */}
        <div className="h-full">
          <div className="glass-card p-8 rounded-3xl h-full flex flex-col space-y-6">
            <label className="text-lg font-bold text-white flex items-center gap-2">
              <i className="bi bi-pencil-square text-blue-400"></i>
