            <button 
              className={`w-full py-4 rounded-2xl font-black text-xl flex items-center justify-center gap-3 transition-all ${isMockMode ? 'bg-amber-600 hover:bg-amber-500' : 'blue-gradient hover:blue-glow'} text-white shadow-xl shadow-blue-500/10 disabled:opacity-50`}
