import React, { useState, useRef, useEffect } from 'react';

interface AudioNewsProps {
  isMockMode?: boolean;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode = false }) => {
  const [inputText, setInputText] = useState('');
  const [lyrics, setLyrics] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const audioRef = useRef<HTMLAudioElement>(null);

  // ✅ [수정 1] 끊기지 않는 확실한 BGM 주소 (무료 음원)
  // 만약 이 주소도 안 되면 'https://www.soundhelix.com/examples/mp3/SoundHelix-Song-1.mp3' 로 바꿔보세요.
  const TROT_BGM_URL = "https://cdn.pixabay.com/audio/2024/01/15/audio_2760822688.mp3"; 

  const handleConvert = () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setLyrics(null);
    setIsPlaying(false);

    // ✅ [수정 2] 버튼 누르자마자 오디오 로딩 시작 (브라우저에게 '사용자가 시켰다'고 알림)
    if (audioRef.current) {
        audioRef.current.src = TROT_BGM_URL;
        audioRef.current.load();
    }

    // 0.8초 딜레이 (연출용)
    setTimeout(() => {
      const mockLyrics = `
**(전주: 쿵짝 쿵짝 쿵짜라 쿵짝~)**

**[1절]**
"${inputText.slice(0, 10)}..." 소식 들었소 (어이!)
세상 돌아가는 꼴이 요지경일세
팩트 체크 해봤나 기자가 뛴다 (지화자!)

**[후렴]**
특종이다 특종이야~ 동아일보 특종이야~
오늘도 우리는 진실을 향해 달린다~
(얼쑤! 좋다!)
      `;

      setLyrics(mockLyrics);
      setIsLoading(false);
      setIsPlaying(true);

      // ✅ [수정 3] 재생 강제 실행 및 에러 확인
      if (audioRef.current) {
        audioRef.current.volume = 0.5;
        const playPromise = audioRef.current.play();

        if (playPromise !== undefined) {
            playPromise.catch(error => {
                console.error("재생 실패:", error);
                alert("브라우저 정책으로 소리가 차단되었습니다. 화면 중앙의 재생 버튼을 한 번 더 눌러주세요!");
                setIsPlaying(false); // 재생 실패 시 멈춤 상태로 표시
            });
        }
      }
    }, 800);
  };

  const togglePlay = () => {
    if (!audioRef.current) return;

    if (isPlaying) {
        audioRef.current.pause();
    } else {
        audioRef.current.play().catch(e => console.error("재생 에러:", e));
    }
    setIsPlaying(!isPlaying);
  };

  return (
    <div className="container py-4">
      {/* 오디오 태그 (숨김) */}
      <audio ref={audioRef} loop />

      <div className="text-center mb-5">
        <h2 className="display-6 fw-bold text-white mb-2">
          <span className="text-gradient-primary">오디오 뉴스 (Trot TTS)</span>
        </h2>
        <p className="text-secondary">딱딱한 뉴스를 신나는 트로트로! {isMockMode && <span className="badge bg-warning text-dark ms-2">Mock Mode</span>}</p>
      </div>

      <div className="row g-4">
        {/* 입력 부분 */}
        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column">
            <label className="form-label text-white fw-bold mb-3">트로트로 변환할 기사</label>
            <textarea
              className="form-control bg-dark text-white border-secondary mb-3 flex-grow-1"
              style={{ resize: 'none', minHeight: '200px' }}
              placeholder="기사 내용을 입력하세요..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            ></textarea>
            <button 
              className="btn btn-primary w-100 py-3 fw-bold fs-5 blue-glow"
              onClick={handleConvert}
              disabled={isLoading}
            >
              {isLoading ? (
                <span><span className="spinner-border spinner-border-sm me-2"></span>변환 중...</span>
              ) : (
                <span><i className="bi bi-music-note-beamed me-2"></i>트로트로 변환 및 재생</span>
              )}
            </button>
          </div>
        </div>

        {/* 결과 부분 */}
        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column align-items-center justify-content-center text-center">
            {!lyrics ? (
              <div className="text-secondary opacity-50">
                <i className="bi bi-music-player display-1 mb-3 d-block"></i>
                <p>기사를 입력하고 트로트 뉴스를 들어보세요!</p>
              </div>
            ) : (
              <div className="w-100 animate-fade-in">
                {/* LP판 */}
                <div className="mb-4 position-relative">
                    <div 
                        className={`rounded-circle bg-dark border border-secondary mx-auto d-flex align-items-center justify-content-center shadow-lg ${isPlaying ? 'spin-slow' : ''}`}
                        style={{ width: '150px', height: '150px', background: 'radial-gradient(circle, #333 30%, #000 70%)' }}
                    >
                        <div className="rounded-circle bg-danger" style={{ width: '50px', height: '50px' }}></div>
                    </div>
                    {/* 재생 버튼 오버레이 */}
                    <div 
                        className="position-absolute top-50 start-50 translate-middle"
                        style={{ cursor: 'pointer', zIndex: 10 }}
                        onClick={togglePlay}
                    >
                       <i className={`bi ${isPlaying ? 'bi-pause-circle-fill' : 'bi-play-circle-fill'} display-1 text-white drop-shadow`} style={{ filter: 'drop-shadow(0 0 10px rgba(0,0,0,0.8))' }}></i>
                    </div>
                </div>

                {/* 가사 */}
                <div className="bg-black bg-opacity-50 rounded p-3 mb-3 text-start border border-secondary custom-scrollbar" style={{ maxHeight: '200px', overflowY: 'auto' }}>
                  <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '1.6' }}>
                    {lyrics}
                  </pre>
                </div>

                <button className={`btn w-100 py-2 fw-bold ${isPlaying ? 'btn-outline-danger' : 'btn-outline-light'}`} onClick={togglePlay}>
                    <i className={`bi ${isPlaying ? 'bi-stop-fill' : 'bi-play-circle'} me-2`}></i>
                    {isPlaying ? '재생 중지' : '다시 듣기'}
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

      <style>{`
        .spin-slow { animation: spin 3s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .text-gradient-primary {
            background: linear-gradient(to right, #4facfe, #00f2fe);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
        .custom-scrollbar::-webkit-scrollbar { width: 6px; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #4facfe; border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default AudioNews;

