  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentArticle, setCurrentArticle] = useState<NewsArticle | null>(null);
  const [savedArticles, setSavedArticles] = useState<NewsArticle[]>([]);

  const handleGenerate = async () => {
    if (!topic.trim()) {
      alert("취재할 주제를 입력해주세요!");
      return;
    }

    setIsGenerating(true);
    try {
      // 1. Generate article text via Gemini service
      const aiData = await generateArticle(topic, isMockMode);

      // 2. Generate relevant news image
      const imageUrl = await generateNewsImage(aiData.imageKeyword || "news") || `https://source.unsplash.com/1600x900/?${encodeURIComponent(aiData.imageKeyword || "news")}`;

      const newArticle: NewsArticle = {
        id: Date.now(),
        title: aiData.title,
        category: aiData.category,
        content: aiData.content,
        imageUrl: imageUrl,
        date: new Date().toLocaleDateString(),
        sources: aiData.sources || [],
