import React, { useState, useRef } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';

interface AudioNewsProps {
  isMockMode?: boolean;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode = false }) => {
  const [inputText, setInputText] = useState('');
  const [lyrics, setLyrics] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const bgmRef = useRef<HTMLAudioElement | null>(null);

  // Background Trot Rhythm
  const BGM_URL = "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3";

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setLyrics(null);
    setIsPlaying(false);

    // Stop previous audio
    if (sourceNodeRef.current) sourceNodeRef.current.stop();
    if (bgmRef.current) bgmRef.current.pause();

    try {
      // 1. Generate Trot Lyrics
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // 2. Generate Audio via Gemini TTS
      const audioData = await speakTrot(trotLyrics);

      if (!audioData) throw new Error("Audio generation failed");

      // 3. Setup Audio Context and Nodes
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      const buffer = await decodeAudio(audioData, audioContextRef.current);
      const source = audioContextRef.current.createBufferSource();
      source.buffer = buffer;
      source.connect(audioContextRef.current.destination);
      source.onended = () => setIsPlaying(false);

      sourceNodeRef.current = source;

      // 4. Play BGM and TTS
      if (bgmRef.current) {
        bgmRef.current.volume = 0.2;
        bgmRef.current.play();
      }

      source.start();
      setIsPlaying(true);

    } catch (error) {
      console.error("Audio generation failed:", error);
      alert("오디오 생성 중 오류가 발생했습니다.");
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = () => {
    if (isPlaying) {
      if (sourceNodeRef.current) sourceNodeRef.current.stop();
      if (bgmRef.current) bgmRef.current.pause();
      setIsPlaying(false);
    } else {
      if (lyrics) handleConvert();
    }
  };

  return (
    <div className="container py-4">
      <audio ref={bgmRef} src={BGM_URL} loop hidden />

      <div className="text-center mb-5">
        <h2 className="display-6 fw-bold text-white mb-2">
          <span className="text-gradient-trot">오디오 뉴스 (Trot TTS)</span>
        </h2>
        <p className="text-secondary">딱딱한 뉴스를 신나는 트로트로! (Gemini AI Voice)</p>
      </div>

      <div className="row g-4">
        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column">
            <label className="form-label text-white fw-bold mb-3">변환할 기사</label>
            <textarea
              className="form-control bg-dark text-white border-secondary mb-3 flex-grow-1"
              style={{ resize: 'none', minHeight: '280px' }}
              placeholder="여기에 기사를 입력하세요..."
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            ></textarea>
            <button 
              className="btn btn-warning w-100 py-3 fw-bold fs-5 shadow-lg border-0"
              style={{ background: 'linear-gradient(135deg, #F09819 0%, #EDDE5D 100%)', color: '#000' }}
              onClick={handleConvert}
              disabled={isLoading}
            >
              {isLoading ? (
                <span><span className="spinner-border spinner-border-sm me-2"></span>제작 중...</span>
              ) : (
                <span>🎤 뽕짝 뉴스 시작!</span>
              )}
            </button>
          </div>
        </div>

        <div className="col-lg-6">
          <div className="glass-card p-4 h-100 d-flex flex-column align-items-center justify-content-center text-center">
            {!lyrics ? (
              <div className="text-secondary opacity-50 py-5">
                <i className="bi bi-music-player display-1 mb-3 d-block"></i>
                <p>AI가 당신의 뉴스를 노래할 준비를 하고 있습니다.</p>
              </div>
            ) : (
              <div className="w-100 animate-fade-in">
                <div className="mb-5 position-relative">
                    <div 
                        className={`rounded-circle border-8 border-slate-800 mx-auto d-flex align-items-center justify-content-center shadow-2xl ${isPlaying ? 'spin-slow' : ''}`}
                        style={{ width: '180px', height: '180px', background: 'radial-gradient(circle, #333 30%, #000 70%)' }}
                    >
                      <div className="rounded-circle bg-warning" style={{ width: '50px', height: '50px', border: '3px solid #000' }}></div>
                    </div>
                    <div 
                        className="position-absolute top-50 start-50 translate-middle"
                        style={{ cursor: 'pointer', zIndex: 10 }}
                        onClick={togglePlay}
                    >
                       <i className={`bi ${isPlaying ? 'bi-pause-circle-fill' : 'bi-play-circle-fill'} display-1 text-white opacity-90`}></i>
                    </div>
                </div>

                <div className="bg-black bg-opacity-40 rounded-3xl p-4 mb-4 text-start border border-slate-800 custom-scrollbar" style={{ maxHeight: '200px', overflowY: 'auto' }}>
                  <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '1.8', fontSize: '1.1rem' }}>
                    {lyrics}
                  </pre>
                </div>

                <button className={`btn w-100 py-2 fw-bold ${isPlaying ? 'btn-outline-danger' : 'btn-outline-light'}`} onClick={togglePlay}>
                    {isPlaying ? '재생 중지' : '다시 듣기'}
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

      <style>{`
        .spin-slow { animation: spin 5s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .text-gradient-trot {
            background: linear-gradient(to right, #F09819, #EDDE5D);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
      `}</style>
    </div>
  );
};

