import React, { useState } from 'react';
import { generateArticle, generateNewsImage } from '../services/gemini';

interface NewsArticle {
  id: number;
  title: string;
  category: string;
  content: string;
  imageUrl: string; 
  date: string;
  sources: string[];
  factCheck: string;
}

interface AIWriterProps {
  isMockMode?: boolean;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode = false }) => {
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentArticle, setCurrentArticle] = useState<NewsArticle | null>(null);
  const [savedArticles, setSavedArticles] = useState<NewsArticle[]>([]);

  const handleGenerate = async () => {
    if (!topic.trim()) {
      alert("취재할 주제를 입력해주세요!");
      return;
    }

    setIsGenerating(true);
    try {
      const aiData = await generateArticle(topic, isMockMode);
      const imageUrl = await generateNewsImage(aiData.imageKeyword || "news") || `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;

      const newArticle: NewsArticle = {
        id: Date.now(),
        title: aiData.title,
        category: aiData.category,
        content: aiData.content,
        imageUrl: imageUrl,
        date: new Date().toLocaleDateString(),
        sources: aiData.sources || [],
        factCheck: aiData.factCheck || "동아 데이터 검증 완료",
      };

      setCurrentArticle(newArticle);
      setSavedArticles(prev => [newArticle, ...prev]);
