interface AIWriterProps {
  isMockMode?: boolean;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode = false }) => {
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentArticle, setCurrentArticle] = useState<NewsArticle | null>(null);
  const [savedArticles, setSavedArticles] = useState<NewsArticle[]>([]);

  const handleGenerate = async () => {
    if (!topic.trim()) {
      alert("취재할 주제를 입력해주세요!");
      return;
    }

    setIsGenerating(true);
    try {
      const aiData = await generateArticle(topic, isMockMode);
      const imageUrl = await generateNewsImage(aiData.imageKeyword || "news", isMockMode) || `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;

      const newArticle: NewsArticle = {
        id: Date.now(),
        title: aiData.title,
        category: aiData.category,
        content: aiData.content,
        imageUrl: imageUrl,
        date: new Date().toLocaleDateString(),
        sources: aiData.sources || [],
        factCheck: aiData.factCheck || "동아 데이터 검증 완료",
      };

      setCurrentArticle(newArticle);
      setSavedArticles(prev => [newArticle, ...prev]);
      setTopic('');
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        alert("API 사용량이 초과되었습니다. 상단 바의 'Mock Mode'를 켜시면 데모 데이터를 통해 기능을 계속 확인하실 수 있습니다.");
      } else {
        console.error("Failed to generate article:", error);
        alert("기사 생성 중 오류가 발생했습니다. 나중에 다시 시도해주세요.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="container-fluid py-4">
      <div className="row g-4 h-100">
        <div className="col-lg-3">
          <div className="glass-card h-100 p-3 d-flex flex-column" style={{ minHeight: '80vh' }}>
            <h5 className="text-white fw-bold mb-4 pb-2 border-bottom border-secondary">
              <i className="bi bi-archive-fill me-2"></i>기사 보관함
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1">
              {savedArticles.length === 0 ? (
                <div className="text-secondary text-center py-5 opacity-50">
                    <p>작성된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="d-grid gap-2">
                  {savedArticles.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setCurrentArticle(item)}
                      className={`p-3 rounded transition-all ${currentArticle?.id === item.id ? 'bg-primary border-primary text-white shadow-lg' : 'bg-dark bg-opacity-50 border-secondary text-secondary'}`}
                      style={{ cursor: 'pointer', border: '1px solid' }}
                    >
                      <h6 className="m-0 text-truncate fw-bold">{item.title}</h6>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-9">
          <div className="glass-card p-4 mb-4">
            <div className="input-group input-group-lg">
              <input 
                type="text" 
                className="form-control bg-dark text-white border-secondary"
                placeholder="취재 주제를 입력하세요 (예: 2025년 IT 트렌드)" 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
              />
              <button 
                className="btn btn-primary fw-bold blue-glow px-5 border-0"
                style={{ background: 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
                onClick={handleGenerate}
                disabled={isGenerating}
              >
                {isGenerating ? (
                    <span><span className="spinner-border spinner-border-sm me-2"></span>AI 작성 중...</span>
                ) : (
                    '기사 생성'
                )}
              </button>
            </div>
            {isMockMode && <div className="mt-2 text-amber-400 text-xs font-bold"><i className="bi bi-zap-fill me-1"></i>Mock Mode 활성화 중 (샘플 데이터 사용)</div>}
          </div>

          {currentArticle ? (
            <div className="glass-card p-0 overflow-hidden animate-fade-in border-0">
              <div className="position-relative" style={{ height: '400px', backgroundColor: '#000' }}>
                <img src={currentArticle.imageUrl} alt="News" className="w-100 h-100 object-fit-cover" />
                <div className="position-absolute bottom-0 start-0 w-100 p-5" style={{ background: 'linear-gradient(to top, rgba(0,0,0,0.9) 0%, transparent 100%)' }}>
                    <span className="badge bg-success mb-2 p-2">{currentArticle.factCheck}</span>
                    <h1 className="text-white fw-bold display-5 drop-shadow m-0">{currentArticle.title}</h1>
                </div>
              </div>

              <div className="p-5 bg-dark bg-opacity-40">
                <div className="d-flex justify-content-between text-secondary mb-4 pb-3 border-bottom border-secondary border-opacity-25">
                    <span className="fw-bold text-white"><i className="bi bi-robot me-2"></i>동아 AI 기자</span>
                    <span>{currentArticle.date}</span>
                </div>

                <div 
                  className="text-white text-opacity-90 mb-5 article-content" 
                  style={{ lineHeight: '1.9', fontSize: '1.15rem' }}
                  dangerouslySetInnerHTML={{ __html: currentArticle.content }}
                />
              </div>
            </div>
          ) : (
            <div className="glass-card p-5 text-center text-secondary d-flex flex-column align-items-center justify-content-center" style={{ minHeight: '550px' }}>
                <i className="bi bi-stars display-2 text-blue-400 mb-3"></i>
                <h3 className="fw-bold text-white">동아 AI 뉴스룸</h3>
                <p>기사 주제를 입력하여 AI 취재를 시작하세요.</p>
            </div>
          )}
        </div>
      </div>
      <style>{`
        .article-content p { margin-bottom: 1.5rem; }
        .article-content b { color: #fff; font-weight: 800; }
        .object-fit-cover { object-fit: cover; }
      `}</style>
    </div>
  );
};

export default AIWriter;

