import React, { useState } from 'react';
import { ViewType } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AIWriter from './components/AIWriter';
import AIIllustrator from './components/AIIllustrator';
import HeadlineAI from './components/HeadlineAI';
import NetizenSimulator from './components/NetizenSimulator';
import AudioNews from './components/AudioNews';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isMockMode, setIsMockMode] = useState(false);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard': return <Dashboard />;
      case 'writer': return <AIWriter isMockMode={isMockMode} />;
      case 'illustrator': return <AIIllustrator isMockMode={isMockMode} />;
      case 'headline': return <HeadlineAI isMockMode={isMockMode} />;
      case 'comments': return <NetizenSimulator isMockMode={isMockMode} />;
      case 'audio': return <AudioNews isMockMode={isMockMode} />;
      default: return <Dashboard />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView}
      isMockMode={isMockMode}
      setIsMockMode={setIsMockMode}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

