// Helper to handle 429 error and other API failures
const handleAIError = (error: any) => {
  console.error("Gemini API Error Detail:", error);
  const errorStr = JSON.stringify(error).toLowerCase();
  const errorMessage = error?.message?.toLowerCase() || "";

  if (
    errorStr.includes('429') || 
    errorStr.includes('resource_exhausted') || 
    errorStr.includes('quota') ||
    errorMessage.includes('quota') ||
    errorMessage.includes('exhausted')
  ) {
    throw new Error("QUOTA_EXCEEDED");
  }
  throw error;
};

export const generateArticle = async (prompt: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return MOCK_ARTICLE;
  }
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a professional journalist for 'Dong-A AI News'. Write a detailed news article about "${prompt}" in KOREAN. Use HTML tags for formatting (<b>, <p>).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            category: { type: Type.STRING, description: "One of: Politics, Economy, Sports, Tech, Society" },
            content: { type: Type.STRING, description: "Full article in HTML format" },
            factCheck: { type: Type.STRING },
            sources: { type: Type.ARRAY, items: { type: Type.STRING } },
            imageKeyword: { type: Type.STRING, description: "A single English keyword for image search" }
          },
          required: ["title", "category", "content", "factCheck", "sources", "imageKeyword"],
        },
      },
    });
    return JSON.parse(response.text);
  } catch (error) {
    return handleAIError(error);
  }
};

