export const generateNewsImage = async (prompt: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 600));
    return `https://images.unsplash.com/photo-1585829365234-78d2b502931d?auto=format&fit=crop&w=1600&q=80`;
  }
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [{ text: `Professional journalistic news photo: ${prompt}. Cinematic lighting, 8k.` }]
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  } catch (error: any) {
    const errorStr = JSON.stringify(error);
    if (errorStr.includes('429')) {
      throw new Error("QUOTA_EXCEEDED");
    }
    console.warn("Image generation failed, using fallback:", error);
    return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  }
};

