export const speakTrot = async (lyrics: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 500));
    return null; 
  }
  try {
    // TTS를 위한 텍스트 정제 (토큰 절약 및 가독성)
    const cleanLyrics = lyrics.replace(/[*#\[\]]/g, '').replace(/\(.*\)/g, '').trim();
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say this cheerful trot singer style: ${cleanLyrics}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Puck' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return handleAIError(error);
  }
};

export const decodeAudio = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const numChannels = 1;
  const sampleRate = 24000;
  const dataInt16 = new Int16Array(bytes.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

import React, { useState, useRef, useEffect } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode?: boolean;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode = false }) => {
  // 상태: localStorage에서 초기값을 불러와 메뉴 이동 후에도 데이터 유지
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);
  const [errorStatus, setErrorStatus] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null); 
  const bgmRef = useRef<HTMLAudioElement | null>(null);

  const stopPlayback = () => {
    if (sourceNodeRef.current) {
      try { sourceNodeRef.current.stop(); } catch(e) {}
      sourceNodeRef.current = null;
    }
    if (bgmRef.current) {
      bgmRef.current.pause();
    }
    setIsPlaying(false);
  };

  useEffect(() => {
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    return () => {
      stopPlayback();
    };
  }, []);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const BGM_URL = "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3";

  const startPlayback = async () => {
    if (!audioBufferRef.current || !audioContextRef.current) return;

    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    if (sourceNodeRef.current) {
      try { sourceNodeRef.current.stop(); } catch(e) {}
    }

    const source = audioContextRef.current.createBufferSource();
    source.buffer = audioBufferRef.current;
    source.connect(audioContextRef.current.destination);
    source.onended = () => setIsPlaying(false);

    sourceNodeRef.current = source;

    if (bgmRef.current) {
      bgmRef.current.volume = 0.15;
      bgmRef.current.play();
    }

    source.start();
    setIsPlaying(true);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setErrorStatus(null);
    stopPlayback();
    audioBufferRef.current = null;

    try {
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      const audioData = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      const buffer = await decodeAudio(audioData, audioContextRef.current);
      audioBufferRef.current = buffer; 

      startPlayback();
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        setErrorStatus("API 할당량이 초과되었습니다. 상단 바에서 'Mock Mode'를 켜시면 데모 데이터로 기능을 계속 체험해 보실 수 있습니다.");
      } else {
        setErrorStatus("오디오 생성 중 알 수 없는 오류가 발생했습니다. 잠시 후 다시 시도해 주세요.");
      }
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = () => {
    if (!lyrics) return;
    const newItem: SavedAudioNews = {
      id: Date.now(),
      title: inputText.split('\n')[0].slice(0, 20) || "제목 없음",
      lyrics: lyrics,
      timestamp: new Date().toLocaleString('ko-KR', { hour12: false }).slice(0, -3)
    };
    const updated = [newItem, ...savedItems];
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
    alert("보관함에 저장되었습니다.");
  };

  const loadSavedItem = async (item: SavedAudioNews) => {
    if (lyrics === item.lyrics && audioBufferRef.current) {
      startPlayback();
      return;
    }

    if (isMockMode) {
        setLyrics(item.lyrics);
        return;
    }

    setIsLoading(true);
    setErrorStatus(null);
    setLyrics(item.lyrics);
    stopPlayback();
    audioBufferRef.current = null;
    try {
      const audioData = await speakTrot(item.lyrics, isMockMode);
      if (!audioData) throw new Error("Audio generation failed");
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const buffer = await decodeAudio(audioData, audioContextRef.current);
      audioBufferRef.current = buffer;
      startPlayback();
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        setErrorStatus("API 할당량이 초과되었습니다. 'Mock Mode'를 활용해 보세요.");
      } else {
        setErrorStatus("오디오를 불러오는 중 오류가 발생했습니다.");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const deleteItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = savedItems.filter(item => item.id !== id);
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      if (audioBufferRef.current) {
        await startPlayback();
      } else if (lyrics) {
        if (isMockMode) {
            alert("Mock Mode에서는 가사만 생성됩니다.");
        } else {
            loadSavedItem({ id: 0, title: '', lyrics: lyrics, timestamp: '' });
        }
      }
    }
  };

  return (
    <div className="container-fluid py-4">
      <audio ref={bgmRef} src={BGM_URL} loop hidden />

      <div className="row g-4">
        <div className="col-lg-3">
          <div className="glass-card h-100 p-3 d-flex flex-column" style={{ minHeight: '75vh' }}>
            <h5 className="text-white fw-bold mb-4 pb-2 border-bottom border-secondary d-flex justify-content-between align-items-center">
              <span><i className="bi bi-collection-play-fill me-2 text-warning"></i>보관함</span>
              <span className="badge bg-dark text-secondary">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1">
              {savedItems.length === 0 ? (
                <div className="text-center py-5 text-secondary opacity-50">
                  <i className="bi bi-inbox display-4 mb-2 d-block"></i>
                  <p className="small">저장된 뉴스가 없습니다.</p>
                </div>
              ) : (
                <div className="d-grid gap-2">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => loadSavedItem(item)}
                      className={`p-3 rounded bg-dark transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning shadow-lg shadow-warning/10' : 'border-secondary border-opacity-20 bg-opacity-40'}`}
                    >
                      <h6 className="text-white text-truncate mb-1 fw-bold" style={{ fontSize: '0.9rem' }}>{item.title}</h6>
                      <p className="text-secondary m-0" style={{ fontSize: '0.7rem' }}>{item.timestamp}</p>
                      <button 
                        onClick={(e) => deleteItem(e, item.id)}
                        className="btn btn-link text-danger p-0 position-absolute top-0 end-0 mt-2 me-2 opacity-0 group-hover:opacity-100 transition-all"
                      >
                        <i className="bi bi-trash"></i>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-9">
          <div className="text-center mb-4">
            <h2 className="display-6 fw-bold text-white mb-2">
              <span className="text-gradient-trot">오디오 뉴스룸</span>
            </h2>
            <p className="text-secondary">기사를 입력하면 신나는 트로트 가사와 AI 음성이 자동 생성됩니다.</p>
            {isMockMode && <span className="badge bg-amber-500 text-black px-3 py-2 rounded-pill fw-bold animate-pulse">Mock Mode 활성화 중</span>}
          </div>

          {errorStatus && (
            <div className="alert alert-danger border-0 bg-red-950 text-red-200 mb-4 animate-in fade-in slide-in-from-top-2">
                <i className="bi bi-exclamation-triangle-fill me-2"></i>
                {errorStatus}
            </div>
          )}

          <div className="row g-4">
            <div className="col-xl-6">
              <div className="glass-card p-4 h-100 d-flex flex-column">
                <label className="form-label text-white fw-bold mb-3">기사 원문</label>
                <textarea
                  className="form-control bg-dark text-white border-secondary mb-3 flex-grow-1"
                  style={{ resize: 'none', minHeight: '300px', fontSize: '1rem' }}
                  placeholder="기사 내용을 입력하세요..."
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                ></textarea>
                <div className="d-flex gap-2">
                  <button 
                    className="btn btn-warning flex-grow-1 py-3 fw-bold fs-5 shadow-lg border-0 transition-transform active:scale-95"
                    style={{ background: 'linear-gradient(135deg, #F09819 0%, #EDDE5D 100%)', color: '#000' }}
                    onClick={handleConvert}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <span><span className="spinner-border spinner-border-sm me-2"></span>AI 처리 중...</span>
                    ) : (
                      <span>🎤 트로트 뉴스 생성</span>
                    )}
                  </button>
                  {lyrics && (
                    <button className="btn btn-outline-light px-4 border-secondary" onClick={handleSave} title="보관함에 저장">
                      <i className="bi bi-save"></i>
                    </button>
                  )}
                </div>
              </div>
            </div>

            <div className="col-xl-6">
              <div className="glass-card p-4 h-100 d-flex flex-column align-items-center justify-content-center text-center">
                {!lyrics ? (
                  <div className="text-secondary opacity-50 py-5">
                    <i className="bi bi-music-player display-1 d-block mb-3"></i>
                    <p className="fs-5">기사를 입력하고 생성 버튼을 누르세요.</p>
                  </div>
                ) : (
                  <div className="w-100 animate-fade-in">
                    <div className="mb-5 position-relative d-inline-block">
                        <div 
                            className={`rounded-circle border-8 border-slate-800 mx-auto d-flex align-items-center justify-content-center shadow-2xl ${isPlaying ? 'spin-slow' : ''}`}
                            style={{ width: '220px', height: '220px', background: 'radial-gradient(circle, #333 30%, #000 70%)', transition: 'transform 0.3s ease' }}
                        >
                          <div className="rounded-circle bg-warning" style={{ width: '70px', height: '70px', border: '3px solid #000', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <i className={`bi bi-vinyl-fill text-dark fs-2 ${isPlaying ? 'animate-pulse' : ''}`}></i>
                          </div>
                        </div>
                        <div 
                            className="position-absolute top-50 start-50 translate-middle cursor-pointer"
                            onClick={togglePlay}
                            style={{ zIndex: 10 }}
                        >
                           <i className={`bi ${isPlaying ? 'bi-pause-circle-fill' : 'bi-play-circle-fill'} display-1 text-white opacity-90 hover-scale drop-shadow`}></i>
                        </div>
                    </div>

                    <div className="bg-black bg-opacity-40 rounded-3xl p-4 mb-4 text-start border border-slate-800 custom-scrollbar" style={{ maxHeight: '200px', overflowY: 'auto' }}>
                      <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '1.7', fontSize: '1.05rem' }}>
                        {lyrics}
                      </pre>
                    </div>

                    <button 
                      className={`btn w-100 py-3 fw-bold transition-all ${isPlaying ? 'btn-outline-danger' : 'btn-primary'}`} 
                      onClick={togglePlay}
                      disabled={isLoading}
                    >
                        {isLoading ? (
                          <span><span className="spinner-border spinner-border-sm me-2"></span>음성 생성 중...</span>
                        ) : (
                          isPlaying ? '재생 중지' : '오디오 재생'
                        )}
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        .spin-slow { animation: spin 4s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .text-gradient-trot {
            background: linear-gradient(to right, #F09819, #EDDE5D);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
        .hover-scale:hover { transform: translate(-50%, -50%) scale(1.1) !important; }
        .hover-scale { transition: transform 0.2s; }
        .group:hover .opacity-100 { opacity: 1 !important; }
        .drop-shadow { filter: drop-shadow(0 0 10px rgba(0,0,0,0.5)); }
        .animate-pulse { animation: pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite; }
        @keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: .5; } }
      `}</style>
    </div>
  );
};

export default AudioNews;

import React, { useState } from 'react';
import { ViewType } from './types';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AIWriter from './components/AIWriter';
import AIIllustrator from './components/AIIllustrator';
import HeadlineAI from './components/HeadlineAI';
import NetizenSimulator from './components/NetizenSimulator';
import AudioNews from './components/AudioNews';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('dashboard');
  const [isMockMode, setIsMockMode] = useState(false);

  const renderView = () => {
    switch (activeView) {
      case 'dashboard': return <Dashboard />;
      case 'writer': return <AIWriter isMockMode={isMockMode} setIsMockMode={setIsMockMode} />;
      case 'illustrator': return <AIIllustrator isMockMode={isMockMode} setIsMockMode={setIsMockMode} />;
      case 'headline': return <HeadlineAI isMockMode={isMockMode} setIsMockMode={setIsMockMode} />;
      case 'comments': return <NetizenSimulator isMockMode={isMockMode} setIsMockMode={setIsMockMode} />;
      case 'audio': return <AudioNews isMockMode={isMockMode} setIsMockMode={setIsMockMode} />;
      default: return <Dashboard />;
    }
  };

  return (
    <Layout 
      activeView={activeView} 
      setActiveView={setActiveView}
      isMockMode={isMockMode}
      setIsMockMode={setIsMockMode}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState } from 'react';
import { generateArticle, generateNewsImage } from '../services/gemini';
import { Zap } from 'lucide-react';

interface NewsArticle {
  id: number;
  title: string;
  category: string;
  content: string;
  imageUrl: string; 
  date: string;
  sources: string[];
  factCheck: string;
}

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentArticle, setCurrentArticle] = useState<NewsArticle | null>(null);
  const [savedArticles, setSavedArticles] = useState<NewsArticle[]>([]);
  const [errorType, setErrorType] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!topic.trim()) {
      alert("취재할 주제를 입력해주세요!");
      return;
    }

    setIsGenerating(true);
    setErrorType(null);
    try {
      const aiData = await generateArticle(topic, isMockMode);
      const imageUrl = await generateNewsImage(aiData.imageKeyword || "news", isMockMode) || `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;

      const newArticle: NewsArticle = {
        id: Date.now(),
        title: aiData.title,
        category: aiData.category,
        content: aiData.content,
        imageUrl: imageUrl,
        date: new Date().toLocaleDateString(),
        sources: aiData.sources || [],
        factCheck: aiData.factCheck || "동아 데이터 검증 완료",
      };

      setCurrentArticle(newArticle);
      setSavedArticles(prev => [newArticle, ...prev]);
      setTopic('');
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        setErrorType("QUOTA_EXCEEDED");
      } else {
        console.error("Failed to generate article:", error);
        setErrorType("UNKNOWN");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="container-fluid py-4">
      {errorType === "QUOTA_EXCEEDED" && (
        <div className="glass-card border-amber-500/50 p-4 rounded-2xl mb-4 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
          <div className="flex items-center gap-3 text-amber-200">
            <Zap size={24} className="text-amber-400" />
            <div>
              <p className="font-bold m-0">API 할당량 초과 (429 Error)</p>
              <p className="text-sm m-0 opacity-80">현재 API 키의 호출 한도가 소진되었습니다. Mock 모드에서 기능을 계속 확인하시겠습니까?</p>
            </div>
          </div>
          <button 
            onClick={() => { setIsMockMode(true); setErrorType(null); }}
            className="bg-amber-500 text-black px-4 py-2 rounded-xl font-bold hover:bg-amber-400 transition-colors"
          >
            Mock 모드 전환
          </button>
        </div>
      )}

      <div className="row g-4 h-100">
        <div className="col-lg-3">
          <div className="glass-card h-100 p-3 d-flex flex-column" style={{ minHeight: '80vh' }}>
            <h5 className="text-white fw-bold mb-4 pb-2 border-bottom border-secondary">
              <i className="bi bi-archive-fill me-2"></i>기사 보관함
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1">
              {savedArticles.length === 0 ? (
                <div className="text-secondary text-center py-5 opacity-50">
                    <p>작성된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="d-grid gap-2">
                  {savedArticles.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setCurrentArticle(item)}
                      className={`p-3 rounded transition-all ${currentArticle?.id === item.id ? 'bg-primary border-primary text-white shadow-lg' : 'bg-dark bg-opacity-50 border-secondary text-secondary'}`}
                      style={{ cursor: 'pointer', border: '1px solid' }}
                    >
                      <h6 className="m-0 text-truncate fw-bold">{item.title}</h6>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-9">
          <div className="glass-card p-4 mb-4">
            <div className="input-group input-group-lg">
              <input 
                type="text" 
                className="form-control bg-dark text-white border-secondary"
                placeholder="취재 주제를 입력하세요 (예: 2025년 IT 트렌드)" 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
              />
              <button 
                className="btn btn-primary fw-bold blue-glow px-5 border-0"
                style={{ background: 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
                onClick={handleGenerate}
                disabled={isGenerating}
              >
                {isGenerating ? (
                    <span><span className="spinner-border spinner-border-sm me-2"></span>AI 작성 중...</span>
                ) : (
                    '기사 생성'
                )}
              </button>
            </div>
            {isMockMode && <div className="mt-2 text-amber-400 text-xs font-bold"><i className="bi bi-zap-fill me-1"></i>Mock Mode 활성화 중 (샘플 데이터 사용)</div>}
          </div>

          {currentArticle ? (
            <div className="glass-card p-0 overflow-hidden animate-fade-in border-0">
              <div className="position-relative" style={{ height: '400px', backgroundColor: '#000' }}>
                <img src={currentArticle.imageUrl} alt="News" className="w-100 h-100 object-fit-cover" />
                <div className="position-absolute bottom-0 start-0 w-100 p-5" style={{ background: 'linear-gradient(to top, rgba(0,0,0,0.9) 0%, transparent 100%)' }}>
                    <span className="badge bg-success mb-2 p-2">{currentArticle.factCheck}</span>
                    <h1 className="text-white fw-bold display-5 drop-shadow m-0">{currentArticle.title}</h1>
                </div>
              </div>

              <div className="p-5 bg-dark bg-opacity-40">
                <div className="d-flex justify-content-between text-secondary mb-4 pb-3 border-bottom border-secondary border-opacity-25">
                    <span className="fw-bold text-white"><i className="bi bi-robot me-2"></i>동아 AI 기자</span>
                    <span>{currentArticle.date}</span>
                </div>

                <div 
                  className="text-white text-opacity-90 mb-5 article-content" 
                  style={{ lineHeight: '1.9', fontSize: '1.15rem' }}
                  dangerouslySetInnerHTML={{ __html: currentArticle.content }}
                />
              </div>
            </div>
          ) : (
            <div className="glass-card p-5 text-center text-secondary d-flex flex-column align-items-center justify-content-center" style={{ minHeight: '550px' }}>
