import React, { useState } from 'react';
import { generateNewsImage } from '../services/gemini';
import { ImageIcon, Loader2, Sparkles, Download, Zap } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIIllustrator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [image, setImage] = useState<string | null>(null);
  const [errorType, setErrorType] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!prompt) return;
    setLoading(true);
    setErrorType(null);
    try {
      const img = await generateNewsImage(prompt, isMockMode);
      setImage(img);
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        setErrorType("QUOTA_EXCEEDED");
