    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say this cheerful trot singer style: ${cleanLyrics}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Puck' },
          },
        },
      },
    });
    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  } catch (error) {
    return handleAIError(error);
  }
};

export const decodeAudio = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const numChannels = 1;
  const sampleRate = 24000;
  const dataInt16 = new Int16Array(bytes.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

import React, { useState } from 'react';
import { generateArticle, generateNewsImage } from '../services/gemini';
import { Zap, AlertCircle } from 'lucide-react';

interface NewsArticle {
  id: number;
  title: string;
  category: string;
  content: string;
  imageUrl: string; 
  date: string;
  sources: string[];
  factCheck: string;
}

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [currentArticle, setCurrentArticle] = useState<NewsArticle | null>(null);
  const [savedArticles, setSavedArticles] = useState<NewsArticle[]>([]);
  const [errorType, setErrorType] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!topic.trim()) {
      alert("취재할 주제를 입력해주세요!");
      return;
    }

    setIsGenerating(true);
    setErrorType(null);
    try {
      const aiData = await generateArticle(topic, isMockMode);
      // 이미지 생성 시 에러가 나더라도 기사는 보여줄 수 있도록 fallback 처리
      let imageUrl = `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
      try {
        const generatedImg = await generateNewsImage(aiData.imageKeyword || "news", isMockMode);
        if (generatedImg) imageUrl = generatedImg;
      } catch (e) {
        console.warn("Image fallback used due to error", e);
      }

      const newArticle: NewsArticle = {
        id: Date.now(),
        title: aiData.title,
        category: aiData.category,
        content: aiData.content,
        imageUrl: imageUrl,
        date: new Date().toLocaleDateString(),
        sources: aiData.sources || [],
        factCheck: aiData.factCheck || "동아 데이터 검증 완료",
      };

      setCurrentArticle(newArticle);
      setSavedArticles(prev => [newArticle, ...prev]);
      setTopic('');
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") {
        setErrorType("QUOTA_EXCEEDED");
      } else {
        console.error("Failed to generate article:", error);
        setErrorType("UNKNOWN");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="container-fluid py-4">
      {errorType === "QUOTA_EXCEEDED" && (
        <div className="bg-amber-500/10 border border-amber-500/50 p-4 rounded-2xl mb-4 flex items-center justify-between animate-in fade-in slide-in-from-top-2">
          <div className="flex items-center gap-3 text-amber-200">
            <AlertCircle size={24} className="text-amber-400" />
            <div>
              <p className="font-bold m-0">API 할당량 초과 (429 Error)</p>
              <p className="text-sm m-0 opacity-80">현재 사용 중인 API 키의 무료 호출 한도가 소진되었습니다. 데모 모드로 전환하시겠습니까?</p>
            </div>
          </div>
          <button 
            onClick={() => { setIsMockMode(true); setErrorType(null); }}
            className="bg-amber-500 text-black px-4 py-2 rounded-xl font-bold hover:bg-amber-400 transition-colors whitespace-nowrap shadow-lg"
          >
            데모 모드로 계속하기
          </button>
        </div>
      )}

      {errorType === "UNKNOWN" && (
        <div className="bg-rose-500/10 border border-rose-500/50 p-4 rounded-2xl mb-4 flex items-center gap-3 text-rose-200">
          <AlertCircle size={24} className="text-rose-400" />
          <p className="m-0">기사 생성 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.</p>
        </div>
      )}

      <div className="row g-4 h-100">
        <div className="col-lg-3">
          <div className="glass-card h-100 p-3 d-flex flex-column" style={{ minHeight: '80vh' }}>
            <h5 className="text-white fw-bold mb-4 pb-2 border-bottom border-secondary">
              <i className="bi bi-archive-fill me-2 text-blue-400"></i>기사 보관함
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1">
              {savedArticles.length === 0 ? (
                <div className="text-secondary text-center py-5 opacity-50">
                    <p>작성된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="d-grid gap-2">
                  {savedArticles.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => setCurrentArticle(item)}
                      className={`p-3 rounded transition-all ${currentArticle?.id === item.id ? 'bg-primary border-primary text-white shadow-lg' : 'bg-dark bg-opacity-50 border-secondary text-secondary'}`}
                      style={{ cursor: 'pointer', border: '1px solid' }}
                    >
                      <h6 className="m-0 text-truncate fw-bold">{item.title}</h6>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-9">
          <div className="glass-card p-4 mb-4 shadow-xl">
            <div className="input-group input-group-lg">
              <input 
                type="text" 
                className="form-control bg-dark text-white border-secondary focus:border-blue-500"
                placeholder="취재 주제를 입력하세요 (예: 2025년 IT 트렌드)" 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
              />
              <button 
                className={`btn ${isMockMode ? 'btn-warning' : 'btn-primary'} fw-bold blue-glow px-5 border-0`}
                style={{ background: isMockMode ? 'linear-gradient(135deg, #d97706 0%, #f59e0b 100%)' : 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
                onClick={handleGenerate}
                disabled={isGenerating}
              >
                {isGenerating ? (
                    <span><span className="spinner-border spinner-border-sm me-2"></span>AI 작성 중...</span>
                ) : (
                    '기사 생성'
                )}
              </button>
            </div>
            {isMockMode && <div className="mt-2 text-amber-400 text-xs font-bold animate-pulse"><i className="bi bi-zap-fill me-1"></i>Mock Mode 활성화 중 (샘플 데이터 사용)</div>}
          </div>

          {currentArticle ? (
            <div className="glass-card p-0 overflow-hidden animate-fade-in border-0 shadow-2xl">
              <div className="position-relative" style={{ height: '400px', backgroundColor: '#000' }}>
                <img src={currentArticle.imageUrl} alt="News" className="w-100 h-100 object-fit-cover opacity-80" />
                <div className="position-absolute bottom-0 start-0 w-100 p-5" style={{ background: 'linear-gradient(to top, rgba(2,6,23,1) 0%, rgba(2,6,23,0.8) 50%, transparent 100%)' }}>
                    <span className="badge bg-success mb-2 p-2 shadow-lg">{currentArticle.factCheck}</span>
                    <h1 className="text-white fw-bold display-5 drop-shadow m-0">{currentArticle.title}</h1>
                </div>
              </div>

              <div className="p-5 bg-slate-900">
                <div className="d-flex justify-content-between text-secondary mb-4 pb-3 border-bottom border-slate-800">
                    <span className="fw-bold text-blue-400"><i className="bi bi-robot me-2"></i>동아 AI 기자 (Alpha 2.0)</span>
                    <span>{currentArticle.date}</span>
                </div>

                <div 
                  className="text-white text-opacity-90 mb-5 article-content" 
                  style={{ lineHeight: '2.0', fontSize: '1.2rem' }}
                  dangerouslySetInnerHTML={{ __html: currentArticle.content }}
                />

                <div className="mt-5 pt-4 border-t border-slate-800">
                   <p className="text-slate-500 text-sm">출처: {currentArticle.sources.join(', ')}</p>
                </div>
              </div>
            </div>
          ) : (
            <div className="glass-card p-5 text-center text-secondary d-flex flex-column align-items-center justify-content-center" style={{ minHeight: '550px' }}>
                <i className="bi bi-stars display-2 text-blue-500 mb-3 animate-pulse"></i>
                <h3 className="fw-bold text-white">동아 AI 뉴스룸</h3>
                <p>기사 주제를 입력하여 AI 취재 및 작성을 시작하세요.</p>
                <p className="text-xs opacity-50 mt-4 italic">The Future of Journalism starts here.</p>
            </div>
          )}
        </div>
      </div>
      <style>{`
        .article-content p { margin-bottom: 1.8rem; }
        .article-content b { color: #60a5fa; font-weight: 800; }
        .object-fit-cover { object-fit: cover; }
        .drop-shadow { filter: drop-shadow(0 2px 4px rgba(0,0,0,0.8)); }
      `}</style>
    </div>
  );
};

export default AIWriter;

