import React, { useState } from 'react';
import { generateArticle, generateImage } from '../services/gemini';
import { Sparkles, Save, Loader2, Camera, FileText, AlertTriangle, CheckCircle } from 'lucide-react';

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState("");
  const [category, setCategory] = useState("social");

  // 결과 저장 변수 (객체 구조로 변경)
  const [articleData, setArticleData] = useState<{
    title: string;
    content: string;
    category: string;
    factCheck: string;
    sources: string[];
  } | null>(null);

  const [imageResult, setImageResult] = useState<string | null>(null);

  // 상태 관리
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");

  // ★ 기사 + 사진 한 번에 생성하기
  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }

    setLoading(true);
    setArticleData(null);
    setImageResult(null);
    setErrorMsg("");

    try {
      // 1단계: 기사 작성
      setStatusText("1단계: AI 기자가 기사를 작성 중입니다... ✍️");
      const result = await generateArticle(topic, category, isMockMode);

      if (!result) throw new Error("기사 생성 결과가 없습니다.");

      // JSON 결과 파싱 및 상태 저장
      setArticleData({
        title: result.title || topic,
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "동아 데이터 검증 완료",
        sources: result.sources || []
      });

      // 2단계: 사진 촬영
      setStatusText("2단계: 현장 사진을 생성 중입니다... 📸");
      try {
        const photoPrompt = `Professional news photo for: ${topic}, high quality, realistic`;
        const imgUrl = await generateImage(photoPrompt, isMockMode);
        setImageResult(imgUrl);
      } catch (imgError) {
        console.warn("이미지 생성 실패, 기사만 노출합니다.", imgError);
      }

    } catch (e: any) {
      console.error(e);
      if (e.message === "QUOTA_EXCEEDED") {
        setErrorMsg("API 할당량이 초과되었습니다. 상단의 Demo 모드를 켜주세요.");
      } else {
        setErrorMsg("취재 중 오류가 발생했습니다. 잠시 후 다시 시도해주세요.");
      }
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  // ★ 저장 기능
  const handleSave = () => {
    if (!articleData) {
        alert("저장할 기사가 없습니다.");
        return;
    }

    const newArticle = {
      id: Date.now(),
      title: articleData.title,
      category: articleData.category,
      content: articleData.content,
      image: imageResult,
      date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      factCheck: articleData.factCheck
    };

    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    localStorage.setItem('my_articles', JSON.stringify([newArticle, ...saved]));

    alert("✅ 특종 기사가 발행되어 대시보드에 저장되었습니다!");
  };

  return (
    <div className="h-100 p-2">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold m-0"><i className="bi bi-pen-fill text-primary me-2"></i>AI 통합 취재실</h2>
        {isMockMode && <span className="badge bg-warning text-dark animate-pulse px-3 py-2 rounded-pill fw-bold">Demo Mode Active</span>}
      </div>

      {/* 1. 입력 패널 */}
      <div className="glass-card p-4 mb-4 rounded-3 border-0 shadow-lg" style={{ background: 'rgba(30, 41, 59, 0.5)' }}>
        <div className="row g-3">
          <div className="col-md-2">
            <select 
              className="form-select bg-slate-900 text-white border-slate-700 h-100" 
              value={category} 
              onChange={(e) => setCategory(e.target.value)}
            >
              <option value="social">사회</option>
              <option value="politics">정치</option>
              <option value="economy">경제</option>
              <option value="culture">문화</option>
              <option value="tech">IT/과학</option>
            </select>
          </div>
          <div className="col-md-8">
            <input 
              className="form-control bg-slate-900 text-white border-slate-700 h-100 fs-5" 
              placeholder="취재할 핵심 주제를 입력하세요..." 
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()}
            />
          </div>
          <div className="col-md-2">
            <button 
              className="btn btn-primary w-100 h-100 d-flex align-items-center justify-content-center gap-2 fw-bold" 
              onClick={handleFullCreation} 
              disabled={loading}
            >
              {loading ? <Loader2 className="animate-spin" size={20}/> : <Sparkles size={20}/>}
              {loading ? "취재 중" : "취재 시작"}
            </button>
          </div>
        </div>

        {loading && (
            <div className="mt-4 p-3 bg-blue-500/10 rounded border border-blue-500/30 text-blue-400 fw-bold text-center animate-pulse">
                <i className="bi bi-hourglass-split me-2"></i> {statusText}
            </div>
        )}

        {errorMsg && (
            <div className="mt-4 p-3 bg-red-500/10 rounded border border-red-500/30 text-red-400 fw-bold text-center">
                <AlertTriangle size={18} className="me-2 inline-block"/>
                {errorMsg}
                {errorMsg.includes("할당량") && (
                  <button className="btn btn-sm btn-outline-warning ms-3" onClick={() => setIsMockMode(true)}>데모 모드 켜기</button>
                )}
            </div>
        )}
      </div>

      {/* 2. 결과 화면 */}
      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            {/* 왼쪽: 기사 본문 편집기 */}
            <div className="col-lg-8">
                <div className="glass-card p-4 rounded-3 h-100 border-0 shadow-lg overflow-hidden">
                    <div className="d-flex align-items-center justify-content-between mb-4 pb-3 border-bottom border-slate-700">
                        <div className="d-flex align-items-center">
                          <FileText className="text-primary me-2"/>
                          <h5 className="fw-bold m-0 text-white">작성된 기사 초안</h5>
                        </div>
                        <span className="badge bg-success/20 text-success border border-success/30 px-3 py-2">
                          <CheckCircle size={14} className="me-1 inline"/> {articleData.factCheck}
                        </span>
                    </div>

                    <div className="mb-4">
                      <label className="text-slate-500 text-xs uppercase font-bold mb-2 block">헤드라인</label>
                      <input 
                        className="form-control bg-transparent border-0 text-white fw-bold fs-2 p-0 focus:ring-0" 
                        value={articleData.title}
                        onChange={(e) => setArticleData({...articleData, title: e.target.value})}
                      />
                    </div>

                    <div className="mb-4">
                      <label className="text-slate-500 text-xs uppercase font-bold mb-2 block">기사 본문</label>
                      <textarea 
                          className="form-control bg-slate-900/50 border-slate-700 text-slate-300 p-4" 
                          style={{ height: '450px', resize: 'none', fontFamily: 'serif', fontSize: '1.15rem', lineHeight: '1.8' }}
                          value={articleData.content.replace(/<[^>]*>/g, '')} // 단순화를 위해 태그 제거 후 편집 유도
                          onChange={(e) => setArticleData({...articleData, content: e.target.value})}
                      />
                    </div>

                    <div className="text-slate-500 text-sm italic">
                      참고 자료: {articleData.sources.join(', ')}
                    </div>
                </div>
            </div>

            {/* 오른쪽: 현장 사진 & 액션 */}
            <div className="col-lg-4">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-3 border-0 shadow-lg">
                        <div className="d-flex align-items-center mb-3 pb-2 border-bottom border-slate-700">
                            <Camera className="text-warning me-2"/>
                            <h5 className="fw-bold m-0 text-white">생성된 보도 사진</h5>
                        </div>

                        <div className="bg-slate-900 rounded-lg overflow-hidden mb-3 border border-slate-800 flex items-center justify-center" style={{ aspectRatio: '16/9' }}>
                            {imageResult ? (
                                <img src={imageResult} alt="News" className="w-full h-full object-cover"/>
                            ) : (
                                <div className="text-center text-slate-600">
                                    <Camera size={48} className="mb-2 opacity-20"/>
                                    <p className="small m-0">이미지를 불러올 수 없습니다.</p>
                                </div>
                            )}
                        </div>
                        <p className="text-xs text-slate-500 text-center">AI가 기사 키워드를 바탕으로 생성한 이미지입니다.</p>
                    </div>

                    <div className="glass-card p-4 rounded-3 border-0 shadow-lg mt-auto bg-blue-600/10 border-blue-600/20">
                        <button 
                            className="btn btn-primary w-100 py-3 fw-bold fs-5 shadow-lg d-flex align-items-center justify-content-center gap-2" 
                            onClick={handleSave} 
                            disabled={loading || !articleData}
                        >
                            <Save size={22}/> 기사 최종 발행
                        </button>
                        <p className="text-center text-slate-500 text-xs mt-3">발행된 기사는 대시보드 메뉴에서 확인할 수 있습니다.</p>
                    </div>
                </div>
            </div>
        </div>
      )}
      <style>{`
        .animate-fade-in { animation: fadeIn 0.8s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
      `}</style>
    </div>
  );
};

