import React, { useState, useEffect, useRef } from 'react';
import { Camera, Send, MessageCircle, Heart, ThumbsUp, Angry, Frown, Save, Trash2 } from 'lucide-react';

interface Comment {
  id: number;
  user: string;
  text: string;
  date: string;
}

interface SavedHeadline {
  id: number;
  name: string;
  headline: string;
  image: string;
  reactions: {
    like: number;
    heart: number;
    angry: number;
    sad: number;
  };
  comments: Comment[];
  date: string;
}

const HeadlineMaker: React.FC = () => {
  const [name, setName] = useState('');
  const [headline, setHeadline] = useState('');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedHeadlines, setSavedHeadlines] = useState<SavedHeadline[]>([]);
  const [commentInputs, setCommentInputs] = useState<{ [key: number]: string }>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('viewer_headlines');
    if (saved) setSavedHeadlines(JSON.parse(saved));
  }, []);

  const saveToLocal = (data: SavedHeadline[]) => {
    setSavedHeadlines(data);
    localStorage.setItem('viewer_headlines', JSON.stringify(data));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const publishHeadline = () => {
    if (!name.trim() || !headline.trim()) {
      alert("이름과 속보 내용을 입력해주세요!");
      return;
    }

    const newEntry: SavedHeadline = {
      id: Date.now(),
      name,
      headline,
      image: uploadedImage || 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80',
      reactions: { like: 0, heart: 0, angry: 0, sad: 0 },
      comments: [],
      date: new Date().toLocaleString()
    };

    const updated = [newEntry, ...savedHeadlines];
    saveToLocal(updated);

    // Reset inputs
    setName('');
    setHeadline('');
    setUploadedImage(null);
    alert("🚀 속보가 전 세계로 타전되었습니다!");
  };

  const handleReaction = (id: number, type: keyof SavedHeadline['reactions']) => {
    const updated = savedHeadlines.map(h => {
      if (h.id === id) {
        return { ...h, reactions: { ...h.reactions, [type]: h.reactions[type] + 1 } };
      }
      return h;
    });
    saveToLocal(updated);
  };

  const addComment = (id: number) => {
    const text = commentInputs[id];
    if (!text?.trim()) return;

    const updated = savedHeadlines.map(h => {
      if (h.id === id) {
        const newComment: Comment = {
          id: Date.now(),
          user: "익명의 독자",
          text,
          date: "방금 전"
        };
        return { ...h, comments: [...h.comments, newComment] };
      }
      return h;
    });

    saveToLocal(updated);
    setCommentInputs({ ...commentInputs, [id]: '' });
  };

  const deleteHeadline = (id: number) => {
    if (!window.confirm("이 속보를 삭제하시겠습니까?")) return;
    const updated = savedHeadlines.filter(h => h.id !== id);
    saveToLocal(updated);
  };

  return (
    <div className="text-white pb-5 animate-fade-in">
      <div className="row g-5">
        {/* 왼쪽: 속보 제작 도구 */}
        <div className="col-lg-5">
          <div className="glass-card p-4 sticky-top border-0 shadow-2xl" style={{ top: '20px', background: '#0f172a' }}>
            <h3 className="fw-bold mb-4 d-flex align-items-center gap-2">
              <Camera className="text-danger" /> 나만의 속보 만들기
            </h3>

            <div className="mb-3">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">주인공 성함</label>
              <input 
                type="text" 
                placeholder="예: 홍길동" 
                className="form-control !bg-slate-900 border-slate-700 py-3 text-white fs-5"
                value={name}
                onChange={(e) => setName(e.target.value)}
              />
            </div>

            <div className="mb-3">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">속보 타이틀</label>
              <input 
                type="text" 
                placeholder="예: 오늘 점심 메뉴로 돈까스 선택해 큰 화제" 
                className="form-control !bg-slate-900 border-slate-700 py-3 text-white fs-5"
                value={headline}
                onChange={(e) => setHeadline(e.target.value)}
              />
            </div>

            <div className="mb-4">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">배경 사진 업로드</label>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="btn btn-outline-slate-500 w-100 py-3 border-dashed border-2 d-flex align-items-center justify-content-center gap-2 text-slate-300 hover:text-white hover:bg-slate-800"
              >
                <Camera size={20} /> {uploadedImage ? "사진 변경하기" : "내 사진 선택하기"}
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleImageUpload} 
                className="hidden" 
                accept="image/*" 
              />
            </div>

            <div className="preview-container mb-4">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">실시간 프리뷰</label>
              <div className="position-relative rounded-3 overflow-hidden border border-slate-700 shadow-lg" style={{ height: '240px', background: '#000' }}>
                <img 
                    src={uploadedImage || `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80`} 
                    alt="news bg" 
                    className="w-100 h-100 object-cover opacity-60"
                />
                <div className="position-absolute bottom-0 start-0 w-100 p-3" style={{ background: 'linear-gradient(to right, #cc0000 0%, #7f0000 100%)' }}>
                    <div className="d-flex align-items-center gap-2">
                        <span className="badge bg-white text-danger fw-black px-2 py-1 animate-pulse" style={{ fontSize: '0.7rem' }}>속보</span>
                        <span className="text-white fw-bold fs-5 tracking-tighter truncate">
                            {name ? `${name} 씨, ` : '동아인, '} 
                            {headline || '이곳에 속보 내용이 표시됩니다'}
                        </span>
                    </div>
                </div>
                <div className="position-absolute top-0 end-0 p-3">
                    <span className="badge bg-danger flex items-center gap-1 px-2 py-1 shadow-lg">● LIVE</span>
                </div>
              </div>
            </div>

            <button 
                className="btn btn-danger w-100 py-3 fw-bold fs-5 shadow-lg d-flex align-items-center justify-content-center gap-2 border-0" 
                style={{ background: 'linear-gradient(135deg, #E50914 0%, #9b070d 100%)' }}
                onClick={publishHeadline}
            >
                <Send size={22}/> 속보 전 세계 발행
            </button>
          </div>
        </div>

        {/* 오른쪽: 타임라인 (저장된 기사들) */}
        <div className="col-lg-7">
