interface Comment {
  id: number;
  user: string;
  text: string;
  date: string;
}

interface SavedHeadline {
  id: number;
  name: string;
  headline: string;
  image: string;
  script?: string;
  summary?: string;
  hashtags?: string[];
  reactions: {
    like: number;
    heart: number;
    angry: number;
    sad: number;
  };
  comments: Comment[];
  date: string;
}

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const HeadlineMaker: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [name, setName] = useState('');
  const [headline, setHeadline] = useState('');
  const [material, setMaterial] = useState('');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedHeadlines, setSavedHeadlines] = useState<SavedHeadline[]>([]);
  const [commentInputs, setCommentInputs] = useState<{ [key: number]: string }>({});

  // AI 스크립트 상태
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [aiScript, setAiScript] = useState<{ summary: string, script: string, hashtags: string[] } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('viewer_headlines');
    if (saved) setSavedHeadlines(JSON.parse(saved));
  }, []);

  const saveToLocal = (data: SavedHeadline[]) => {
    setSavedHeadlines(data);
    localStorage.setItem('viewer_headlines', JSON.stringify(data));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleAnalyzeMaterial = async () => {
    if (!material.trim()) {
      alert("분석할 자료나 이슈 내용을 입력해주세요!");
      return;
    }
    setIsAnalyzing(true);
    setAiScript(null);
    try {
      const result = await generateNewsScript(material, isMockMode);
      setAiScript(result);
      // 요약된 내용으로 헤드라인 자동 추천 (첫 문장 활용)
      if (!headline) {
        setHeadline(result.summary.split('.')[0]);
      }
    } catch (error) {
      console.error(error);
      alert("자료 분석 중 오류가 발생했습니다.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const publishHeadline = () => {
    if (!name.trim() || !headline.trim()) {
      alert("이름과 속보 내용을 입력해주세요!");
      return;
    }

    const newEntry: SavedHeadline = {
      id: Date.now(),
      name,
      headline,
      image: uploadedImage || 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80',
      summary: aiScript?.summary,
      script: aiScript?.script,
      hashtags: aiScript?.hashtags,
      reactions: { like: 0, heart: 0, angry: 0, sad: 0 },
      comments: [],
      date: new Date().toLocaleString()
    };

    const updated = [newEntry, ...savedHeadlines];
    saveToLocal(updated);

    // Reset
    setName('');
    setHeadline('');
    setMaterial('');
    setUploadedImage(null);
    setAiScript(null);
    alert("🚀 특종 기사가 발행되었습니다!");
  };

  const handleReaction = (id: number, type: keyof SavedHeadline['reactions']) => {
    const updated = savedHeadlines.map(h => {
      if (h.id === id) return { ...h, reactions: { ...h.reactions, [type]: h.reactions[type] + 1 } };
      return h;
    });
    saveToLocal(updated);
  };

  const addComment = (id: number) => {
    const text = commentInputs[id];
    if (!text?.trim()) return;
    const updated = savedHeadlines.map(h => {
      if (h.id === id) {
        return { ...h, comments: [...h.comments, { id: Date.now(), user: "익명의 독자", text, date: "방금 전" }] };
      }
      return h;
    });
    saveToLocal(updated);
    setCommentInputs({ ...commentInputs, [id]: '' });
  };

  const deleteHeadline = (id: number) => {
