            </div>

            {/* 자료 분석 입력창 */}
            <div className="mb-4">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider d-flex justify-content-between">
                <span>데이터/이슈 분석 자료</span>
                <span className="text-blue-400">AI 분석 지원</span>
              </label>
              <textarea 
                className="form-control !bg-slate-900 border-slate-700 text-white text-sm"
                rows={4}
                placeholder="분석할 원문 자료, 통계, 혹은 핫한 이슈 내용을 여기에 붙여넣으세요..."
                value={material}
                onChange={(e) => setMaterial(e.target.value)}
                style={{ resize: 'none' }}
              />
              <button 
                onClick={handleAnalyzeMaterial}
                disabled={isAnalyzing || !material.trim()}
                className="btn btn-primary w-100 mt-2 d-flex align-items-center justify-content-center gap-2 font-bold py-2 shadow-lg"
                style={{ background: 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
              >
                {isAnalyzing ? <Loader2 size={16} className="animate-spin" /> : <Cpu size={16} />}
                {isAnalyzing ? "데이터 정밀 분석 중..." : "AI 대본 및 요약 추출"}
              </button>
            </div>

            <div className="row g-3 mb-3">
              <div className="col-4">
                <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">주인공</label>
                <input 
                  type="text" 
                  placeholder="이름" 
                  className="form-control !bg-slate-900 border-slate-700 py-3 text-white"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                />
              </div>
              <div className="col-8">
                <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">속보 헤드라인</label>
                <input 
                  type="text" 
                  placeholder="뉴스 하단에 표시될 제목" 
                  className="form-control !bg-slate-900 border-slate-700 py-3 text-white"
                  value={headline}
                  onChange={(e) => setHeadline(e.target.value)}
                />
              </div>
            </div>

            <div className="mb-4">
              <label className="text-slate-400 text-xs font-bold mb-2 block uppercase tracking-wider">배경 사진 (합성용)</label>
              <button 
                onClick={() => fileInputRef.current?.click()}
