                   <p className="text-[11px] text-slate-300 m-0 line-clamp-3 italic">"{aiScript.summary}"</p>
                </div>
              </div>
            )}

            <div className="preview-container mb-4">
              <div className="position-relative rounded-3 overflow-hidden border border-slate-700 shadow-lg" style={{ height: '220px', background: '#000' }}>
                <img src={uploadedImage || 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80'} className="w-100 h-100 object-cover opacity-60" />
                <div className="position-absolute bottom-0 start-0 w-100 p-3" style={{ background: 'linear-gradient(to right, #cc0000 0%, #7f0000 100%)' }}>
                    <div className="d-flex align-items-center gap-2">
                        <span className="badge bg-white text-danger fw-black px-2 py-1 animate-pulse">속보</span>
                        <span className="text-white fw-bold truncate">{name ? `${name} 씨, ` : ''}{headline || '헤드라인을 입력하세요'}</span>
                    </div>
