const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [writeMode, setWriteMode] = useState<'topic' | 'analysis'>('topic');
  const [topic, setTopic] = useState("");
  const [material, setMaterial] = useState(""); // 자료 분석용 입력
  const [category, setCategory] = useState("social");

  const [articleData, setArticleData] = useState<{
    title: string;
    content: string;
    category: string;
    factCheck: string;
    sources: string[];
    summary?: string;
  } | null>(null);

  const [imageResult, setImageResult] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");

  // AI 분석 및 초안 생성 (자료 기반)
  const handleMaterialAnalysis = async () => {
    if (!material.trim()) {
      alert("분석할 자료나 이슈 데이터를 입력해주세요!");
      return;
    }
    setLoading(true);
    setErrorMsg("");
    setStatusText("데이터 정밀 분석 및 대본 추출 중... 🤖");

    try {
      const result = await generateNewsScript(material, isMockMode);

      setArticleData({
        title: result.summary.split('.')[0] || "AI 분석 속보",
        content: result.script,
        category: category,
        factCheck: "AI 데이터 분석 완료",
        sources: ["입력 데이터 원본", "AI 분석 센터"],
        summary: result.summary
      });

      setStatusText("관련 보도 사진 생성 중... 📸");
      const imgUrl = await generateImage(result.summary.substring(0, 50), isMockMode);
      setImageResult(imgUrl);

    } catch (e: any) {
      console.error(e);
      setErrorMsg("자료 분석 중 오류가 발생했습니다.");
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  // 일반 주제 기반 생성
  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }

    setLoading(true);
    setArticleData(null);
    setImageResult(null);
    setErrorMsg("");

    try {
      setStatusText("AI 기자가 기사를 작성 중입니다... ✍️");
      const result = await generateArticle(topic, category, isMockMode);

      setArticleData({
        title: result.title || topic,
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "동아 데이터 검증 완료",
        sources: result.sources || []
      });

      setStatusText("현장 사진 생성 중... 📸");
      const imgUrl = await generateImage(topic, isMockMode);
      setImageResult(imgUrl);

    } catch (e: any) {
      setErrorMsg("취재 중 오류가 발생했습니다.");
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  const handleSave = () => {
    if (!articleData) return;
    const newArticle = {
      id: Date.now(),
      title: articleData.title,
      category: articleData.category,
      content: articleData.content,
      image: imageResult,
      date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      factCheck: articleData.factCheck
    };
    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    localStorage.setItem('my_articles', JSON.stringify([newArticle, ...saved]));
    alert("✅ 특종 기사가 발행되어 대시보드에 저장되었습니다!");
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold m-0"><i className="bi bi-cpu-fill text-primary me-2"></i>AI 스마트 통합 취재실</h2>
        <div className="btn-group shadow-sm">
          <button 
            className={`btn btn-sm ${writeMode === 'topic' ? 'btn-primary' : 'btn-outline-secondary'}`}
            onClick={() => setWriteMode('topic')}
          >단순 주제</button>
          <button 
            className={`btn btn-sm ${writeMode === 'analysis' ? 'btn-primary' : 'btn-outline-secondary'}`}
            onClick={() => setWriteMode('analysis')}
          >자료 분석</button>
        </div>
      </div>

      {/* 1. 입력 패널 */}
      <div className="glass-card p-4 mb-4 rounded-3 border-0 shadow-lg" style={{ background: 'rgba(15, 23, 42, 0.8)' }}>
        {writeMode === 'topic' ? (
          <div className="row g-3">
            <div className="col-md-2">
              <select className="form-select" value={category} onChange={(e) => setCategory(e.target.value)}>
                <option value="social">사회</option>
                <option value="politics">정치</option>
                <option value="economy">경제</option>
                <option value="tech">IT/과학</option>
              </select>
            </div>
            <div className="col-md-8">
              <input 
                className="form-control fs-5" 
                placeholder="취재할 핵심 주제를 한 줄로 입력하세요..." 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()}
              />
            </div>
            <div className="col-md-2">
              <button className="btn btn-primary w-100 h-100 fw-bold" onClick={handleFullCreation} disabled={loading}>
                {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={18} className="me-2"/>}
                취재 시작
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            <label className="text-slate-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
              <FileSearch size={14}/> 분석할 원문 자료 또는 데이터 (이슈 전문 등)
            </label>
            <textarea 
              className="form-control"
              style={{ height: '150px', resize: 'none' }}
              placeholder="여기에 요약하거나 대본화할 자료를 붙여넣으세요. AI가 자동으로 핵심을 파악하여 기사를 구성합니다."
              value={material}
              onChange={(e) => setMaterial(e.target.value)}
            />
            <button 
              className="btn btn-primary w-100 py-3 fw-bold d-flex align-items-center justify-content-center gap-2"
              onClick={handleMaterialAnalysis}
              disabled={loading}
              style={{ background: 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
            >
              {loading ? <Loader2 className="animate-spin" /> : <Cpu size={20} />}
              데이터 심층 분석 및 대본 생성 시작
            </button>
          </div>
        )}

        {loading && (
            <div className="mt-4 p-3 bg-blue-500/10 rounded border border-blue-500/30 text-blue-300 fw-bold text-center animate-pulse">
                <i className="bi bi-gear-fill spin me-2"></i> {statusText}
            </div>
        )}
      </div>

      {/* 2. 결과 화면 */}
      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            <div className="col-lg-8">
                <div className="glass-card p-4 rounded-3 h-100 border-0 shadow-2xl" style={{ background: '#0f172a' }}>
                    <div className="d-flex align-items-center justify-content-between mb-4 pb-3 border-bottom border-slate-700">
                        <div className="d-flex align-items-center">
                          <FileText className="text-primary me-2"/>
                          <h5 className="fw-bold m-0 text-white">AI 생성 기사/대본 초안</h5>
                        </div>
                        <span className="badge bg-success text-white px-3 py-2">
                          <CheckCircle size={14} className="me-1 inline"/> {articleData.factCheck}
                        </span>
                    </div>

                    {articleData.summary && (
                      <div className="mb-4 p-3 bg-blue-500/5 rounded border border-blue-500/20">
                        <label className="text-blue-400 text-[10px] font-bold uppercase mb-1 block">AI 핵심 요약</label>
                        <p className="text-slate-300 text-sm m-0 italic">"{articleData.summary}"</p>
                      </div>
                    )}

                    <div className="mb-4">
                      <label className="text-slate-400 text-xs font-bold mb-2 block tracking-widest">HEADLINE</label>
                      <input 
                        className="form-control !bg-transparent border-0 text-white fw-bold fs-2 p-0 shadow-none" 
                        style={{ outline: 'none', boxShadow: 'none', backgroundColor: 'transparent !important' }}
                        value={articleData.title}
                        onChange={(e) => setArticleData({...articleData, title: e.target.value})}
                      />
                    </div>

                    <div className="mb-4">
                      <label className="text-slate-400 text-xs font-bold mb-2 block tracking-widest">CONTENT / SCRIPT</label>
                      <textarea 
                          className="form-control !text-white !bg-slate-900 border-slate-700 p-4 shadow-inner" 
                          style={{ 
                            height: '500px', 
                            resize: 'none', 
                            fontFamily: "'Pretendard', sans-serif", 
                            fontSize: '1.1rem', 
                            lineHeight: '1.8',
                            color: 'white',
                            backgroundColor: '#020617 !important'
                          }}
                          value={articleData.content.replace(/<[^>]*>/g, '')} 
                          onChange={(e) => setArticleData({...articleData, content: e.target.value})}
                      />
                    </div>
                </div>
            </div>

            <div className="col-lg-4">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-3 border-0 shadow-lg" style={{ background: '#1e293b' }}>
                        <div className="d-flex align-items-center mb-3 pb-2 border-bottom border-slate-700">
                            <Camera className="text-warning me-2"/>
                            <h5 className="fw-bold m-0 text-white">보도 사진</h5>
                        </div>
                        <div className="bg-slate-950 rounded-lg overflow-hidden mb-3 border border-slate-800 flex items-center justify-center" style={{ aspectRatio: '16/9' }}>
                            {imageResult ? (
                                <img src={imageResult} alt="News" className="w-full h-full object-cover"/>
                            ) : (
                                <div className="text-center text-slate-700">
                                    <Camera size={40} className="mb-2 opacity-20"/>
                                    <p className="small m-0">이미지 대기 중</p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="glass-card p-4 rounded-3 border-0 shadow-lg mt-auto" style={{ background: 'linear-gradient(to bottom, #1e293b, #0f172a)' }}>
                        <button 
                            className="btn btn-primary w-100 py-3 fw-bold fs-5 shadow-lg d-flex align-items-center justify-content-center gap-2 border-0" 
                            style={{ background: 'linear-gradient(135deg, #2563eb 0%, #1d4ed8 100%)' }}
                            onClick={handleSave} 
                        >
                            <Save size={22}/> 기사 최종 발행
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
      <style>{`
        .animate-fade-in { animation: fadeIn 0.8s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        .spin { animation: fa-spin 2s infinite linear; }
        @keyframes fa-spin { from { transform: rotate(0deg); } to { transform: rotate(359deg); } }
      `}</style>
    </div>
  );
};

