export const generateImage = async (prompt: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 600));
    return `https://images.unsplash.com/photo-1585829365234-78d2b502931d?auto=format&fit=crop&w=1600&q=80`;
  }
  try {
    const ai = getAI();
    // 이미지 내 텍스트 발생을 방지하기 위한 정교한 프롬프트 구성
    const photoPrompt = `Professional photojournalism, news press photography, highly detailed, realistic, cinematic lighting, 8k resolution. Scene: ${prompt}. (CRITICAL: ABSOLUTELY NO TEXT, NO LETTERS, NO WORDS, NO NUMBERS, NO WATERMARK, NO SIGNATURE, NO OVERLAYS IN THE IMAGE).`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: photoPrompt }] },
      config: { imageConfig: { aspectRatio: "16:9" } }
    });
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  } catch (error: any) {
    return handleAIError(error);
  }
};

