            className={`btn btn-sm ${writeMode === 'topic' ? 'btn-primary' : 'btn-outline-secondary'}`}
            onClick={() => setWriteMode('topic')}
          >단순 주제</button>
          <button 
            className={`btn btn-sm ${writeMode === 'analysis' ? 'btn-primary' : 'btn-outline-secondary'}`}
            onClick={() => setWriteMode('analysis')}
          >자료 분석</button>
        </div>
      </div>

      {/* 1. 입력 패널 */}
      <div className="glass-card p-4 mb-4 rounded-3 border-0 shadow-lg" style={{ background: 'rgba(15, 23, 42, 0.8)' }}>
        {writeMode === 'topic' ? (
          <div className="row g-3">
            <div className="col-md-2">
              <select className="form-select" value={category} onChange={(e) => setCategory(e.target.value)}>
                <option value="social">사회</option>
                <option value="politics">정치</option>
                <option value="economy">경제</option>
                <option value="tech">IT/과학</option>
              </select>
            </div>
            <div className="col-md-8">
              <input 
                className="form-control fs-5" 
                placeholder="취재할 핵심 주제를 입력하거나 상단 아이템을 선택하세요..." 
                value={topic}
                onChange={(e) => setTopic(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()}
              />
            </div>
            <div className="col-md-2">
              <button className="btn btn-primary w-100 h-100 fw-bold" onClick={handleFullCreation} disabled={loading}>
                {loading ? <Loader2 className="animate-spin" /> : <Sparkles size={18} className="me-2"/>}
                취재 시작
              </button>
            </div>
          </div>
        ) : (
          <div className="space-y-3">
            <label className="text-slate-400 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
              <FileSearch size={14}/> 분석할 원문 자료 또는 데이터 (이슈 전문 등)
            </label>
            <textarea 
              className="form-control"
              style={{ height: '150px', resize: 'none' }}
              placeholder="여기에 요약하거나 대본화할 자료를 붙여넣으세요. AI가 자동으로 핵심을 파악하여 기사를 구성합니다."
              value={material}
              onChange={(e) => setMaterial(e.target.value)}
            />
            <button 
              className="btn btn-primary w-100 py-3 fw-bold d-flex align-items-center justify-content-center gap-2"
              onClick={handleMaterialAnalysis}
              disabled={loading}
              style={{ background: 'linear-gradient(135deg, #1e40af 0%, #3b82f6 100%)' }}
            >
              {loading ? <Loader2 className="animate-spin" /> : <Cpu size={20} />}
              데이터 심층 분석 및 대본 생성 시작
            </button>
          </div>
        )}

        {loading && (
            <div className="mt-4 p-3 bg-blue-500/10 rounded border border-blue-500/30 text-blue-300 fw-bold text-center animate-pulse">
                <i className="bi bi-gear-fill spin me-2"></i> {statusText}
            </div>
        )}
      </div>

      {/* 2. 결과 화면 */}
      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            <div className="col-lg-8">
                <div className="glass-card p-4 rounded-3 h-100 border-0 shadow-2xl" style={{ background: '#0f172a' }}>
                    <div className="d-flex align-items-center justify-content-between mb-4 pb-3 border-bottom border-slate-700">
                        <div className="d-flex align-items-center">
                          <FileText className="text-primary me-2"/>
                          <h5 className="fw-bold m-0 text-white">AI 생성 기사/대본 초안</h5>
                        </div>
                        <span className="badge bg-success text-white px-3 py-2">
                          <CheckCircle size={14} className="me-1 inline"/> {articleData.factCheck}
                        </span>
                    </div>

                    {articleData.summary && (
                      <div className="mb-4 p-3 bg-blue-500/5 rounded border border-blue-500/20">
                        <label className="text-blue-400 text-[10px] font-bold uppercase mb-1 block">AI 핵심 요약</label>
                        <p className="text-slate-300 text-sm m-0 italic">"{articleData.summary}"</p>
                      </div>
                    )}

                    <div className="mb-4">
                      <label className="text-slate-400 text-xs font-bold mb-2 block tracking-widest">HEADLINE</label>
                      <input 
                        className="form-control !bg-transparent border-0 text-white fw-bold fs-2 p-0 shadow-none" 
                        style={{ outline: 'none', boxShadow: 'none', backgroundColor: 'transparent !important' }}
                        value={articleData.title}
                        onChange={(e) => setArticleData({...articleData, title: e.target.value})}
                      />
                    </div>

                    <div className="mb-4">
                      <label className="text-slate-400 text-xs font-bold mb-2 block tracking-widest">CONTENT / SCRIPT</label>
                      <textarea 
                          className="form-control !text-white !bg-slate-900 border-slate-700 p-4 shadow-inner" 
                          style={{ 
                            height: '500px', 
                            resize: 'none', 
                            fontFamily: "'Pretendard', sans-serif", 
                            fontSize: '1.1rem', 
                            lineHeight: '1.8',
                            color: 'white',
                            backgroundColor: '#020617 !important'
                          }}
                          value={articleData.content.replace(/<[^>]*>/g, '')} 
                          onChange={(e) => setArticleData({...articleData, content: e.target.value})}
                      />
                    </div>
                </div>
            </div>

            <div className="col-lg-4">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-3 border-0 shadow-lg overflow-hidden" style={{ background: '#1e293b' }}>
                        <div className="d-flex align-items-center mb-3 pb-2 border-bottom border-slate-700">
                            <Camera className="text-warning me-2"/>
                            <h5 className="fw-bold m-0 text-white">현장 보도 사진</h5>
                        </div>
                        <div className="position-relative bg-slate-950 rounded-lg overflow-hidden mb-2 border border-slate-800 flex items-center justify-center" style={{ aspectRatio: '16/9' }}>
                            {imageResult ? (
                                <>
                                  <img src={imageResult} alt="News" className="w-full h-full object-cover"/>
                                  <div className="position-absolute bottom-0 start-0 w-100 p-2" style={{ background: 'linear-gradient(to top, rgba(0,0,0,0.8), transparent)' }}>
                                      <p className="text-[10px] text-white/70 m-0 italic flex items-center gap-1">
                                        <Info size={10}/> AI 스마트 카메라 촬영
                                      </p>
                                  </div>
                                </>
