          </div>
        </div>
      </div>

      <div className="row g-4">
        {articles.length === 0 ? (
          <div className="col-12">
            <div className="glass-card p-5 rounded-4 text-center border-dashed border-slate-800">
               <Newspaper size={80} className="mx-auto mb-4 text-slate-800 opacity-20" />
               <h3 className="text-slate-500 fw-bold">아직 도착한 속보가 없습니다.</h3>
               <p className="text-slate-600">기자실에서 첫 번째 기사가 발행될 때까지 잠시만 기다려 주세요.</p>
            </div>
          </div>
        ) : (
          <div className="col-lg-8">
            <div className="d-flex flex-column gap-4">
              {articles.map((article, idx) => (
                <div 
                  key={article.id} 
                  className={`glass-card rounded-4 overflow-hidden border-0 shadow-lg group cursor-pointer transition-all hover:scale-[1.01] ${idx === 0 ? 'ring-2 ring-red-600/50' : ''}`}
                  onClick={() => setSelectedArticle(article)}
                >
                  <div className="row g-0">
                    <div className="col-md-4 position-relative overflow-hidden">
                      {article.image ? (
                        <img src={article.image} alt="news" className="w-100 h-100 object-cover group-hover:scale-110 transition-transform duration-700" style={{ minHeight: '200px' }} />
                      ) : (
                        <div className="w-100 h-100 bg-slate-900 flex items-center justify-center text-slate-800">
                           <Newspaper size={40} />
                        </div>
                      )}
                      {idx === 0 && (
                        <div className="position-absolute top-0 start-0 m-3">
                          <span className="badge bg-red-600 shadow-lg px-2 py-1">최신 속보</span>
                        </div>
                      )}
                    </div>
                    <div className="col-md-8">
                      <div className="p-4">
                        <div className="d-flex align-items-center justify-content-between mb-2">
