                          <span className="text-slate-500 text-[10px] flex items-center gap-1">
                            <Clock size={10} /> {article.date}
                          </span>
                        </div>
                        <h3 className="text-white fw-bold mb-3 line-clamp-2 group-hover:text-red-400 transition-colors">{article.title}</h3>
