                      <Share2 className="text-white" size={20} />
                   </div>
                   <h6 className="fw-bold text-white mb-2">동아 AI 뉴스 제보하기</h6>
                   <p className="text-[10px] text-slate-400 mb-3 leading-relaxed">여러분의 제보가 AI를 통해<br/>전국으로 보도됩니다.</p>
                   <button className="btn btn-sm btn-outline-slate-700 w-100 text-xs fw-bold py-2">제보하기</button>
                </div>
             </div>
          </div>
        )}
      </div>

      {/* 기사 팝업 모달 */}
      {selectedArticle && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/90 backdrop-blur-xl animate-fade-in" onClick={() => setSelectedArticle(null)}>
