              )}
              <div className="absolute inset-0 bg-gradient-to-t from-slate-900 to-transparent"></div>
              <button className="absolute top-6 right-6 w-10 h-10 bg-black/50 hover:bg-red-600 rounded-full flex items-center justify-center transition-all" onClick={() => setSelectedArticle(null)}>
                <ChevronRight className="text-white rotate-180" />
              </button>
              <div className="absolute bottom-6 left-8 right-8">
                 <span className="badge bg-red-600 mb-3 px-3 py-1 text-xs">{selectedArticle.category}</span>
                 <h1 className="text-3xl md:text-4xl font-black text-white leading-tight">{selectedArticle.title}</h1>
