            <div className="flex-1 overflow-y-auto p-8 md:p-12 bg-slate-900 custom-scrollbar">
               <div className="flex items-center gap-6 mb-8 text-slate-500 text-sm border-b border-slate-800 pb-6">
                 <span className="flex items-center gap-2"><Calendar size={14}/> {selectedArticle.date}</span>
                 <span className="flex items-center gap-2"><Clock size={14}/> 방금 전 보도됨</span>
                 <span className="text-green-500 font-bold">✅ {selectedArticle.factCheck}</span>
               </div>

               <div 
                  className="text-slate-200 text-lg leading-relaxed space-y-6"
                  style={{ fontFamily: "'Pretendard', sans-serif", fontSize: '1.2rem' }}
                  dangerouslySetInnerHTML={{ __html: selectedArticle.content }}
                />
            </div>

            <div className="p-6 bg-slate-950 border-t border-slate-800 flex justify-between items-center">
               <div className="flex gap-4">
                 <button className="btn btn-sm btn-outline-slate-800 text-slate-400 hover:text-white flex items-center gap-2"><Heart size={14}/> 공감</button>
                 <button className="btn btn-sm btn-outline-slate-800 text-slate-400 hover:text-white flex items-center gap-2"><MessageCircle size={14}/> 댓글</button>
               </div>
               <button className="btn btn-primary px-8 py-2 font-bold rounded-full" onClick={() => setSelectedArticle(null)}>닫기</button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .animate-fade-in { animation: fadeIn 0.6s ease-out forwards; }
        @keyframes fadeIn { from { opacity: 0; transform: translateY(15px); } to { opacity: 1; transform: translateY(0); } }
        .line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
        .custom-scrollbar::-webkit-scrollbar { width: 5px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 10px; }
      `}</style>
    </div>
  );
};

