interface Comment {
  id: string;
  user: string;
  text: string;
  date: string;
}

interface Article {
  id: number;
  title: string;
  category: string;
  content: string;
  image: string | null;
  date: string;
  factCheck: string;
  likes?: number;
  comments?: Comment[];
}

const RealtimeNews: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [commentInput, setCommentInput] = useState("");

  useEffect(() => {
    const fetchArticles = () => {
      const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
      // 초기값이 없는 경우를 대비한 매핑
      const initialized = saved.map((a: Article) => ({
        ...a,
        likes: a.likes || 0,
        comments: a.comments || []
      }));
      setArticles(initialized);
    };

    fetchArticles();
    const interval = setInterval(fetchArticles, 5000);
    return () => clearInterval(interval);
  }, []);

  // 상호작용 데이터 저장 헬퍼
  const updateArticleInStorage = (updatedArticle: Article) => {
    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    const newArticles = saved.map((a: any) => a.id === updatedArticle.id ? updatedArticle : a);
    localStorage.setItem('my_articles', JSON.stringify(newArticles));
    setArticles(newArticles.map((a: Article) => ({
        ...a,
        likes: a.likes || 0,
        comments: a.comments || []
    })));
    if (selectedArticle?.id === updatedArticle.id) {
