  const handleShare = async (e: React.MouseEvent, article: Article) => {
    e.stopPropagation();

    let shareUrl = "";
    try {
      const url = new URL(window.location.pathname, window.location.origin);
      shareUrl = url.toString();
      if (shareUrl.includes('about:srcdoc') || !shareUrl.startsWith('http')) {
        shareUrl = 'https://www.donga.com'; 
      }
    } catch (err) {
      shareUrl = 'https://www.donga.com';
    }

    const shareData = {
      title: `[동아 AI 뉴스] ${article.title}`,
      text: article.content.replace(/<[^>]*>/g, '').substring(0, 100) + "...",
      url: shareUrl,
    };

    const copyToClipboard = async () => {
      try {
        await navigator.clipboard.writeText(`${shareData.title}\n${shareData.url}`);
        alert("기사 링크가 클립보드에 복사되었습니다!");
      } catch (err) {
        alert("복사 기능이 지원되지 않는 환경입니다.");
      }
    };

    try {
      if (navigator.share && navigator.canShare && navigator.canShare(shareData)) {
        await navigator.share(shareData);
      } else {
        await copyToClipboard();
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        console.warn("Share API failed", err);
        await copyToClipboard();
      }
    }
  };

