interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

interface Suggestion {
  id: string;
  title: string;
  category: string;
  angle: string;
  urgency: string;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [writeMode, setWriteMode] = useState<'topic' | 'analysis'>('topic');
  const [topic, setTopic] = useState("");
  const [material, setMaterial] = useState("");
  const [category, setCategory] = useState("social");

  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [suggestionError, setSuggestionError] = useState<string | null>(null);

  const [articleData, setArticleData] = useState<{
    title: string;
    content: string;
    category: string;
    factCheck: string;
    sources: string[];
    summary?: string;
  } | null>(null);

  const [imageResult, setImageResult] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");

  const fetchSuggestions = async () => {
    setLoadingSuggestions(true);
    setSuggestionError(null);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data);
    } catch (e: any) {
      console.error("Failed to fetch suggestions:", e);
      if (e.message === "QUOTA_EXCEEDED") {
        setSuggestionError("API 할당량 초과. Demo 모드를 이용해 주세요.");
      } else {
        setSuggestionError("실시간 트렌드를 불러오지 못했습니다.");
      }
    } finally {
      setLoadingSuggestions(false);
    }
  };

  useEffect(() => {
    fetchSuggestions();
  }, [isMockMode]);

  const handleQuickStart = (item: Suggestion) => {
    setWriteMode('topic');
    setTopic(item.title);
    setCategory(item.category.toLowerCase().includes('it') || item.category.toLowerCase().includes('과학') ? 'tech' : 
                item.category.toLowerCase().includes('경제') ? 'economy' :
                item.category.toLowerCase().includes('정치') ? 'politics' : 'social');

    window.scrollTo({ top: 400, behavior: 'smooth' });
  };

  const handleMaterialAnalysis = async () => {
    if (!material.trim()) {
      alert("분석할 자료나 이슈 데이터를 입력해주세요!");
      return;
    }
    setLoading(true);
    setErrorMsg("");
    setStatusText("데이터 정밀 분석 및 대본 추출 중... 🤖");

    try {
      const result = await generateNewsScript(material, isMockMode);
      setArticleData({
        title: result.summary.split('.')[0] || "AI 분석 속보",
        content: result.script,
        category: category,
        factCheck: "AI 데이터 분석 완료",
        sources: ["입력 데이터 원본", "AI 분석 센터"],
        summary: result.summary
