      setStatusText("관련 보도 사진 생성 중... 📸");
      const visualPrompt = result.summary.split('.')[0].replace(/[\[\]]/g, '');
      const imgUrl = await generateImage(visualPrompt, isMockMode);
      setImageResult(imgUrl);
