            <h4 className="fw-bold m-0">실시간 AI 취재 아이템 브리핑</h4>
            <span className="badge bg-red-500/10 text-red-500 border border-red-500/30 px-2 py-0.5 animate-pulse text-[10px] font-black">LIVE</span>
          </div>
          <div className="flex items-center gap-3">
            {suggestionError && (
               <span className="text-amber-500 text-xs flex items-center gap-1 font-bold">
                 <AlertCircle size={14}/> {suggestionError}
