import { GoogleGenAI, Type, Modality } from "@google/genai";

// 환경 변수 접근을 위한 안전한 헬퍼
const getApiKey = () => {
  try {
    const env = (typeof process !== 'undefined' && process.env) ? process.env : (window as any).process?.env;
    return env?.API_KEY || '';
  } catch (e) {
    return '';
  }
};

// JSON 추출을 위한 견고한 헬퍼
const extractJson = (text: string) => {
  try {
    const firstBracket = text.indexOf('[');
    const lastBracket = text.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket !== -1) {
      return text.substring(firstBracket, lastBracket + 1);
    }
    const firstObj = text.indexOf('{');
    const lastObj = text.lastIndexOf('}');
    if (firstObj !== -1 && lastObj !== -1) {
      return text.substring(firstObj, lastObj + 1);
    }
    return text;
  } catch (e) {
    console.error("JSON extraction failed", e);
    return text;
  }
};

const getAI = () => new GoogleGenAI({ apiKey: getApiKey() });

const handleAIError = (error: any) => {
  console.error("Gemini API Error Detail:", error);
  const errorStr = JSON.stringify(error);
  if (errorStr.includes('429') || errorStr.includes('RESOURCE_EXHAUSTED')) {
    throw new Error("QUOTA_EXCEEDED");
  }
  throw error;
};

// 실시간 취재 아이템 추천
export const generateCoverageSuggestions = async (isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return [
