      { id: "2", title: "제로 웨이스트 팝업 열풍", category: "Social", angle: "MZ세대 소비 트렌드", urgency: "Medium" }
    ];
  }
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
