// 팩트 기반 기사 생성 (구글 검색 활용)
export const generateFactBasedArticle = async (topic: string, category: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 1500));
    return {
      title: `[데모 속보] ${topic}`,
      category,
      content: "<p>이것은 <b>데모 모드</b>의 팩트체크 기사입니다. 실시간 검색을 사용하려면 Live 모드를 활성화하세요.</p>",
      factCheck: "데모 데이터 기반 확인됨",
      sources: ["내부 아카이브", "연합뉴스"],
      searchSources: [{ title: "네이버 뉴스", uri: "https://news.naver.com" }]
    };
  }

  try {
    const ai = getAI();
    // 팩트체크를 위해 gemini-3-pro-preview 모델 사용 (검색 도구 지원)
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `주제: "${topic}" (${category})
      당신은 동아일보의 팩트체크 전문 기자입니다. 
      구글 검색을 사용하여 위 주제에 대한 최신 팩트를 수집하고, 논리적이고 신뢰할 수 있는 기사를 작성하세요.

      본문에는 HTML 태그(<p>, <b>, <h3>)를 사용하고, 반드시 JSON 형식으로 응답하세요.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            category: { type: Type.STRING },
            content: { type: Type.STRING },
            factCheck: { type: Type.STRING },
            sources: { type: Type.ARRAY, items: { type: Type.STRING } },
            imageKeyword: { type: Type.STRING }
          },
          required: ["title", "category", "content", "factCheck", "sources", "imageKeyword"],
        },
      },
    });

    const parsed = JSON.parse(extractJson(response.text));

    // 검색 출처(Grounding Metadata) 추출
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const searchSources = groundingChunks
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        uri: chunk.web.uri,
        title: chunk.web.title
      }));

    return { ...parsed, searchSources: searchSources.length > 0 ? searchSources : [] };
  } catch (error) {
    return handleAIError(error);
  }
};

