export const generateFactBasedArticle = async (topic: string, category: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 1500));
    return {
      title: `[AI 팩트체크] ${topic}의 실상과 전망`,
      category,
      summary: "1. 해당 이슈는 최근 글로벌 시장에서 가장 뜨거운 감자로 부상했습니다.\n2. 데이터 분석 결과 전년 대비 15% 이상의 변동폭을 보이고 있습니다.\n3. 정부의 정책적 대응이 향후 시장의 핵심 변수가 될 전망입니다.",
      content: "<h3>현황 분석</h3><p>현재 <b>주요 지표</b>들은 급격한 변화를 예고하고 있습니다. </p><h3>상세 팩트체크</h3><p>교차 검증 결과, 업계의 우려와는 달리 실제 데이터는 안정적인 것으로 파악되었습니다.</p><h3>향후 전망</h3><p>전문가들은 이번 이슈가 장기적으로는 산업의 <b>체질 개선</b> 기회가 될 것으로 보고 있습니다.</p>",
      factCheck: "상위 3개 핵심 채널 교차 검증 완료",
      sources: ["내부 데이터베이스", "공식 통계"],
      imageKeyword: topic
    };
  }

  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `주제: "${topic}" (${category})
      당신은 동아일보의 수석 데이터 기자입니다. 구글 검색을 통해 사실을 수집하고, 독자가 단 30초 만에 내용을 파악할 수 있도록 '정리된' 리포트를 작성하세요.

      구성 필수 요소:
      1. **summary**: 전체 기사 내용을 아우르는 핵심 요약 3줄.
      2. **content**: HTML 태그(h3, b, p)를 사용한 구조화된 본문. (현황-분석-전망 구조)
      3. **factCheck**: 데이터 검증 경로를 1문장으로 기술.
      4. **imageKeyword**: 보도 사진 생성을 위한 구체적인 영어 키워드.

      반드시 JSON 형식으로 응답하세요.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            category: { type: Type.STRING },
            summary: { type: Type.STRING },
            content: { type: Type.STRING },
            factCheck: { type: Type.STRING },
            sources: { type: Type.ARRAY, items: { type: Type.STRING } },
            imageKeyword: { type: Type.STRING }
          },
          required: ["title", "category", "summary", "content", "factCheck", "sources", "imageKeyword"],
        },
      },
    });

    const parsed = JSON.parse(extractJson(response.text));
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const searchSources = groundingChunks
      .filter((chunk: any) => chunk.web)
      .map((chunk: any) => ({
        uri: chunk.web.uri,
        title: chunk.web.title
      }))
      .slice(0, 3); // 3개로 엄격 제한

    return { ...parsed, searchSources: searchSources.length > 0 ? searchSources : [] };
  } catch (error) {
    return handleAIError(error);
  }
};

export const generateImage = async (prompt: string, isMock: boolean = false) => {
  if (isMock) return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: `Professional photo for a news article about: ${prompt}. High quality, photorealistic.` }] },
      config: { imageConfig: { aspectRatio: "16:9" } }
    });
    for (const part of response.candidates[0].content.parts) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  } catch (error: any) {
    return handleAIError(error);
  }
};

