import { GoogleGenAI, Type, Modality } from "@google/genai";

const getApiKey = () => {
  try {
    const env = (typeof process !== 'undefined' && process.env) ? process.env : (window as any).process?.env;
    return env?.API_KEY || '';
  } catch (e) {
    return '';
  }
};

/**
 * JSON 추출 유틸리티: 텍스트 내에서 유효한 JSON 객체 또는 배열 블록을 찾아 추출합니다.
 */
const extractJson = (text: string) => {
  try {
    // 가장 바깥쪽의 { } 또는 [ ]를 찾습니다.
    const firstBrace = text.indexOf('{');
    const firstBracket = text.indexOf('[');

    let startIdx = -1;
    let endIdx = -1;
    let type: 'object' | 'array' | null = null;

    if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
      startIdx = firstBrace;
      endIdx = text.lastIndexOf('}');
      type = 'object';
    } else if (firstBracket !== -1) {
      startIdx = firstBracket;
      endIdx = text.lastIndexOf(']');
      type = 'array';
    }

    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      const candidate = text.substring(startIdx, endIdx + 1);
      // 기본적인 검증: 대괄호/중괄호 밸런싱은 생략하고 JSON.parse 시도
      return candidate;
    }
    return text;
  } catch (e) {
    return text;
  }
};

const getAI = () => new GoogleGenAI({ apiKey: getApiKey() });

const handleAIError = (error: any) => {
  console.error("Gemini API Error Detail:", error);
  const errorStr = JSON.stringify(error);
  if (errorStr.includes('429') || errorStr.includes('RESOURCE_EXHAUSTED')) {
    throw new Error("QUOTA_EXCEEDED");
  }
  throw error;
};

