export const decodeAudio = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
  const dataInt16 = new Int16Array(bytes.buffer);
  const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);
  for (let i = 0; i < dataInt16.length; i++) channelData[i] = dataInt16[i] / 32768.0;
  return buffer;
};

import { GoogleGenAI, Type, Modality } from "@google/genai";

/**
 * JSON 추출 유틸리티: 텍스트 내에서 유효한 JSON 객체{} 또는 배열[] 블록을 찾아 추출합니다.
 * 마크다운 코드 블록(```json ... ```)이 포함된 경우도 처리합니다.
 */
const extractJson = (text: string) => {
  try {
    // 1. 마크다운 코드 블록 제거 시도
    let cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();

    // 2. 가장 바깥쪽의 { } 또는 [ ] 위치 찾기
    const firstBrace = cleanText.indexOf('{');
    const firstBracket = cleanText.indexOf('[');

    let startIdx = -1;
    let endIdx = -1;

    if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
      startIdx = firstBrace;
      endIdx = cleanText.lastIndexOf('}');
    } else if (firstBracket !== -1) {
      startIdx = firstBracket;
      endIdx = cleanText.lastIndexOf(']');
    }

    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      return cleanText.substring(startIdx, endIdx + 1);
    }
    return cleanText;
  } catch (e) {
    console.error("JSON extraction error:", e);
    return text;
  }
};

