                <div className="glass-card p-5 rounded-4 h-100 border-0 shadow-2xl overflow-hidden" style={{ background: '#0f172a' }}>
                    <div className="d-flex align-items-center justify-content-between mb-5 pb-4 border-bottom border-slate-800">
                        <div className="d-flex align-items-center gap-3">
                          <div className="bg-blue-600 p-2 rounded-lg"><FileText className="text-white" size={24}/></div>
