                    <div className="glass-card p-4 rounded-4 border-slate-800 shadow-lg overflow-hidden" style={{ background: '#1e293b' }}>
                        <div className="d-flex align-items-center mb-3">
                            <Camera className="text-warning me-2" size={18}/>
