  const [errorMsg, setErrorMsg] = useState("");
  const [isZoomed, setIsZoomed] = useState(false); // 이미지 확대 상태

  // 실시간 저장
  useEffect(() => localStorage.setItem('donga_writer_topic', topic), [topic]);
  useEffect(() => localStorage.setItem('donga_writer_category', category), [category]);
  useEffect(() => {
    if (articleData) localStorage.setItem('donga_writer_article', JSON.stringify(articleData));
  }, [articleData]);
  useEffect(() => {
    if (imageResult) localStorage.setItem('donga_writer_image', imageResult);
  }, [imageResult]);

  const fetchSuggestions = useCallback(async () => {
    setLoadingSuggestions(true);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data || []);
    } catch (e: any) {
      console.error(e);
    } finally {
      setLoadingSuggestions(false);
    }
  }, [isMockMode]);

  useEffect(() => {
    fetchSuggestions();
  }, [fetchSuggestions]);

  const handleReset = () => {
    if (window.confirm("작성 중인 내용을 초기화하고 새 기사를 쓰시겠습니까?")) {
      setTopic("");
      setArticleData(null);
      setImageResult(null);
      localStorage.removeItem('donga_writer_article');
      localStorage.removeItem('donga_writer_image');
      localStorage.removeItem('donga_writer_topic');
    }
  };

  const handleQuickStart = (item: Suggestion) => {
    setTopic(item.title);
    const cat = item.category.toLowerCase();
    if (cat.includes('it') || cat.includes('tech')) setCategory('tech');
    else if (cat.includes('econ')) setCategory('economy');
    else if (cat.includes('polit')) setCategory('politics');
    else setCategory('social');
    window.scrollTo({ top: 450, behavior: 'smooth' });
  };

  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }
    setLoading(true);
    setErrorMsg("");

    try {
      setStatusText("실시간 관련 속보 및 공공 데이터 검색 중... 🔍");
      await new Promise(r => setTimeout(r, 800));
      setStatusText("사실 관계 정밀 분석 및 팩트체크 교차 검증 중... ✅");

      const result = await generateFactBasedArticle(topic, category, isMockMode);

      const newArticleData = {
        title: result.title || topic,
        summary: result.summary || "",
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "AI 정밀 검증 완료",
        sources: result.sources || [],
        searchSources: result.searchSources
      };

      setArticleData(newArticleData);

      setStatusText("보도용 시각화 이미지 생성 중... 📸");
      const imgUrl = await generateImage(result.imageKeyword || topic, isMockMode);
      setImageResult(imgUrl);
    } catch (e: any) {
      console.error(e);
      setErrorMsg("데이터 수집 중 문제가 발생했습니다. 잠시 후 다시 시도해 주세요.");
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  const handleSave = () => {
    if (!articleData) return;
    const newArticle = {
      ...articleData,
      id: Date.now(),
      image: imageResult,
      date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
    };
    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    localStorage.setItem('my_articles', JSON.stringify([newArticle, ...saved]));
    alert("✅ 팩트 기반 브리핑 기사가 정상적으로 발행되었습니다!");
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      {/* 이미지 확대 모달 */}
      {isZoomed && imageResult && (
        <div 
          className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-fade-in cursor-zoom-out"
          onClick={() => setIsZoomed(false)}
        >
          <button className="absolute top-8 right-8 text-white/50 hover:text-white transition-colors">
            <X size={40} />
          </button>
          <img 
            src={imageResult} 
            alt="Expanded News" 
            className="max-w-[90vw] max-h-[85vh] object-contain rounded-2xl shadow-[0_0_100px_rgba(37,99,235,0.2)] animate-scale-up"
          />
          <div className="absolute bottom-10 left-1/2 -translate-x-1/2 text-white/60 font-bold tracking-widest text-xs uppercase">
            Click anywhere to close
          </div>
        </div>
      )}

      {/* 실시간 취재 아이템 브리핑 섹션 */}
      <div className="mb-5">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <div className="d-flex align-items-center gap-3">
            <div className="bg-blue-600/30 p-2 rounded-xl border border-blue-500/30">
              <RefreshCw className={`text-blue-400 ${loadingSuggestions ? 'animate-spin' : ''}`} size={20} />
            </div>
            <div>
              <h4 className="fw-black m-0 tracking-tighter flex items-center gap-2">
                실시간 AI 편집국 브리핑
                <span className="badge bg-red-600 px-2 py-0.5 animate-pulse text-[10px] font-black tracking-tighter rounded">LIVE</span>
              </h4>
              <p className="text-[11px] text-slate-500 m-0">현재 온라인 트렌드와 뉴스 소스를 바탕으로 한 취재 추천입니다.</p>
            </div>
          </div>
          <button onClick={handleReset} className="btn btn-outline-slate-700 btn-sm text-[10px] fw-bold d-flex align-items-center gap-2 px-3 py-2 rounded-xl">
            <Trash2 size={14} /> 새 기사 작성 (초기화)
          </button>
        </div>

        <div className="row g-3">
          {loadingSuggestions ? (
            Array.from({ length: 4 }).map((_, i) => (
              <div key={i} className="col-md-3">
                <div className="glass-card p-4 rounded-2xl border-slate-800 animate-pulse h-[140px]"></div>
              </div>
            ))
          ) : suggestions.map((item) => (
            <div key={item.id} className="col-md-3">
              <div 
                className="glass-card p-4 rounded-2xl border-slate-800 h-100 hover:border-blue-500/50 hover:bg-slate-800/60 transition-all cursor-pointer group flex flex-col justify-between shadow-xl"
                onClick={() => handleQuickStart(item)}
              >
                <div>
                  <div className="d-flex justify-content-between mb-3">
                    <span className="badge bg-red-600/20 text-red-500 border border-red-500/30 text-[9px] px-2 py-1 font-black uppercase">{item.urgency}</span>
                    <span className="text-[10px] text-blue-400 font-black uppercase tracking-widest">{item.category}</span>
                  </div>
                  <h6 className="text-white fw-bold text-sm mb-2 group-hover:text-blue-400 leading-snug line-clamp-2">{item.title}</h6>
                </div>
                <div className="pt-3 border-t border-slate-800/50 mt-3 flex justify-between items-center">
                  <span className="text-[10px] text-slate-500 italic">"{item.angle}"</span>
                  <ArrowRight size={14} className="text-blue-500 group-hover:translate-x-1 transition-transform" />
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* 기사 작성 입력 필드 */}
      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl relative overflow-hidden" style={{ background: 'rgba(15, 23, 42, 0.95)' }}>
        <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
          <Cpu size={120} />
        </div>

        <h2 className="fw-black mb-4 tracking-tighter d-flex align-items-center gap-3 text-white">
          <div className="bg-primary/20 p-2 rounded-xl"><Sparkles className="text-primary" size={24} /></div>
          AI 팩트체크 기사 정리
        </h2>

        <div className="row g-3">
          <div className="col-md-2">
            <label className="text-slate-500 text-[10px] font-black mb-2 block uppercase tracking-widest">분야</label>
            <select className="form-select !bg-slate-950 border-slate-800 rounded-xl py-3 text-white" value={category} onChange={(e) => setCategory(e.target.value)}>
              <option value="social">사회</option>
              <option value="politics">정치</option>
              <option value="economy">경제</option>
              <option value="tech">IT/과학</option>
            </select>
          </div>
          <div className="col-md-8">
            <label className="text-slate-500 text-[10px] font-black mb-2 block uppercase tracking-widest">취재 주제</label>
            <input 
              className="form-control fs-5 !bg-slate-950 border-slate-800 rounded-xl py-3 px-4 text-white placeholder:text-slate-700" 
              placeholder="취재하고 싶은 핵심 주제를 입력하세요 (예: 최근 한국 경제 금리 영향)" 
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()}
            />
          </div>
          <div className="col-md-2 pt-4">
            <button className="btn btn-primary w-100 py-3 rounded-xl fw-black shadow-lg shadow-blue-900/40 hover:scale-[1.02] transition-all d-flex align-items-center justify-content-center gap-2" onClick={handleFullCreation} disabled={loading}>
              {loading ? <Loader2 className="animate-spin" size={20}/> : <Cpu size={18}/>}
              기사 생성
            </button>
          </div>
        </div>

        {(loading || errorMsg) && (
            <div className={`mt-5 p-4 rounded-2xl border font-bold text-center animate-fade-in ${errorMsg ? 'bg-red-500/10 border-red-500/30 text-red-400' : 'bg-blue-500/10 border-blue-500/30 text-blue-300'}`}>
                {errorMsg ? <AlertCircle size={20} className="inline me-2"/> : <div className="spinner-border spinner-border-sm me-3"></div>}
                {errorMsg || statusText}
            </div>
        )}
      </div>

      {/* 기사 출력 레이아웃 */}
      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            {/* 좌측: 원천 소스 (Sources) */}
            <div className="col-lg-3">
              <div className="glass-card p-4 rounded-4 border-slate-800 h-100 shadow-xl" style={{ background: '#0f172a' }}>
                <h6 className="text-blue-400 fw-bold mb-4 flex items-center gap-2 text-sm uppercase tracking-widest">
                  <Link size={16} /> 실시간 원천 소스 (상위 3개)
                </h6>
                <div className="d-flex flex-column gap-3">
                  {articleData.searchSources && articleData.searchSources.length > 0 ? (
                    articleData.searchSources.map((source, i) => (
                      <a 
                        key={i} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="glass-card p-3 rounded-xl border-slate-800 text-slate-400 text-xs hover:text-blue-400 no-underline transition-all flex flex-col gap-2 group hover:bg-slate-800/50"
                      >
                        <div className="text-white font-bold line-clamp-2 group-hover:text-blue-400">{source.title}</div>
                        <div className="text-[9px] opacity-40 truncate flex items-center gap-1">
                          <Link size={10} /> {source.uri}
                        </div>
                      </a>
                    ))
                  ) : (
                    <p className="text-slate-600 text-xs italic">수집된 출처가 없습니다.</p>
                  )}
                </div>

                <div className="mt-5 pt-4 border-t border-slate-800">
                  <h6 className="text-slate-400 fw-bold mb-3 text-[11px] uppercase tracking-widest flex items-center gap-2">
                    <ListChecks size={14} className="text-green-500" /> 데이터 검증 로그
                  </h6>
                  <div className="bg-slate-950 p-3 rounded-xl border border-slate-800">
                    <p className="text-[10px] text-green-500/80 m-0 leading-relaxed font-mono">
                      &gt; SEARCH: {articleData.sources[0] || 'Web'}<br/>
                      &gt; VERIFIED: {articleData.factCheck}<br/>
                      &gt; STATUS: 기사화 적합 판정
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* 중앙: 기사 본문 (Main Content) */}
            <div className="col-lg-6">
                <div className="glass-card p-5 rounded-4 h-100 border-0 shadow-2xl overflow-hidden" style={{ background: '#0f172a' }}>
                    <div className="d-flex align-items-center justify-content-between mb-5 pb-4 border-bottom border-slate-800">
                        <div className="d-flex align-items-center gap-3">
                          <div className="bg-blue-600 p-2 rounded-lg"><FileText className="text-white" size={24}/></div>
                          <h4 className="fw-black m-0 text-white tracking-tighter">AI 브리핑 리포트</h4>
                        </div>
                        <span className="badge bg-blue-600/10 text-blue-500 border border-blue-600/30 px-3 py-2 rounded-pill text-[10px] font-bold">
                          {articleData.category.toUpperCase()}
                        </span>
                    </div>

                    <div className="mb-5">
                      <h1 className="fw-black text-white display-5 leading-tight tracking-tighter mb-4">{articleData.title}</h1>
                    </div>

                    <div className="mb-5">
                      <div 
                          className="text-slate-200 article-body" 
                          style={{ 
                            fontFamily: "'Pretendard', sans-serif", 
                            fontSize: '1.2rem', 
                            lineHeight: '2.0',
                          }}
                          dangerouslySetInnerHTML={{ __html: articleData.content }}
                      />
                    </div>
                </div>
            </div>

            {/* 우측: 기사 요약 및 미디어 (Summary & Actions) */}
            <div className="col-lg-3">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-4 border-0 shadow-xl" style={{ background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)' }}>
                        <h6 className="text-blue-400 font-black mb-3 flex items-center gap-2 text-xs uppercase tracking-widest">
                          <Quote size={14} /> AI 핵심 인사이트 정리
                        </h6>
                        <div className="text-slate-300 leading-relaxed text-sm font-medium whitespace-pre-wrap bg-slate-950/40 p-3 rounded-xl border border-slate-800">
                          {articleData.summary}
                        </div>
                    </div>

                    <div className="glass-card p-4 rounded-4 border-slate-800 shadow-lg overflow-hidden group/img" style={{ background: '#1e293b' }}>
                        <div className="d-flex align-items-center mb-3">
                            <Camera className="text-warning me-2" size={18}/>
                            <h6 className="fw-black m-0 text-white text-xs uppercase tracking-tight">현장 보도 이미지</h6>
                        </div>
                        <div 
                          className="position-relative bg-slate-950 rounded-xl overflow-hidden mb-3 border border-slate-800 cursor-zoom-in" 
                          style={{ aspectRatio: '16/9' }}
                          onClick={() => setIsZoomed(true)}
                        >
                            {imageResult ? (
                                <>
                                  <img src={imageResult} alt="News" className="w-full h-full object-cover group-hover/img:scale-105 transition-transform duration-500"/>
                                  <div className="absolute inset-0 bg-black/0 group-hover/img:bg-black/20 transition-colors flex items-center justify-center opacity-0 group-hover/img:opacity-100">
                                    <div className="bg-white/10 backdrop-blur-md p-2 rounded-full border border-white/20">
                                      <Maximize2 size={20} className="text-white" />
                                    </div>
                                  </div>
                                </>
                            ) : (
                                <div className="text-center text-slate-700 h-100 d-flex flex-column items-center justify-center">
                                    <Loader2 className="animate-spin mb-2" size={24}/>
                                    <p className="text-[9px] font-bold opacity-30">이미지 생성 중</p>
                                </div>
                            )}
                        </div>
                    </div>

                    <div className="mt-auto">
                        <button 
                            className="btn btn-primary w-100 py-4 fw-black fs-5 shadow-2xl d-flex align-items-center justify-content-center gap-3 border-0 transition-all active:scale-[0.98] group" 
                            style={{ background: 'linear-gradient(135deg, #2563eb 0%, #1d4ed8 100%)' }}
                            onClick={handleSave} 
                        >
                            <Save size={24} className="group-hover:scale-110 transition-transform" /> 최종 기사 발행
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
      <style>{`
        .article-body h3 { font-size: 1.5rem; font-weight: 900; color: white; margin-top: 2.5rem; margin-bottom: 1rem; color: #60a5fa; border-left: 5px solid #2563eb; padding-left: 1rem; }
        .article-body p { margin-bottom: 1.5rem; color: #cbd5e1; }
        .article-body b { color: #facc15; font-weight: 800; }
        .line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
        @keyframes scale-up {
          from { opacity: 0; transform: scale(0.95); }
          to { opacity: 1; transform: scale(1); }
        }
        .animate-scale-up {
          animation: scale-up 0.3s cubic-bezier(0.16, 1, 0.3, 1);
        }
      `}</style>
    </div>
  );
};

export default AIWriter;

import { useState, useEffect } from 'react';
import { Trash2, Calendar, X, AlertCircle, FileText } from 'lucide-react';

const Dashboard = () => {
  const [articles, setArticles] = useState<any[]>([]);
  const [selectedArticle, setSelectedArticle] = useState<any | null>(null);

  useEffect(() => {
    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    setArticles(saved);
  }, []);

  const deleteArticle = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 영구적으로 삭제하시겠습니까? 삭제된 기사는 복구할 수 없습니다.")) return;

    const updated = articles.filter(item => item.id !== id);
    localStorage.setItem('my_articles', JSON.stringify(updated));
    setArticles(updated);

    // 만약 현재 열려있는 기사라면 모달 닫기
    if (selectedArticle && selectedArticle.id === id) {
      setSelectedArticle(null);
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="d-flex justify-content-between align-items-center mb-5">
        <div>
          <h2 className="fw-black mb-1 tracking-tighter">📊 발행 기사 관리</h2>
          <p className="text-slate-500 text-sm m-0">작성 및 발행된 모든 AI 기사 리포트를 관리합니다.</p>
        </div>
        <div className="bg-slate-900/50 px-4 py-2 rounded-2xl border border-slate-800">
          <span className="text-slate-400 text-xs font-bold uppercase tracking-widest me-2">Total Articles</span>
          <span className="text-blue-400 fw-black">{articles.length}</span>
        </div>
      </div>

      <div className="row g-4">
        {articles.length === 0 ? (
          <div className="col-12">
            <div className="glass-card p-10 rounded-3xl text-center border-dashed border-slate-800 flex flex-col items-center justify-center min-h-[400px]">
               <div className="bg-slate-900 p-4 rounded-full mb-4">
                <FileText size={48} className="text-slate-700" />
               </div>
               <h3 className="text-slate-400 fw-black">발행된 기사가 없습니다</h3>
               <p className="text-slate-600 max-w-sm">기자실에서 AI와 함께 첫 번째 특종 기사를 작성하고 발행해 보세요!</p>
            </div>
          </div>
        ) : (
          articles.map(article => (
            <div key={article.id} className="col-md-6 col-lg-4">
              <div 
                className="card h-100 border-0 shadow-2xl glass-card overflow-hidden group transition-all duration-300 hover:translate-y-[-8px]" 
                style={{ cursor: 'pointer', background: '#0f172a', borderRadius: '24px' }}
                onClick={() => setSelectedArticle(article)}
              >
                <div style={{ height: '220px', overflow: 'hidden', background: '#020617' }} className="position-relative">
                   {article.image ? (
                       <img src={article.image} alt="news" className="w-100 h-100 object-cover group-hover:scale-110 transition-transform duration-700" />
                   ) : (
                       <div className="w-100 h-100 d-flex align-items-center justify-content-center text-slate-800">
                        <FileText size={40} />
                       </div>
                   )}
                   <div className="position-absolute inset-0 bg-gradient-to-t from-[#0f172a] via-transparent to-transparent opacity-80"></div>
                   <span className="position-absolute top-4 right-4 badge bg-blue-600 px-3 py-2 rounded-lg shadow-xl text-[10px] font-black uppercase tracking-wider">{article.category}</span>
                </div>

                <div className="card-body p-4">
                  <div className="d-flex align-items-center gap-2 text-slate-500 text-[10px] font-bold mb-3 uppercase tracking-widest">
                    <Calendar size={12}/> {article.date}
                  </div>
                  <h5 className="text-white fw-black mb-3 line-clamp-2 leading-tight group-hover:text-blue-400 transition-colors">{article.title}</h5>
                  <p className="card-text text-slate-400 text-sm line-clamp-3 leading-relaxed opacity-70">
                    {article.content.replace(/<[^>]*>/g, '')}
                  </p>
                </div>

                <div className="card-footer bg-slate-900/50 border-top border-slate-800/50 d-flex justify-content-between align-items-center p-3 px-4">
                    <span className="text-[10px] text-green-500 font-bold bg-green-500/10 px-2 py-1 rounded border border-green-500/20">VERIFIED</span>
                    <button 
                      className="btn btn-sm text-red-500 hover:bg-red-500/10 p-2 rounded-lg transition-all border-0 d-flex align-items-center gap-1 font-bold text-[11px]" 
                      onClick={(e) => deleteArticle(article.id, e)}
                    >
                        <Trash2 size={14} /> 삭제
                    </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>

      {selectedArticle && (
        <div 
          className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/95 backdrop-blur-xl animate-fade-in" 
          onClick={() => setSelectedArticle(null)}
        >
            <div 
                className="rounded-3xl shadow-2xl overflow-hidden border border-slate-800 flex flex-col w-full max-w-4xl max-h-[90vh]" 
                style={{ background: '#0f172a' }}
                onClick={(e) => e.stopPropagation()}
            >
                {/* 헤더 */}
                <div className="p-4 px-6 border-bottom border-slate-800 d-flex justify-content-between align-items-center bg-slate-900/80">
                    <div className="d-flex align-items-center gap-3">
                      <div className="bg-blue-600 p-1.5 rounded-lg"><FileText size={18} className="text-white"/></div>
                      <h6 className="m-0 fw-black text-white text-sm tracking-tight uppercase">Article Archive</h6>
