                <div className="p-4 px-6 border-bottom border-slate-800 d-flex justify-content-between align-items-center bg-slate-900/80">
                    <h6 className="m-0 fw-black text-white text-sm tracking-tight uppercase flex items-center gap-2"><FileText size={16}/> Article Viewer</h6>
                    <button className="btn-close btn-close-white opacity-50" onClick={() => setSelectedItem(null)}></button>
