    return {
      title: `[AI 팩트체크] ${topic}의 실상과 전망`,
      category,
      summary: "1. 이슈 요약 첫 번째 줄입니다.\n2. 데이터 분석 결과입니다.\n3. 향후 전망 요약입니다.",
      content: "<h3>현황 분석</h3><p>현재 <b>주요 지표</b>들은 급격한 변화를 예고하고 있습니다.</p><h3>상세 분석</h3><p>교차 검증 결과 사실로 확인되었습니다.</p>",
      factCheck: "상위 3개 채널 교차 검증 완료",
      sources: ["공식 통계"],
      imageKeyword: topic
    };
  }

  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: `주제: "${topic}" (${category})
        당신은 동아일보의 데이터 저널리즘 팀장입니다. 구글 검색을 활용하여 사실을 수집하고 리포트를 작성하세요.
        반드시 다음 형식을 엄격히 준수하여 JSON으로만 답변하세요. 인사말이나 다른 텍스트는 일절 금지합니다.
        {
          "title": "기사 제목",
          "category": "분야",
          "summary": "핵심 요약 3줄 (문자열)",
          "content": "HTML 태그(h3, b, p)를 포함한 본문",
          "factCheck": "검증 경로 1문장",
          "sources": ["출처1", "출처2"],
          "imageKeyword": "이미지 생성을 위한 구체적인 영어 키워드"
        }`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              category: { type: Type.STRING },
              summary: { type: Type.STRING },
              content: { type: Type.STRING },
              factCheck: { type: Type.STRING },
              sources: { type: Type.ARRAY, items: { type: Type.STRING } },
              imageKeyword: { type: Type.STRING }
            },
            required: ["title", "category", "summary", "content", "factCheck", "sources", "imageKeyword"]
          }
        }
      });

      const parsed = JSON.parse(extractJson(response.text));
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const searchSources = groundingChunks
        .filter((chunk: any) => chunk.web)
        .map((chunk: any) => ({
          uri: chunk.web.uri,
          title: chunk.web.title
        }))
        .slice(0, 3);

      return { ...parsed, searchSources: searchSources.length > 0 ? searchSources : [] };
    } catch (error) {
      return handleAIError(error);
    }
  });
};

