import React, { useState, useRef, useEffect } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Zap, ShieldAlert, Key } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const audioBufferRef = useRef<AudioBuffer | null>(null); 
  const bgmRef = useRef<HTMLAudioElement | null>(null);

  const stopPlayback = () => {
    if (sourceNodeRef.current) {
      try { sourceNodeRef.current.stop(); } catch(e) {}
      sourceNodeRef.current = null;
    }
    if (bgmRef.current) {
      bgmRef.current.pause();
    }
    setIsPlaying(false);
  };

  useEffect(() => {
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }

    return () => {
      stopPlayback();
    };
  }, []);

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      window.location.reload();
    }
  };

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const BGM_URL = "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-8.mp3";

  const startPlayback = async () => {
    if (!audioBufferRef.current || !audioContextRef.current) return;

    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    if (sourceNodeRef.current) {
      try { sourceNodeRef.current.stop(); } catch(e) {}
    }

    const source = audioContextRef.current.createBufferSource();
    source.buffer = audioBufferRef.current;
    source.connect(audioContextRef.current.destination);
    source.onended = () => setIsPlaying(false);

    sourceNodeRef.current = source;

    if (bgmRef.current) {
      bgmRef.current.volume = 0.15;
      bgmRef.current.play();
    }

    source.start();
    setIsPlaying(true);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    setApiErrorType(null);
    stopPlayback();
    audioBufferRef.current = null;

    try {
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      const audioData = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      const buffer = await decodeAudio(audioData, audioContextRef.current);
      audioBufferRef.current = buffer; 

      startPlayback();
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      else if (error.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
      else setApiErrorType("UNKNOWN");
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = () => {
    if (!lyrics) return;
    const newItem: SavedAudioNews = {
      id: Date.now(),
      title: inputText.split('\n')[0].slice(0, 20) || "제목 없음",
      lyrics: lyrics,
      timestamp: new Date().toLocaleString('ko-KR', { hour12: false }).slice(0, -3)
    };
    const updated = [newItem, ...savedItems];
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
    alert("보관함에 저장되었습니다.");
  };

  const loadSavedItem = async (item: SavedAudioNews) => {
    if (lyrics === item.lyrics && audioBufferRef.current) {
      startPlayback();
      return;
    }

    if (isMockMode) {
        setLyrics(item.lyrics);
        return;
    }

    setIsLoading(true);
    setApiErrorType(null);
    setLyrics(item.lyrics);
    stopPlayback();
    audioBufferRef.current = null;
    try {
      const audioData = await speakTrot(item.lyrics, isMockMode);
      if (!audioData) throw new Error("Audio generation failed");
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const buffer = await decodeAudio(audioData, audioContextRef.current);
      audioBufferRef.current = buffer;
      startPlayback();
    } catch (error: any) {
      if (error.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      else if (error.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
      else setApiErrorType("UNKNOWN");
    } finally {
      setIsLoading(false);
    }
  };

  const deleteItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = savedItems.filter(item => item.id !== id);
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      if (audioBufferRef.current) {
        await startPlayback();
      } else if (lyrics) {
        if (isMockMode) {
            alert("Mock Mode에서는 가사만 생성됩니다.");
        } else {
            loadSavedItem({ id: 0, title: '', lyrics: lyrics, timestamp: '' });
        }
      }
    }
  };

  return (
    <div className="container-fluid py-4 text-white">
      <audio ref={bgmRef} src={BGM_URL} loop hidden />

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4 text-white text-start">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-400" />}
            </div>
            <div>
              <p className="font-bold m-0 text-lg">
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : '서비스 이용 제한'}
              </p>
              <p className="text-sm m-0 opacity-80">
                {apiErrorType === 'PERMISSION' 
                  ? '현재 사용 중인 API 키가 Referrer 제한으로 인해 차단되었습니다. 개인 API 키를 선택하세요.' 
                  : '할당량 소진 또는 오디오 생성 중 오류가 발생했습니다. 개인 키를 설정하세요.'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2 border-0`}>
              <Key size={16} /> API 키 설정
            </button>
          </div>
        </div>
      )}

      <div className="row g-4">
        <div className="col-lg-3">
          <div className="glass-card h-100 p-3 d-flex flex-column" style={{ minHeight: '75vh', background: '#0f172a' }}>
            <h5 className="text-white fw-bold mb-4 pb-2 border-bottom border-slate-700 d-flex justify-content-between align-items-center">
              <span><i className="bi bi-collection-play-fill me-2 text-warning"></i>보관함</span>
              <span className="badge bg-slate-800 text-slate-300">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1">
              {savedItems.length === 0 ? (
                <div className="text-center py-5">
                  <i className="bi bi-inbox display-4 mb-2 d-block text-slate-700"></i>
                  <p className="small text-slate-500">저장된 뉴스가 없습니다.</p>
                </div>
              ) : (
                <div className="d-grid gap-2">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => loadSavedItem(item)}
                      className={`p-3 rounded transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning bg-slate-800' : 'border-slate-800 bg-slate-900/50 hover:bg-slate-800'}`}
                    >
                      <h6 className="text-white text-truncate mb-1 fw-bold" style={{ fontSize: '0.9rem' }}>{item.title}</h6>
                      <p className="text-slate-400 m-0" style={{ fontSize: '0.7rem' }}>{item.timestamp}</p>
                      <button 
                        onClick={(e) => deleteItem(e, item.id)}
                        className="btn btn-link text-danger p-0 position-absolute top-0 end-0 mt-2 me-2 opacity-0 group-hover:opacity-100 transition-all"
                      >
                        <i className="bi bi-trash"></i>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="col-lg-9">
          <div className="text-center mb-4">
            <h2 className="display-6 fw-bold text-white mb-2">
              <span className="text-gradient-trot">오디오 뉴스룸</span>
            </h2>
            <p className="text-slate-300">기사를 입력하면 신나는 트로트 가사와 AI 음성이 자동 생성됩니다.</p>
            {isMockMode && <span className="badge bg-amber-500 text-black px-4 py-2 rounded-pill fw-bold animate-pulse shadow-lg">Mock Mode 활성화 중</span>}
          </div>

          <div className="row g-4">
            <div className="col-xl-6">
              <div className="glass-card p-4 h-100 d-flex flex-column" style={{ background: '#0f172a' }}>
                <label className="form-label text-white fw-bold mb-3 d-flex align-items-center gap-2">
                  <i className="bi bi-file-earmark-text text-primary"></i> 기사 원문
                </label>
                <textarea
                  className="form-control bg-slate-900 text-white border-slate-700 mb-4 flex-grow-1 p-3"
                  style={{ resize: 'none', minHeight: '350px', fontSize: '1rem', lineHeight: '1.6' }}
                  placeholder="트로트로 변환할 기사 내용을 입력하세요..."
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                ></textarea>
                <div className="d-flex gap-2">
                  <button 
                    className="btn btn-warning flex-grow-1 py-3 fw-bold fs-5 shadow-lg border-0 transition-transform active:scale-95"
                    style={{ background: 'linear-gradient(135deg, #F09819 0%, #EDDE5D 100%)', color: '#000' }}
                    onClick={handleConvert}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <span><span className="spinner-border spinner-border-sm me-2"></span>AI 분석 중...</span>
                    ) : (
                      <span>🎤 트로트 뉴스 생성</span>
                    )}
                  </button>
                  {lyrics && (
                    <button className="btn btn-outline-light px-4 border-slate-700 hover:bg-slate-800" onClick={handleSave} title="보관함에 저장">
                      <i className="bi bi-save"></i>
                    </button>
                  )}
                </div>
              </div>
            </div>

            <div className="col-xl-6">
              <div className="glass-card p-4 h-100 d-flex flex-column align-items-center justify-content-center text-center" style={{ background: '#0f172a' }}>
                {!lyrics ? (
                  <div className="py-5">
                    <i className="bi bi-music-player display-1 d-block mb-3 text-slate-800"></i>
                    <p className="fs-5 text-slate-500">기사를 입력하고 생성 버튼을 누르세요.</p>
                  </div>
                ) : (
                  <div className="w-100 animate-fade-in">
                    <div className="mb-5 position-relative d-inline-block">
                        <div 
                            className={`rounded-circle border-8 border-slate-800 mx-auto d-flex align-items-center justify-content-center shadow-2xl ${isPlaying ? 'spin-slow' : ''}`}
                            style={{ width: '220px', height: '220px', background: 'radial-gradient(circle, #334155 30%, #020617 70%)', transition: 'transform 0.3s ease' }}
                        >
                          <div className="rounded-circle bg-warning" style={{ width: '70px', height: '70px', border: '3px solid #000', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <i className={`bi bi-vinyl-fill text-dark fs-2 ${isPlaying ? 'animate-pulse' : ''}`}></i>
                          </div>
                        </div>
                        <div 
                            className="position-absolute top-50 start-50 translate-middle cursor-pointer"
                            onClick={togglePlay}
                            style={{ zIndex: 10 }}
                        >
                           <i className={`bi ${isPlaying ? 'bi-pause-circle-fill' : 'bi-play-circle-fill'} display-1 text-white opacity-95 hover-scale drop-shadow`}></i>
                        </div>
                    </div>

                    <div className="bg-slate-900/80 rounded-4 p-4 mb-4 text-start border border-slate-700 custom-scrollbar shadow-inner" style={{ maxHeight: '250px', overflowY: 'auto' }}>
                      <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '1.8', fontSize: '1.1rem', letterSpacing: '-0.2px' }}>
                        {lyrics}
                      </pre>
                    </div>

                    <button 
                      className={`btn w-100 py-3 fw-bold fs-5 transition-all shadow-lg ${isPlaying ? 'btn-outline-danger' : 'btn-primary'}`} 
                      onClick={togglePlay}
                      disabled={isLoading}
                    >
                        {isLoading ? (
                          <span><span className="spinner-border spinner-border-sm me-2"></span>음성 현상 중...</span>
                        ) : (
                          isPlaying ? '■ 재생 중지' : '▶ 오디오 재생'
                        )}
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .spin-slow { animation: spin 5s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .text-gradient-trot {
            background: linear-gradient(to right, #F09819, #EDDE5D);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
        .hover-scale:hover { transform: translate(-50%, -50%) scale(1.1) !important; }
        .hover-scale { transition: transform 0.2s; }
      `}</style>
    </div>
  );
};

