};

export default AIWriter;

import React, { useState, useEffect } from 'react';
import { Calendar, Clock, ChevronRight, Share2, MessageCircle, Heart, Newspaper, Trash2, Send } from 'lucide-react';

const LoadingSpinnerIcon = ({ size, className }: { size: number, className: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}>
    <path d="M3 12a9 9 0 0 1 9-9 9.75 9.75 0 0 1 6.74 2.74L21 8" /><path d="M21 3v5h-5" /><path d="M21 12a9 9 0 0 1-9 9 9.75 9.75 0 0 1-6.74-2.74L3 16" /><path d="M3 21v-5h5" />
  </svg>
);

interface Comment {
  id: string;
  user: string;
  text: string;
  date: string;
}

interface Article {
  id: number;
  title: string;
  category: string;
  content: string;
  image: string | null;
  date: string;
  factCheck: string;
  likes?: number;
  comments?: Comment[];
}

const RealtimeNews: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [commentInput, setCommentInput] = useState("");

  const fetchArticles = () => {
    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const initialized = saved.map((a: Article) => ({
        ...a,
        likes: a.likes || 0,
        comments: a.comments || []
      }));
      setArticles(initialized);
    } catch (e) {
      console.error("Failed to load articles from localStorage", e);
    }
  };

  useEffect(() => {
    fetchArticles();
    const interval = setInterval(fetchArticles, 5000);
    return () => clearInterval(interval);
  }, []);

  const deleteArticle = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 뉴스 피드에서 삭제하시겠습니까?")) return;

    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const updated = saved.filter((a: any) => a.id !== id);
      localStorage.setItem('my_articles', JSON.stringify(updated));
      setArticles(updated);
      if (selectedArticle?.id === id) setSelectedArticle(null);
    } catch (e) {
      console.error("Deletion failed", e);
    }
  };

  const updateArticleInStorage = (updatedArticle: Article) => {
    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const newArticles = saved.map((a: any) => a.id === updatedArticle.id ? updatedArticle : a);
      localStorage.setItem('my_articles', JSON.stringify(newArticles));
      setArticles(newArticles.map((a: Article) => ({
          ...a,
          likes: a.likes || 0,
          comments: a.comments || []
      })));
      if (selectedArticle?.id === updatedArticle.id) {
        setSelectedArticle(updatedArticle);
      }
    } catch (e) {
      console.error("Storage update failed", e);
    }
  };

  const handleLike = (e: React.MouseEvent, article: Article) => {
    e.stopPropagation();
    const updated = { ...article, likes: (article.likes || 0) + 1 };
    updateArticleInStorage(updated);
  };

  const handleShare = async (e: React.MouseEvent, article: Article) => {
    e.stopPropagation();

    let shareUrl = "";
    try {
      const url = new URL(window.location.pathname, window.location.origin);
      shareUrl = url.toString();
      if (shareUrl.includes('about:srcdoc') || !shareUrl.startsWith('http')) {
        shareUrl = 'https://www.donga.com'; 
      }
    } catch (err) {
      shareUrl = 'https://www.donga.com';
    }

    const shareData = {
      title: `[동아 AI 뉴스] ${article.title}`,
      text: article.content.replace(/<[^>]*>/g, '').substring(0, 100) + "...",
      url: shareUrl,
    };

    const copyToClipboard = async () => {
      try {
        await navigator.clipboard.writeText(`${shareData.title}\n${shareData.url}`);
        alert("기사 링크가 클립보드에 복사되었습니다!");
      } catch (err) {
        alert("복사 기능이 지원되지 않는 환경입니다.");
      }
    };

    try {
      if (navigator.share && navigator.canShare && navigator.canShare(shareData)) {
        await navigator.share(shareData);
      } else {
        await copyToClipboard();
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        console.warn("Share API failed", err);
        await copyToClipboard();
      }
    }
  };

  const handleAddComment = () => {
    if (!selectedArticle || !commentInput.trim()) return;

    const newComment: Comment = {
      id: Date.now().toString(),
      user: `시청자_${Math.floor(Math.random() * 9000) + 1000}`,
      text: commentInput,
      date: new Date().toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' })
    };

    const updated = {
      ...selectedArticle,
      comments: [newComment, ...(selectedArticle.comments || [])]
    };

    updateArticleInStorage(updated);
    setCommentInput("");
  };

  return (
    <div className="animate-fade-in max-w-4xl mx-auto pb-5">
      <div className="d-flex align-items-center justify-content-between mb-5">
        <div>
          <h2 className="fw-black mb-1 flex items-center gap-3">
            <span className="bg-red-600 px-3 py-1 rounded text-white text-sm animate-pulse">LIVE</span>
            📡 실시간 보도 파이프라인
          </h2>
          <p className="text-slate-400 m-0">기자실에서 방금 막 전송된 속보입니다.</p>
        </div>
        <div className="text-right hidden md:block">
          <div className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-1">System Status</div>
          <div className="text-green-400 font-bold flex items-center gap-2">
            <div className="w-2 h-2 rounded-full bg-green-400 animate-ping"></div>
            Online
          </div>
        </div>
      </div>

      <div className="row g-4">
        {articles.length === 0 ? (
          <div className="col-12">
            <div className="glass-card p-5 rounded-4 text-center border-dashed border-slate-800">
               <Newspaper size={80} className="mx-auto mb-4 text-slate-800 opacity-20" />
               <h3 className="text-slate-500 fw-bold">아직 도착한 속보가 없습니다.</h3>
               <p className="text-slate-600">기자실에서 첫 번째 기사가 발행될 때까지 잠시만 기다려 주세요.</p>
            </div>
          </div>
        ) : (
          <div className="col-12">
            <div className="d-flex flex-column gap-5">
              {articles.map((article, idx) => (
                <div 
                  key={article.id} 
                  className={`glass-card rounded-4 overflow-hidden border-0 shadow-lg group cursor-pointer transition-all hover:scale-[1.01] ${idx === 0 ? 'ring-2 ring-red-600/50' : ''}`}
                  onClick={() => setSelectedArticle(article)}
                >
                  <div className="row g-0">
                    <div className="col-md-5 position-relative overflow-hidden">
                      {article.image ? (
                        <img src={article.image} alt="news" className="w-100 h-100 object-cover group-hover:scale-110 transition-transform duration-700" style={{ minHeight: '280px' }} />
                      ) : (
                        <div className="w-100 h-100 bg-slate-900 flex items-center justify-center text-slate-800">
                           <Newspaper size={60} />
                        </div>
                      )}
                      {idx === 0 && (
                        <div className="position-absolute top-0 start-0 m-3">
                          <span className="badge bg-red-600 shadow-lg px-3 py-2 fs-6">BREAKING NEWS</span>
                        </div>
                      )}
                    </div>
                    <div className="col-md-7">
                      <div className="p-4 h-100 d-flex flex-column">
                        <div className="d-flex align-items-center justify-content-between mb-3">
                          <span className="text-red-500 text-sm font-black uppercase tracking-widest">{article.category}</span>
                          <span className="text-slate-500 text-xs flex items-center gap-1">
                            <Clock size={12} /> {article.date}
                          </span>
                        </div>
                        <h3 className="text-white fw-bold mb-3 fs-2 line-clamp-2 group-hover:text-red-400 transition-colors leading-tight">{article.title}</h3>
                        <p className="text-slate-400 text-base line-clamp-3 mb-4 flex-grow-1">
                          {article.content.replace(/<[^>]*>/g, '').substring(0, 200)}...
                        </p>
                        <div className="d-flex align-items-center justify-content-between pt-3 border-top border-slate-800/50">
                          <div className="d-flex gap-4">
                            <button onClick={(e) => handleLike(e, article)} className="text-slate-500 text-xs flex items-center gap-1 font-bold hover:text-red-500 transition-colors border-0 bg-transparent">
                              <Heart size={14} className={article.likes && article.likes > 0 ? "fill-red-500 text-red-500" : "text-slate-500"}/> {article.likes || 0}
                            </button>
                            <span className="text-slate-500 text-xs flex items-center gap-1 font-bold">
                              <MessageCircle size={14}/> {article.comments?.length || 0}
                            </span>
                            <button onClick={(e) => handleShare(e, article)} className="text-slate-500 text-xs flex items-center gap-1 font-bold hover:text-blue-400 border-0 bg-transparent">
                              <Share2 size={14}/> 공유
                            </button>
                            <button onClick={(e) => deleteArticle(article.id, e)} className="text-slate-500 text-xs flex items-center gap-1 font-bold hover:text-red-500 border-0 bg-transparent opacity-0 group-hover:opacity-100 transition-opacity">
                              <Trash2 size={14}/> 삭제
                            </button>
                          </div>
                          <button className="btn btn-link p-0 text-white text-sm fw-bold no-underline flex items-center gap-1 hover:text-red-500 transition-colors">
                            기사 전문 보기 <ChevronRight size={18} />
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="py-5 text-center">
              <div className="inline-block p-4 rounded-full bg-slate-900/50 border border-slate-800">
                <p className="text-slate-500 text-xs m-0 font-bold tracking-widest flex items-center gap-2">
                  <LoadingSpinnerIcon size={12} className="animate-spin"/> 기사 업데이트 확인 중...
                </p>
              </div>
            </div>
          </div>
        )}
      </div>

      {selectedArticle && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/95 backdrop-blur-2xl animate-fade-in" onClick={() => setSelectedArticle(null)}>
          <div className="bg-slate-900 w-full max-w-5xl max-h-[95vh] rounded-3xl overflow-hidden border border-slate-800 flex flex-col shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="relative h-72 md:h-[450px] flex-shrink-0">
              {selectedArticle.image ? (
                <img src={selectedArticle.image} alt="Full" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full bg-slate-950 flex items-center justify-center"><Newspaper size={100} className="text-slate-900" /></div>
              )}
              <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/20 to-transparent"></div>
              <button className="absolute top-8 right-8 w-12 h-12 bg-black/50 hover:bg-red-600 rounded-full flex items-center justify-center transition-all shadow-xl" onClick={() => setSelectedArticle(null)}>
                <ChevronRight className="text-white rotate-180" size={24} />
              </button>
              <div className="absolute bottom-10 left-10 right-10">
                 <span className="badge bg-red-600 mb-4 px-4 py-2 text-sm font-bold shadow-lg">{selectedArticle.category}</span>
                 <h1 className="text-4xl md:text-6xl font-black text-white leading-tight drop-shadow-lg">{selectedArticle.title}</h1>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto bg-slate-900 custom-scrollbar">
               <div className="p-10 md:p-16 pt-10">
                  <div className="flex items-center gap-8 mb-10 text-slate-400 text-sm border-b border-slate-800 pb-8">
                    <span className="flex items-center gap-2 font-bold"><Calendar size={16}/> {selectedArticle.date}</span>
                    <span className="flex items-center gap-2 font-bold"><Clock size={16}/> BREAKING NOW</span>
                    <span className="text-green-500 font-black tracking-tighter ml-auto bg-green-500/10 px-3 py-1 rounded border border-green-500/20">VERIFIED: {selectedArticle.factCheck}</span>
                  </div>

                  <div 
                      className="text-slate-200 text-xl leading-relaxed space-y-8 mb-16"
                      style={{ fontFamily: "'Pretendard', sans-serif", fontSize: '1.35rem', lineHeight: '2.2' }}
                      dangerouslySetInnerHTML={{ __html: selectedArticle.content }}
