import React, { useState, useEffect, useRef } from 'react';
import { Camera, Send, MessageCircle, Heart, ThumbsUp, Angry, Frown, Save, Trash2, Sparkles, X } from 'lucide-react';

interface Comment {
  id: number;
  user: string;
  text: string;
  date: string;
}

interface SavedHeadline {
  id: number;
  name: string;
  headline: string;
  image: string;
  reactions: {
    like: number;
    heart: number;
    angry: number;
    sad: number;
  };
  comments: Comment[];
  date: string;
}

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const HeadlineMaker: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [name, setName] = useState('');
  const [headline, setHeadline] = useState('');
  const [uploadedImage, setUploadedImage] = useState<string | null>(null);
  const [savedHeadlines, setSavedHeadlines] = useState<SavedHeadline[]>([]);
  const [commentInputs, setCommentInputs] = useState<{ [key: number]: string }>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('viewer_headlines');
    if (saved) setSavedHeadlines(JSON.parse(saved));
  }, []);

  const saveToLocal = (data: SavedHeadline[]) => {
    setSavedHeadlines(data);
    localStorage.setItem('viewer_headlines', JSON.stringify(data));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setUploadedImage(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const publishHeadline = () => {
    if (!name.trim() || !headline.trim()) {
      alert("이름과 속보 내용을 입력해주세요!");
      return;
    }

    const newEntry: SavedHeadline = {
      id: Date.now(),
      name,
      headline,
      image: uploadedImage || 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80',
      reactions: { like: 0, heart: 0, angry: 0, sad: 0 },
      comments: [],
      date: new Date().toLocaleString()
    };

    const updated = [newEntry, ...savedHeadlines];
    saveToLocal(updated);

    // Reset
    setName('');
    setHeadline('');
    setUploadedImage(null);
    alert("🚀 나만의 속보가 발행되었습니다!");
  };

  const handleReaction = (id: number, type: keyof SavedHeadline['reactions']) => {
    const updated = savedHeadlines.map(h => {
      if (h.id === id) return { ...h, reactions: { ...h.reactions, [type]: h.reactions[type] + 1 } };
      return h;
    });
    saveToLocal(updated);
  };

  const deleteHeadline = (id: number) => {
    if (!window.confirm("이 속보를 영구적으로 삭제하시겠습니까?")) return;
    const updated = savedHeadlines.filter(h => h.id !== id);
    saveToLocal(updated);
  };

  const addComment = (id: number) => {
    const text = commentInputs[id];
    if (!text?.trim()) return;
    const updated = savedHeadlines.map(h => {
      if (h.id === id) {
        return { ...h, comments: [...h.comments, { id: Date.now(), user: "방구석 네티즌", text, date: "방금 전" }] };
      }
      return h;
    });
    saveToLocal(updated);
    setCommentInputs({ ...commentInputs, [id]: '' });
  };

  return (
    <div className="text-white pb-5 animate-fade-in">
      <div className="row g-5">
        <div className="col-lg-5">
          <div className="glass-card p-4 sticky-top border-0 shadow-2xl" style={{ top: '20px', background: '#0f172a' }}>
            <h3 className="fw-bold mb-4 d-flex align-items-center gap-2">
              <Sparkles className="text-danger" /> 속보 합성 스튜디오
            </h3>

            <div className="mb-3">
              <label className="text-slate-400 text-xs font-bold mb-1 block uppercase">주인공</label>
              <input type="text" placeholder="이름" className="form-control" value={name} onChange={(e) => setName(e.target.value)} />
            </div>

            <div className="mb-3">
              <label className="text-slate-400 text-xs font-bold mb-1 block uppercase">속보 헤드라인</label>
              <input type="text" placeholder="속보 제목" className="form-control" value={headline} onChange={(e) => setHeadline(e.target.value)} />
            </div>

            <div className="mb-4">
              <label className="text-slate-400 text-xs font-bold mb-1 block uppercase">배경 사진 업로드</label>
              <button onClick={() => fileInputRef.current?.click()} className="btn btn-outline-slate-700 w-100 py-3 border-dashed border-2 text-slate-300">
                <Camera size={20} className="me-2"/> 사진 선택하기
              </button>
              <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
            </div>

            <div className="preview-container mb-4">
              <div className="position-relative rounded-3 overflow-hidden" style={{ height: '200px', background: '#000' }}>
                <img src={uploadedImage || 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=800&q=80'} className="w-100 h-100 object-cover opacity-60" />
                <div className="position-absolute bottom-0 start-0 w-100 p-3" style={{ background: 'linear-gradient(to right, #cc0000 0%, #7f0000 100%)' }}>
                    <div className="d-flex align-items-center gap-2">
                        <span className="badge bg-white text-danger fw-black px-1 py-1">속보</span>
                        <span className="text-white fw-bold truncate">{name ? `${name} 씨, ` : ''}{headline || '내용을 입력하세요'}</span>
                    </div>
                </div>
              </div>
            </div>

            <button className="btn btn-danger w-100 py-3 fw-bold shadow-lg" onClick={publishHeadline}>속보 발행</button>
          </div>
        </div>

        <div className="col-lg-7">
          <div className="d-flex justify-content-between align-items-center mb-4">
            <h3 className="fw-bold m-0">📡 시청자 발행 타임라인</h3>
            {savedHeadlines.length > 0 && (
              <button onClick={() => { if(window.confirm("모든 속보를 삭제하시겠습니까?")) saveToLocal([]); }} className="btn btn-outline-slate-700 btn-sm rounded-xl px-3 border-0 hover:text-red-500 font-bold">
                전체 삭제
              </button>
            )}
          </div>

          <div className="d-flex flex-column gap-5">
            {savedHeadlines.length === 0 ? (
              <div className="glass-card p-10 rounded-4 text-center border-slate-800 opacity-40">
                <Sparkles size={48} className="mx-auto mb-3" />
                <p className="fw-bold">아직 발행된 나만의 속보가 없습니다.</p>
              </div>
            ) : (
              savedHeadlines.map(h => (
                <div key={h.id} className="glass-card rounded-4 overflow-hidden border-0 shadow-xl group" style={{ background: '#1e293b' }}>
                  <div className="position-relative" style={{ height: '300px' }}>
                    <img src={h.image} className="w-100 h-100 object-cover" />
                    <div className="position-absolute top-4 right-4 z-10">
                      <button 
                        onClick={() => deleteHeadline(h.id)} 
                        className="w-10 h-10 bg-black/50 hover:bg-red-600 text-white rounded-full flex items-center justify-center transition-all border-0 shadow-xl opacity-0 group-hover:opacity-100"
                        title="속보 삭제"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                    <div className="position-absolute bottom-0 start-0 w-100 p-4" style={{ background: 'linear-gradient(to top, rgba(127,0,0,1) 0%, rgba(204,0,0,0.8) 40%, rgba(204,0,0,0) 100%)' }}>
                        <h2 className="text-white fw-bold m-0 fs-3">{h.name} 씨, {h.headline}</h2>
                    </div>
                  </div>

                  <div className="p-3 px-4 d-flex align-items-center justify-content-between bg-slate-900/40">
                    <div className="d-flex gap-4">
                      <button onClick={() => handleReaction(h.id, 'like')} className="reaction-btn text-slate-400 hover:text-blue-400 border-0 bg-transparent"><ThumbsUp size={18}/> {h.reactions.like}</button>
                      <button onClick={() => handleReaction(h.id, 'heart')} className="reaction-btn text-slate-400 hover:text-pink-400 border-0 bg-transparent"><Heart size={18}/> {h.reactions.heart}</button>
                      <button onClick={() => handleReaction(h.id, 'angry')} className="reaction-btn text-slate-400 hover:text-red-400 border-0 bg-transparent"><Angry size={18}/> {h.reactions.angry}</button>
                    </div>
                    <div className="text-slate-500 text-xs font-bold flex items-center gap-1"><MessageCircle size={14}/> 댓글 {h.comments.length}</div>
                  </div>

                  <div className="bg-slate-900/30 p-4">
                    <div className="space-y-2 mb-3">
                      {h.comments.map(c => (
                        <div key={c.id} className="d-flex gap-2 animate-fade-in"><div className="text-blue-400 text-xs font-bold">{c.user}</div><div className="text-slate-300 text-xs">{c.text}</div></div>
                      ))}
                    </div>
                    <div className="d-flex gap-2">
                      <input type="text" className="form-control form-control-sm !bg-slate-800 border-slate-700 text-white" placeholder="시청자 의견 달기..." value={commentInputs[h.id] || ''} onChange={(e) => setCommentInputs({...commentInputs, [h.id]: e.target.value})} onKeyDown={(e) => e.key === 'Enter' && addComment(h.id)} />
                      <button onClick={() => addComment(h.id)} className="btn btn-primary btn-sm border-0 px-3">게시</button>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
      <style>{`
        .reaction-btn { background: none; border: none; padding: 0; display: flex; align-items: center; gap: 4px; transition: 0.2s; }
        .hidden { display: none; }
        .truncate { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
      `}</style>
    </div>
  );
};

export default HeadlineMaker;

import { useState, useEffect } from 'react';
import { Trash2, Calendar, X, FileText, Image as ImageIcon, ExternalLink, Filter, AlertTriangle } from 'lucide-react';

const Dashboard = () => {
  const [activeTab, setActiveTab] = useState<'articles' | 'images'>('articles');
  const [articles, setArticles] = useState<any[]>([]);
  const [images, setImages] = useState<any[]>([]);
  const [selectedItem, setSelectedItem] = useState<any | null>(null);

  const loadData = () => {
    const savedArticles = JSON.parse(localStorage.getItem('my_articles') || '[]');
    const savedImages = JSON.parse(localStorage.getItem('my_images') || '[]');
    setArticles(savedArticles);
    setImages(savedImages);
  };

  useEffect(() => {
    loadData();
    // 데이터 동기화를 위해 정기적으로 로드 (다른 탭에서 저장 시 반영)
    const interval = setInterval(loadData, 2000);
    return () => clearInterval(interval);
  }, []);

  const deleteArticle = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 영구적으로 삭제하시겠습니까? 데이터는 복구되지 않습니다.")) return;
    const updated = articles.filter(item => item.id !== id);
    localStorage.setItem('my_articles', JSON.stringify(updated));
    setArticles(updated);
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const deleteImage = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 이미지를 영구적으로 삭제하시겠습니까? 데이터는 복구되지 않습니다.")) return;
    const updated = images.filter(item => item.id !== id);
    localStorage.setItem('my_images', JSON.stringify(updated));
    setImages(updated);
  };

  const clearAll = () => {
    const targetName = activeTab === 'articles' ? '기사 전체' : '이미지 전체';
    if (!window.confirm(`${targetName}를 정말로 모두 영구 삭제하시겠습니까? 이 작업은 절대 되돌릴 수 없습니다.`)) return;

    if (activeTab === 'articles') {
      localStorage.setItem('my_articles', '[]');
      setArticles([]);
      setSelectedItem(null);
    } else {
      localStorage.setItem('my_images', '[]');
      setImages([]);
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="d-flex justify-content-between align-items-end mb-5">
        <div>
          <h2 className="fw-black mb-1 tracking-tighter">📊 통합 미디어 대시보드</h2>
          <p className="text-slate-500 text-sm m-0">발행된 기사와 생성된 이미지 자산을 통합 관리합니다.</p>
        </div>
        <div className="d-flex align-items-center gap-3">
           {(activeTab === 'articles' ? articles.length > 0 : images.length > 0) && (
             <button 
               onClick={clearAll} 
               className="btn btn-outline-danger btn-sm rounded-xl px-3 py-2 d-flex align-items-center gap-2 font-bold opacity-60 hover:opacity-100 transition-opacity"
             >
               <AlertTriangle size={14} /> 영구 전체 삭제
             </button>
           )}
           <div className="d-flex gap-2 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-800">
            <button 
              onClick={() => setActiveTab('articles')}
              className={`px-4 py-2 rounded-xl text-xs font-black transition-all ${activeTab === 'articles' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              기사 ({articles.length})
            </button>
            <button 
              onClick={() => setActiveTab('images')}
              className={`px-4 py-2 rounded-xl text-xs font-black transition-all ${activeTab === 'images' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
            >
              이미지 ({images.length})
            </button>
          </div>
        </div>
      </div>

      {activeTab === 'articles' ? (
        <div className="row g-4">
          {articles.length === 0 ? (
            <EmptyState message="발행된 기사가 없습니다." icon={<FileText size={48} />} />
          ) : (
            articles.map(article => (
              <div key={article.id} className="col-md-6 col-lg-4">
                <div 
                  className="card h-100 border-0 shadow-2xl glass-card overflow-hidden group transition-all hover:translate-y-[-8px]" 
                  style={{ cursor: 'pointer', background: '#0f172a', borderRadius: '24px' }}
                  onClick={() => setSelectedItem(article)}
                >
                  <div style={{ height: '200px', overflow: 'hidden', background: '#020617' }} className="position-relative">
                    {article.image ? (
                      <img src={article.image} alt="news" className="w-100 h-100 object-cover group-hover:scale-110 transition-transform duration-700" />
                    ) : (
                      <div className="w-100 h-100 d-flex align-items-center justify-content-center text-slate-800">
                        <FileText size={40} />
                      </div>
                    )}
                    <span className="position-absolute top-4 right-4 badge bg-blue-600 px-3 py-2 rounded-lg text-[10px] font-black uppercase">{article.category}</span>
                    <button 
                      className="position-absolute top-4 left-4 p-2 bg-red-600/20 text-red-500 rounded-lg hover:bg-red-600 hover:text-white transition-all border-0 shadow-lg"
                      onClick={(e) => deleteArticle(article.id, e)}
                      title="기사 영구 삭제"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <div className="card-body p-4">
                    <div className="text-slate-500 text-[10px] font-bold mb-2 flex items-center gap-1">
                      <Calendar size={12}/> {article.date}
                    </div>
                    <h5 className="text-white fw-black mb-3 line-clamp-2 leading-tight group-hover:text-blue-400">{article.title}</h5>
                    <p className="text-slate-400 text-xs line-clamp-3 opacity-60">
                      {article.content.replace(/<[^>]*>/g, '')}
                    </p>
                  </div>
                  <div className="card-footer bg-slate-900/50 border-top border-slate-800/50 d-flex justify-content-between p-3 px-4">
                      <span className="text-[9px] text-green-500 font-bold bg-green-500/10 px-2 py-1 rounded">FACT-CHECKED</span>
                      <span className="text-[9px] text-slate-500">View Details</span>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      ) : (
        <div className="row g-4">
          {images.length === 0 ? (
            <EmptyState message="생성된 이미지가 없습니다." icon={<ImageIcon size={48} />} />
          ) : (
            images.map(img => (
              <div key={img.id} className="col-md-4 col-lg-3">
                <div className="glass-card rounded-4 overflow-hidden border-slate-800 group shadow-xl">
                  <div className="position-relative overflow-hidden" style={{ aspectRatio: '1/1' }}>
                    <img src={img.url} className="w-100 h-100 object-cover group-hover:scale-110 transition-transform duration-500" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-3">
                       <button onClick={() => window.open(img.url, '_blank')} className="p-2 bg-white/20 backdrop-blur-md rounded-full text-white hover:bg-white/40 border-0">
                        <ExternalLink size={18} />
                       </button>
                       <button onClick={(e) => deleteImage(img.id, e)} className="p-2 bg-red-500/50 backdrop-blur-md rounded-full text-white hover:bg-red-500/80 border-0">
                        <Trash2 size={18} />
                       </button>
                    </div>
                  </div>
                  <div className="p-3 bg-slate-900/80">
                    <p className="text-[10px] text-slate-400 mb-1 font-bold italic line-clamp-1">"{img.prompt}"</p>
                    <div className="text-[9px] text-slate-600 font-bold">{img.date}</div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {/* 기사 상세 모달 */}
      {selectedItem && activeTab === 'articles' && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center p-4 bg-black/95 backdrop-blur-xl animate-fade-in" onClick={() => setSelectedItem(null)}>
            <div className="rounded-3xl shadow-2xl overflow-hidden border border-slate-800 flex flex-col w-full max-w-4xl max-h-[90vh]" style={{ background: '#0f172a' }} onClick={(e) => e.stopPropagation()}>
                <div className="p-4 px-6 border-bottom border-slate-800 d-flex justify-content-between align-items-center bg-slate-900/80">
                    <h6 className="m-0 fw-black text-white text-sm tracking-tight uppercase flex items-center gap-2"><FileText size={16}/> Article Viewer</h6>
                    <button className="btn-close btn-close-white opacity-50" onClick={() => setSelectedItem(null)}></button>
                </div>
                <div className="p-5 md:p-10 overflow-auto custom-scrollbar">
                    <h1 className="fw-black text-white display-5 mb-4 tracking-tighter">{selectedItem.title}</h1>
                    <div className="text-slate-500 text-xs mb-5 font-bold pb-4 border-bottom border-slate-800">
                        <Calendar size={14} className="inline me-1"/> {selectedItem.date} | 
                        <span className="text-green-500 ms-2">FACT-CHECKED</span>
                    </div>
                    {selectedItem.image && <img src={selectedItem.image} className="img-fluid rounded-4 mb-5 shadow-2xl border border-slate-800" />}
                    <div className="text-slate-200" style={{ fontSize: '1.2rem', lineHeight: '1.8' }} dangerouslySetInnerHTML={{ __html: selectedItem.content }} />
                </div>
                <div className="p-4 px-6 border-top border-slate-800 bg-slate-900/80 d-flex justify-content-between">
                    <button className="btn btn-outline-danger px-4 rounded-xl fw-bold flex items-center gap-2" onClick={() => deleteArticle(selectedItem.id)}>
                      <Trash2 size={16} /> 영구 삭제
                    </button>
                    <button className="btn btn-primary px-5 rounded-xl fw-black" onClick={() => setSelectedItem(null)}>확인</button>
                </div>
            </div>
        </div>
      )}

      <style>{`
        .line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
        .line-clamp-3 { display: -webkit-box; -webkit-line-clamp: 3; -webkit-box-orient: vertical; overflow: hidden; }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
      `}</style>
    </div>
  );
};

const EmptyState = ({ message, icon }: { message: string, icon: any }) => (
  <div className="col-12">
    <div className="glass-card p-10 rounded-3xl text-center border-dashed border-slate-800 flex flex-col items-center justify-center min-h-[400px]">
        <div className="bg-slate-900 p-4 rounded-full mb-4 text-slate-700">{icon}</div>
        <h3 className="text-slate-400 fw-black">{message}</h3>
    </div>
  </div>
);

export default Dashboard;

import { useState, useEffect, useCallback } from 'react';
import { generateFactBasedArticle, generateImage, generateCoverageSuggestions } from '../services/gemini';
import { Sparkles, Save, Loader2, Camera, FileText, Cpu, RefreshCw, AlertCircle, ArrowRight, Link, ListChecks, Trash2, Quote, Maximize2, X, Key, Zap, ShieldAlert, CheckCircle } from 'lucide-react';

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

interface Suggestion {
  id: string;
  title: string;
  category: string;
  angle: string;
  urgency: string;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState(() => localStorage.getItem('donga_writer_topic') || "");
  const [category, setCategory] = useState(() => localStorage.getItem('donga_writer_category') || "social");
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [articleData, setArticleData] = useState<any | null>(() => {
    const saved = localStorage.getItem('donga_writer_article');
    return saved ? JSON.parse(saved) : null;
  });
  const [imageResult, setImageResult] = useState<string | null>(() => localStorage.getItem('donga_writer_image'));
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");
  const [isZoomed, setIsZoomed] = useState(false);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);
  const [isSaved, setIsSaved] = useState(false);
  const [lastSavedId, setLastSavedId] = useState<number | null>(null);

  // 현재 기사가 이미 대시보드(my_articles)에 있는지 확인하는 로직
  const checkIfAlreadySaved = useCallback(() => {
    if (!articleData) return;
    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    const existing = saved.find((a: any) => a.title === articleData.title);
    if (existing) {
      setIsSaved(true);
      setLastSavedId(existing.id);
    } else {
      setIsSaved(false);
      setLastSavedId(null);
    }
  }, [articleData]);

  useEffect(() => {
    checkIfAlreadySaved();
  }, [checkIfAlreadySaved, articleData]);

  useEffect(() => localStorage.setItem('donga_writer_topic', topic), [topic]);
  useEffect(() => localStorage.setItem('donga_writer_category', category), [category]);
  useEffect(() => {
    if (articleData) localStorage.setItem('donga_writer_article', JSON.stringify(articleData));
    else localStorage.removeItem('donga_writer_article');
  }, [articleData]);
  useEffect(() => {
    if (imageResult) localStorage.setItem('donga_writer_image', imageResult);
    else localStorage.removeItem('donga_writer_image');
  }, [imageResult]);

  const fetchSuggestions = useCallback(async () => {
    setLoadingSuggestions(true);
    setApiErrorType(null);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data || []);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      if (e.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
    } finally {
      setLoadingSuggestions(false);
    }
  }, [isMockMode]);

  useEffect(() => {
    fetchSuggestions();
  }, [fetchSuggestions]);

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      setApiErrorType(null);
      setErrorMsg("");
      fetchSuggestions();
    }
  };

  const handleReset = () => {
    if (window.confirm("작성 중인 내용을 초기화하고 새 기사를 쓰시겠습니까?")) {
      setTopic("");
      setArticleData(null);
      setImageResult(null);
      setIsSaved(false);
      setLastSavedId(null);
      localStorage.removeItem('donga_writer_article');
      localStorage.removeItem('donga_writer_image');
      localStorage.removeItem('donga_writer_topic');
    }
  };

  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }
    setLoading(true);
    setErrorMsg("");
    setApiErrorType(null);
    setIsSaved(false);
    setLastSavedId(null);

    try {
      setStatusText("실시간 관련 속보 및 공공 데이터 검색 중... 🔍");
      const result = await generateFactBasedArticle(topic, category, isMockMode);

      const newArticleData = {
        title: result.title || topic,
        summary: result.summary || "",
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "AI 정밀 검증 완료",
        sources: result.sources || [],
        searchSources: result.searchSources
      };
      setArticleData(newArticleData);

      setStatusText("보도용 시각화 이미지 생성 중... 📸");
      const imgUrl = await generateImage(result.imageKeyword || topic, isMockMode);
      setImageResult(imgUrl);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") {
        setApiErrorType("QUOTA");
        setErrorMsg("API 할당량이 초과되었습니다. 개인 키를 설정하세요.");
      } else if (e.message === "PERMISSION_DENIED") {
        setApiErrorType("PERMISSION");
        setErrorMsg("API 키 권한(Referrer 제한 등)에 문제가 있습니다. 개인 키를 설정하세요.");
      } else {
        setErrorMsg("데이터 수집 중 문제가 발생했습니다. 잠시 후 다시 시도해 주세요.");
      }
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  const handleSaveToDashboard = () => {
    if (!articleData) return;

    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    const existing = saved.find((a: any) => a.title === articleData.title);

    if (existing) {
      alert("이미 대시보드에 저장된 동일한 기사가 있습니다.");
      setIsSaved(true);
      setLastSavedId(existing.id);
      return;
    }

    const saveId = Date.now();
    const finalArticle = {
      ...articleData,
      id: saveId,
      image: imageResult,
      date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString()
    };

    localStorage.setItem('my_articles', JSON.stringify([finalArticle, ...saved]));

    setIsSaved(true);
    setLastSavedId(saveId);
    alert("✅ 기사가 대시보드에 성공적으로 저장되었습니다!");
  };

  const handleDeleteSaved = () => {
    if (!lastSavedId) return;
    if (!window.confirm("대시보드에서 이 기사를 영구적으로 삭제하시겠습니까? 이 작업은 복구할 수 없습니다.")) return;

    const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
    const updated = saved.filter((a: any) => a.id !== lastSavedId);
    localStorage.setItem('my_articles', JSON.stringify(updated));

    setIsSaved(false);
    setLastSavedId(null);
    alert("🗑️ 대시보드에서 기사가 영구 삭제되었습니다.");
  };

  const handleQuickStart = (item: Suggestion) => {
    setTopic(item.title);
    const cat = item.category.toLowerCase();
    if (cat.includes('it') || cat.includes('tech')) setCategory('tech');
    else if (cat.includes('econ')) setCategory('economy');
    else if (cat.includes('polit')) setCategory('politics');
    else setCategory('social');
    window.scrollTo({ top: 450, behavior: 'smooth' });
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      {isZoomed && imageResult && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-fade-in cursor-zoom-out" onClick={() => setIsZoomed(false)}>
          <button className="absolute top-8 right-8 text-white/50 hover:text-white"><X size={40} /></button>
          <img src={imageResult} alt="Expanded News" className="max-w-[90vw] max-h-[85vh] object-contain rounded-2xl shadow-2xl animate-scale-up" />
        </div>
      )}

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-500 animate-pulse" />}
            </div>
            <div>
              <p className={`font-bold m-0 text-lg ${apiErrorType === 'PERMISSION' ? 'text-red-200' : 'text-amber-200'}`}>
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : 'AI 서비스 할당량 도달'}
              </p>
              <p className="text-sm m-0 opacity-80">
                {apiErrorType === 'PERMISSION' 
                  ? '현재 사용 중인 API 키가 Referrer 제한으로 인해 차단되었습니다. 개인 API 키를 선택하세요.' 
                  : '무료 할당량이 소진되었습니다. 개인 API 키를 설정하거나 데모 모드를 활성화하세요.'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2`}>
              <Key size={16} /> API 키 설정
            </button>
            <button onClick={() => { setIsMockMode(true); setApiErrorType(null); }} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all">
              데모 모드로 전환
            </button>
          </div>
        </div>
      )}

      <div className="mb-5">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <div className="d-flex align-items-center gap-3">
            <div className="bg-blue-600/30 p-2 rounded-xl border border-blue-500/30"><RefreshCw className={`text-blue-400 ${loadingSuggestions ? 'animate-spin' : ''}`} size={20} /></div>
            <div>
              <h4 className="fw-black m-0 tracking-tighter flex items-center gap-2">실시간 AI 편집국 브리핑 <span className="badge bg-red-600 px-2 py-0.5 animate-pulse text-[10px] rounded">LIVE</span></h4>
              <p className="text-[11px] text-slate-500 m-0">현재 온라인 트렌드와 뉴스 소스를 바탕으로 한 취재 추천입니다.</p>
            </div>
          </div>
          <button onClick={handleReset} className="btn btn-outline-slate-700 btn-sm text-[10px] fw-bold d-flex align-items-center gap-2 px-3 py-2 rounded-xl"><Trash2 size={14} /> 리셋</button>
        </div>
        <div className="row g-3">
          {loadingSuggestions ? Array.from({ length: 4 }).map((_, i) => <div key={i} className="col-md-3"><div className="glass-card p-4 rounded-2xl border-slate-800 animate-pulse h-[140px]"></div></div>) : suggestions.map((item) => (
            <div key={item.id} className="col-md-3">
              <div className="glass-card p-4 rounded-2xl border-slate-800 h-100 hover:border-blue-500/50 hover:bg-slate-800/60 transition-all cursor-pointer group flex flex-col justify-between shadow-xl" onClick={() => handleQuickStart(item)}>
                <div>
                  <div className="d-flex justify-content-between mb-3"><span className="badge bg-red-600/20 text-red-500 border border-red-500/30 text-[9px] px-2 py-1 font-black uppercase">{item.urgency}</span><span className="text-[10px] text-blue-400 font-black uppercase tracking-widest">{item.category}</span></div>
                  <h6 className="text-white fw-bold text-sm mb-2 group-hover:text-blue-400 leading-snug line-clamp-2">{item.title}</h6>
                </div>
                <div className="pt-3 border-t border-slate-800/50 mt-3 flex justify-between items-center"><span className="text-[10px] text-slate-500 italic">"{item.angle}"</span><ArrowRight size={14} className="text-blue-500 group-hover:translate-x-1 transition-transform" /></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl relative overflow-hidden" style={{ background: 'rgba(15, 23, 42, 0.95)' }}>
        <h2 className="fw-black mb-4 tracking-tighter d-flex align-items-center gap-3 text-white"><div className="bg-primary/20 p-2 rounded-xl"><Sparkles className="text-primary" size={24} /></div>AI 팩트체크 기사 정리</h2>
        <div className="row g-3">
          <div className="col-md-2"><select className="form-select !bg-slate-950 border-slate-800 rounded-xl py-3 text-white" value={category} onChange={(e) => setCategory(e.target.value)}><option value="social">사회</option><option value="politics">정치</option><option value="economy">경제</option><option value="tech">IT/과학</option></select></div>
          <div className="col-md-8"><input className="form-control fs-5 !bg-slate-950 border-slate-800 rounded-xl py-3 px-4 text-white" placeholder="취재 핵심 주제를 입력하세요..." value={topic} onChange={(e) => setTopic(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()} /></div>
          <div className="col-md-2 pt-1"><button className="btn btn-primary w-100 py-3 rounded-xl fw-black shadow-lg flex items-center justify-center gap-2" onClick={handleFullCreation} disabled={loading}>{loading ? <Loader2 className="animate-spin" size={20}/> : <Cpu size={18}/>}기사 생성</button></div>
        </div>
        {(loading || errorMsg) && (
            <div className={`mt-5 p-4 rounded-2xl border font-bold text-center animate-fade-in ${errorMsg ? 'bg-red-500/10 border-red-500/30 text-red-400' : 'bg-blue-500/10 border-blue-500/30 text-blue-300'}`}>
                {errorMsg ? <AlertCircle size={20} className="inline me-2"/> : <div className="spinner-border spinner-border-sm me-3"></div>}
                {errorMsg || statusText}
            </div>
        )}
      </div>

      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            <div className="col-lg-3">
              <div className="glass-card p-4 rounded-4 border-slate-800 h-100 shadow-xl" style={{ background: '#0f172a' }}>
                <h6 className="text-blue-400 fw-bold mb-4 flex items-center gap-2 text-sm uppercase tracking-widest"><Link size={16} /> 실시간 원천 소스</h6>
                <div className="d-flex flex-column gap-3">
                  {articleData.searchSources?.map((source: any, i: number) => (
                    <a key={i} href={source.uri} target="_blank" rel="noopener noreferrer" className="glass-card p-3 rounded-xl border-slate-800 text-slate-400 text-xs hover:text-blue-400 no-underline transition-all flex flex-col gap-2 group hover:bg-slate-800/50">
                      <div className="text-white font-bold line-clamp-2 group-hover:text-blue-400">{source.title}</div>
                      <div className="text-[9px] opacity-40 truncate flex items-center gap-1"><Link size={10} /> {source.uri}</div>
                    </a>
                  ))}
                </div>
