  </svg>
);

interface Comment {
  id: string;
  user: string;
  text: string;
  date: string;
}

interface Article {
  id: number;
  title: string;
  category: string;
  content: string;
  image: string | null;
  date: string;
  factCheck: string;
  likes?: number;
  comments?: Comment[];
}

const RealtimeNews: React.FC = () => {
  const [articles, setArticles] = useState<Article[]>([]);
  const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
  const [commentInput, setCommentInput] = useState("");

  const fetchArticles = () => {
    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const initialized = saved.map((a: Article) => ({
        ...a,
        likes: a.likes || 0,
        comments: a.comments || []
      }));
      setArticles(initialized);
    } catch (e) {
      console.error("Failed to load articles from localStorage", e);
    }
  };

  useEffect(() => {
    fetchArticles();
    const interval = setInterval(fetchArticles, 3000);
    return () => clearInterval(interval);
  }, []);

  const deleteArticle = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 영구적으로 삭제하시겠습니까? 삭제된 기사는 복구할 수 없습니다.")) return;

    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const updated = saved.filter((a: any) => a.id !== id);
      localStorage.setItem('my_articles', JSON.stringify(updated));
      setArticles(updated);
      if (selectedArticle?.id === id) setSelectedArticle(null);
    } catch (e) {
      console.error("Deletion failed", e);
    }
  };

  const updateArticleInStorage = (updatedArticle: Article) => {
    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const newArticles = saved.map((a: any) => a.id === updatedArticle.id ? updatedArticle : a);
      localStorage.setItem('my_articles', JSON.stringify(newArticles));
      setArticles(newArticles.map((a: Article) => ({
          ...a,
          likes: a.likes || 0,
          comments: a.comments || []
      })));
      if (selectedArticle?.id === updatedArticle.id) {
        setSelectedArticle(updatedArticle);
      }
    } catch (e) {
      console.error("Storage update failed", e);
    }
