};

export default AIWriter;

import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Image as ImageIcon, Save, Loader2, Zap, LayoutDashboard, Key, ShieldAlert } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIIllustrator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [prompt, setPrompt] = useState("");
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);
  const [isSaved, setIsSaved] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setApiErrorType(null);
    setIsSaved(false);
    try {
      const imgUrl = await generateImage(prompt, isMockMode);
      setImage(imgUrl);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") {
        setApiErrorType("QUOTA");
      } else if (e.message === "PERMISSION_DENIED") {
        setApiErrorType("PERMISSION");
      } else {
        alert("이미지 생성 중 오류가 발생했습니다.");
      }
    } finally {
      setLoading(false);
    }
  };

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      window.location.reload();
    }
  };

  const handleSaveToDashboard = () => {
    if (!image) return;
    try {
      const saved = JSON.parse(localStorage.getItem('my_images') || '[]');
      const newImage = {
        id: Date.now(),
        prompt: prompt,
        url: image,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      };

      let updated = [newImage, ...saved];
      let success = false;
      let attempts = 0;

      while (!success && attempts < 5) {
        try {
          localStorage.setItem('my_images', JSON.stringify(updated));
          success = true;
        } catch (e: any) {
          if (e.name === 'QuotaExceededError' || e.code === 22) {
            if (updated.length > 1) {
              updated.pop(); // 오래된 이미지 하나씩 제거
              attempts++;
            } else {
              throw new Error("STORAGE_FULL");
            }
          } else {
            throw e;
          }
        }
      }

      if (success) {
        setIsSaved(true);
        if (attempts > 0) {
          alert(`✅ 저장되었습니다.\n(용량 확보를 위해 오래된 이미지 ${attempts}개가 자동 정리되었습니다.)`);
        } else {
          alert("✅ 이미지가 통합 대시보드에 안전하게 보관되었습니다!");
        }
      }
    } catch (err: any) {
      console.error("Image save error:", err);
      if (err.message === "STORAGE_FULL") {
        alert("저장 공간이 부족합니다. 대시보드에서 불필요한 이미지나 기사를 삭제해 주세요.");
      } else {
        alert("저장 중 오류가 발생했습니다.");
      }
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="mb-5">
        <h2 className="fw-black mb-1 tracking-tighter">🎨 AI 일러스트레이터</h2>
        <p className="text-slate-500 text-sm m-0">기사 보충용 고퀄리티 일러스트를 생성합니다.</p>
      </div>

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-400" />}
            </div>
            <div>
              <p className={`font-bold m-0 text-lg ${apiErrorType === 'PERMISSION' ? 'text-red-200' : 'text-amber-200'}`}>
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : 'AI 서비스 할당량 도달'}
              </p>
              <p className="text-sm m-0 opacity-80">
                {apiErrorType === 'PERMISSION' 
                  ? '현재 사용 중인 API 키가 Referrer 제한으로 인해 차단되었습니다. 개인 API 키를 선택하세요.' 
                  : '무료 할당량이 소진되었습니다. 개인 API 키를 설정하거나 데모 모드를 활성화하세요.'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2`}>
              <Key size={16} /> API 키 설정
            </button>
            <button onClick={() => { setIsMockMode(true); setApiErrorType(null); }} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all">
              데모 모드로 전환
            </button>
          </div>
        </div>
      )}

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl bg-slate-900/90">
        <label className="text-slate-500 text-[10px] font-black mb-3 block uppercase tracking-widest">일러스트 생성 프롬프트</label>
        <div className="input-group">
          <input 
            type="text" 
            className="form-control !bg-slate-950 border-slate-800 text-white py-3 px-4 rounded-s-xl" 
            placeholder="어떤 이미지가 필요하신가요? (예: 미래 지향적인 한국 도심의 풍경, 3D 렌더링 스타일)"
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
          />
          <button className="btn btn-primary px-5 fw-bold rounded-e-xl" onClick={handleGenerate} disabled={loading}>
            {loading ? <Loader2 className="animate-spin" /> : "이미지 생성"}
          </button>
        </div>
      </div>

      <div className="d-flex justify-content-center align-items-center bg-slate-950/50 rounded-4 border border-slate-800 p-5 min-h-[500px] shadow-inner relative overflow-hidden">
        {loading ? (
          <div className="text-center">
            <Loader2 className="animate-spin mb-3 text-blue-500" size={48} />
            <p className="fw-black tracking-widest text-slate-500">PIXELS ASSEMBLING...</p>
          </div>
        ) : image ? (
          <div className="text-center w-100 animate-scale-up">
            <img src={image} alt="Generated" className="img-fluid rounded-4 shadow-2xl mb-4 max-h-[500px] border border-slate-800" />
            <div className="d-flex justify-content-center gap-3">
              <button 
                className={`btn ${isSaved ? 'btn-success' : 'btn-outline-light'} px-5 py-3 rounded-2xl fw-black flex items-center gap-2 transition-all`} 
                onClick={handleSaveToDashboard}
                disabled={isSaved}
              >
                {isSaved ? <Save size={20} /> : <LayoutDashboard size={20} />}
                {isSaved ? "저장 완료" : "대시보드에 저장"}
              </button>
              <a href={image} download="ai-illustration.png" className="btn btn-outline-slate-700 px-5 py-3 rounded-2xl fw-black flex items-center gap-2">
                파일 다운로드
              </a>
            </div>
          </div>
        ) : (
          <div className="text-center opacity-20">
            <ImageIcon size={80} className="mb-3 mx-auto" />
            <p className="fw-black">위의 프롬프트를 입력하여 작업을 시작하세요</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIIllustrator;

import { useState, useEffect, useCallback } from 'react';
import { generateFactBasedArticle, generateImage, generateCoverageSuggestions } from '../services/gemini';
import { Sparkles, Save, Loader2, FileText, Cpu, RefreshCw, AlertCircle, ArrowRight, Link, Trash2, Quote, Maximize2, X, Key, Zap, ShieldAlert, CheckCircle } from 'lucide-react';

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

interface Suggestion {
  id: string;
  title: string;
  category: string;
  angle: string;
  urgency: string;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState(() => localStorage.getItem('donga_writer_topic') || "");
  const [category, setCategory] = useState(() => localStorage.getItem('donga_writer_category') || "social");
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [articleData, setArticleData] = useState<any | null>(() => {
    const saved = localStorage.getItem('donga_writer_article');
    try {
      return saved ? JSON.parse(saved) : null;
    } catch {
      return null;
    }
  });
  const [imageResult, setImageResult] = useState<string | null>(() => localStorage.getItem('donga_writer_image'));
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");
  const [isZoomed, setIsZoomed] = useState(false);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);
  const [isSaved, setIsSaved] = useState(false);

  // 현재 아티클 ID가 대시보드에 존재하는지 확인
  const checkIfSaved = useCallback(() => {
    if (!articleData || !articleData.id) {
      setIsSaved(false);
      return;
    }
    try {
      const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
      const isAlready = saved.some((a: any) => a.id === articleData.id);
      setIsSaved(isAlready);
    } catch (e) {
      setIsSaved(false);
    }
  }, [articleData]);

  useEffect(() => {
    checkIfSaved();
  }, [checkIfSaved, articleData]);

  useEffect(() => {
    try {
      localStorage.setItem('donga_writer_topic', topic);
    } catch (e) {}
  }, [topic]);

  useEffect(() => {
    try {
      localStorage.setItem('donga_writer_category', category);
    } catch (e) {}
  }, [category]);

  useEffect(() => {
    try {
      if (articleData) {
        localStorage.setItem('donga_writer_article', JSON.stringify(articleData));
      } else {
        localStorage.removeItem('donga_writer_article');
      }
    } catch (e) {
      console.warn("Storage quota warning for current article state");
    }
  }, [articleData]);

  useEffect(() => {
    try {
      if (imageResult) {
        localStorage.setItem('donga_writer_image', imageResult);
      } else {
        localStorage.removeItem('donga_writer_image');
      }
    } catch (e) {
      console.warn("Storage quota warning for current image state");
    }
  }, [imageResult]);

  const fetchSuggestions = useCallback(async () => {
    setLoadingSuggestions(true);
    setApiErrorType(null);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data || []);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      if (e.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
    } finally {
      setLoadingSuggestions(false);
    }
  }, [isMockMode]);

  useEffect(() => {
    fetchSuggestions();
  }, [fetchSuggestions]);

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      setApiErrorType(null);
      setErrorMsg("");
      fetchSuggestions();
    }
  };

  const handleReset = () => {
    if (window.confirm("작성 중인 내용을 초기화하고 새 기사를 쓰시겠습니까?")) {
      setTopic("");
      setArticleData(null);
      setImageResult(null);
      setIsSaved(false);
      localStorage.removeItem('donga_writer_article');
      localStorage.removeItem('donga_writer_image');
      localStorage.removeItem('donga_writer_topic');
    }
  };

  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }
    setLoading(true);
    setErrorMsg("");
    setApiErrorType(null);
    setIsSaved(false);

    try {
      setStatusText("실시간 관련 속보 및 공공 데이터 검색 중... 🔍");
      const result = await generateFactBasedArticle(topic, category, isMockMode);

      const newArticleData = {
        id: Date.now(), // 생성 시점에 고유 ID 부여
        title: result.title || topic,
        summary: result.summary || "",
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "AI 정밀 검증 완료",
        sources: result.sources || [],
        searchSources: result.searchSources,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString()
      };
      setArticleData(newArticleData);

      setStatusText("보도용 시각화 이미지 생성 중... 📸");
      const imgUrl = await generateImage(result.imageKeyword || topic, isMockMode);
      setImageResult(imgUrl);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") {
        setApiErrorType("QUOTA");
        setErrorMsg("API 할당량이 초과되었습니다. 개인 키를 설정하세요.");
      } else if (e.message === "PERMISSION_DENIED") {
        setApiErrorType("PERMISSION");
        setErrorMsg("API 키 권한(Referrer 제한 등)에 문제가 있습니다. 개인 키를 설정하세요.");
      } else {
        setErrorMsg("데이터 수집 중 문제가 발생했습니다. 잠시 후 다시 시도해 주세요.");
      }
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  const handleSaveToDashboard = () => {
    if (!articleData) return;

    try {
      const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');

      // 이미 이 ID의 기사가 저장되어 있는지 체크 (중복 클릭 방지)
      if (saved.some((a: any) => a.id === articleData.id)) {
        alert("이미 대시보드에 저장된 기사입니다.");
        setIsSaved(true);
        return;
      }

      const finalArticle = {
        ...articleData,
        image: imageResult
      };

      let updated = [finalArticle, ...saved];

      // LocalStorage Quota 관리를 위한 재시도 로직
      let success = false;
      let attempts = 0;

      while (!success && attempts < 10) {
        try {
          localStorage.setItem('my_articles', JSON.stringify(updated));
          success = true;
        } catch (e: any) {
          if (e.name === 'QuotaExceededError' || e.code === 22) {
            if (updated.length > 1) {
              updated.pop(); // 가장 오래된 기사 하나 제거하여 공간 확보
              attempts++;
              console.warn(`Storage quota exceeded. Pruning oldest article (Attempt ${attempts})`);
            } else {
              throw new Error("STORAGE_FULL");
            }
          } else {
            throw e;
          }
        }
      }

      if (success) {
        setIsSaved(true);
        if (attempts > 0) {
          alert(`✅ 기사가 저장되었습니다.\n(용량 확보를 위해 오래된 기사 ${attempts}개가 정리되었습니다.)`);
        } else {
          alert("✅ 기사가 대시보드에 성공적으로 저장되었습니다!");
        }
      }
    } catch (err: any) {
      console.error("Save error:", err);
      if (err.message === "STORAGE_FULL") {
        alert("브라우저 저장 공간이 완전히 가득 찼습니다. 대시보드에서 불필요한 기사를 직접 삭제해 주세요.");
      } else {
        alert("저장 중 예상치 못한 오류가 발생했습니다.");
      }
    }
  };

  const handleDeleteSaved = () => {
    if (!articleData || !articleData.id) return;
    if (!window.confirm("대시보드에서 이 기사를 영구적으로 삭제하시겠습니까?")) return;

    try {
      const saved = JSON.parse(localStorage.getItem('my_articles') || '[]');
      const updated = saved.filter((a: any) => a.id !== articleData.id);
      localStorage.setItem('my_articles', JSON.stringify(updated));

      setIsSaved(false);
      alert("🗑️ 대시보드에서 기사가 영구 삭제되었습니다.");
    } catch (err) {
      console.error("Delete error:", err);
    }
  };

  const handleQuickStart = (item: Suggestion) => {
    setTopic(item.title);
    const cat = item.category.toLowerCase();
    if (cat.includes('it') || cat.includes('tech')) setCategory('tech');
    else if (cat.includes('econ')) setCategory('economy');
    else if (cat.includes('polit')) setCategory('politics');
    else setCategory('social');
    window.scrollTo({ top: 450, behavior: 'smooth' });
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      {isZoomed && imageResult && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-fade-in cursor-zoom-out" onClick={() => setIsZoomed(false)}>
          <button className="absolute top-8 right-8 text-white/50 hover:text-white"><X size={40} /></button>
          <img src={imageResult} alt="Expanded News" className="max-w-[90vw] max-h-[85vh] object-contain rounded-2xl shadow-2xl animate-scale-up" />
        </div>
      )}

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-500 animate-pulse" />}
            </div>
            <div>
              <p className={`font-bold m-0 text-lg ${apiErrorType === 'PERMISSION' ? 'text-red-200' : 'text-amber-200'}`}>
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : 'AI 서비스 할당량 도달'}
              </p>
              <p className="text-sm m-0 opacity-80">
                {apiErrorType === 'PERMISSION' 
                  ? '현재 사용 중인 API 키가 Referrer 제한으로 인해 차단되었습니다. 개인 API 키를 선택하세요.' 
                  : '무료 할당량이 소진되었습니다. 개인 API 키를 설정하거나 데모 모드를 활성화하세요.'}
              </p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2`}>
              <Key size={16} /> API 키 설정
            </button>
            <button onClick={() => { setIsMockMode(true); setApiErrorType(null); }} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all">
              데모 모드로 전환
            </button>
          </div>
        </div>
      )}

      <div className="mb-5">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <div className="d-flex align-items-center gap-3">
            <div className="bg-blue-600/30 p-2 rounded-xl border border-blue-500/30"><RefreshCw className={`text-blue-400 ${loadingSuggestions ? 'animate-spin' : ''}`} size={20} /></div>
            <div>
