                              <button 
                                onClick={handleDeleteSaved}
                                className="btn btn-outline-danger px-4 py-2 rounded-xl font-bold flex items-center gap-2 transition-all"
                                title="영구 삭제"
                              >
                                <Trash2 size={18} /> 영구 삭제
