            </div>
            <div className="flex gap-4">
               <span className="text-[9px] text-slate-500 flex items-center gap-1"><FileText size={10}/> 기사 관리 활성</span>
               <span className="text-[9px] text-slate-500 flex items-center gap-1"><UserX size={10}/> 계정 관리 활성</span>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="glass-card p-3 rounded-2xl border-slate-800 flex items-center gap-3 bg-slate-900/40">
