              disabled={loading || !input.trim()}
              className="p-2 text-red-500 hover:text-red-400 transition-colors disabled:opacity-30"
            >
              <Send size={20} />
            </button>
          </div>
          <div className="mt-2 flex items-center justify-between px-2">
            <div className="flex items-center gap-2">
              <AlertCircle size={10} className="text-red-500" />
              <span className="text-[9px] text-slate-600 font-bold uppercase tracking-widest">관리자 로그 기록 중</span>
            </div>
            <div className="flex gap-4">
               <span className="text-[9px] text-slate-500 flex items-center gap-1"><FileText size={10}/> 기사 관리 활성</span>
