// Add React import to resolve missing React namespace errors for MouseEvent
import React, { useState, useEffect } from 'react';
import { Trash2, Calendar, X, FileText, Image as ImageIcon, ExternalLink, Filter, AlertTriangle, FileCheck } from 'lucide-react';

const Dashboard = () => {
  const [activeTab, setActiveTab] = useState<'articles' | 'images'>('articles');
  const [articles, setArticles] = useState<any[]>([]);
  const [images, setImages] = useState<any[]>([]);
  const [selectedItem, setSelectedItem] = useState<any | null>(null);

  const loadData = () => {
    try {
      const savedArticles = JSON.parse(localStorage.getItem('my_articles') || '[]');
      const savedImages = JSON.parse(localStorage.getItem('my_images') || '[]');
      setArticles(savedArticles);
      setImages(savedImages);
    } catch (e) {
      console.error("Dashboard data load failed:", e);
    }
  };

  useEffect(() => {
    loadData();
    // 데이터 동기화를 위해 주기적으로 로드 (다른 탭에서의 변경 사항 반영)
    const interval = setInterval(loadData, 2000);
    return () => clearInterval(interval);
  }, []);

  const deleteArticle = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 영구적으로 삭제하시겠습니까?")) return;
    const updated = articles.filter(item => item.id !== id);
    localStorage.setItem('my_articles', JSON.stringify(updated));
    setArticles(updated);
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const deleteImage = (id: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 이미지를 영구적으로 삭제하시겠습니까?")) return;
    const updated = images.filter(item => item.id !== id);
    localStorage.setItem('my_images', JSON.stringify(updated));
    setImages(updated);
  };

  const clearAll = () => {
    const targetName = activeTab === 'articles' ? '기사 전체' : '이미지 전체';
    if (!window.confirm(`${targetName}를 정말로 모두 영구 삭제하시겠습니까?`)) return;

    if (activeTab === 'articles') {
      localStorage.setItem('my_articles', '[]');
      setArticles([]);
      setSelectedItem(null);
    } else {
      localStorage.setItem('my_images', '[]');
      setImages([]);
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="d-flex justify-content-between align-items-end mb-5">
