import { Calendar, Clock, ChevronRight, Share2, MessageCircle, Heart, Newspaper, Trash2, Send, ShieldCheck, Award } from 'lucide-react';

const LoadingSpinnerIcon = ({ size, className }: { size: number, className: string }) => (
