import React, { useState, useEffect } from 'react';
import { Trash2, Calendar, X, FileText, Image as ImageIcon, ExternalLink, AlertTriangle, FileCheck, Award, Share2, ArrowUpRight } from 'lucide-react';

const Dashboard = () => {
  const [activeTab, setActiveTab] = useState<'articles' | 'images'>('articles');
  const [articles, setArticles] = useState<any[]>([]);
  const [images, setImages] = useState<any[]>([]);
  const [selectedItem, setSelectedItem] = useState<any | null>(null);

  const loadData = () => {
    try {
      const savedArticles = JSON.parse(localStorage.getItem('my_articles') || '[]');
      const savedImages = JSON.parse(localStorage.getItem('my_images') || '[]');
      // 이미 저장된 데이터가 최신순으로 오도록 정렬 (혹시 모를 대비)
      setArticles(savedArticles);
      setImages(savedImages);
    } catch (e) {
      console.error("Dashboard data load failed:", e);
    }
  };

  useEffect(() => {
    loadData();
    const interval = setInterval(loadData, 2000);
    return () => clearInterval(interval);
  }, []);

  // Fixed setSelectedArticle error: using correct state setter setSelectedItem
  const deleteArticle = (id: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    if (!window.confirm("이 기사를 영구적으로 삭제하시겠습니까?")) return;
    const updated = articles.filter(item => item.id !== id);
    localStorage.setItem('my_articles', JSON.stringify(updated));
    setArticles(updated);
    if (selectedItem?.id === id) setSelectedItem(null);
  };

  const clearAll = () => {
    const targetName = activeTab === 'articles' ? '기사 전체' : '이미지 전체';
    if (!window.confirm(`${targetName}를 정말로 모두 영구 삭제하시겠습니까?`)) return;

    if (activeTab === 'articles') {
      localStorage.setItem('my_articles', '[]');
      setArticles([]);
      setSelectedItem(null);
    } else {
      localStorage.setItem('my_images', '[]');
      setImages([]);
    }
  };

  const latestArticle = articles.length > 0 ? articles[0] : null;
  const otherArticles = articles.length > 1 ? articles.slice(1) : [];

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="d-flex justify-content-between align-items-end mb-5">
        <div>
          <h2 className="fw-black mb-1 tracking-tighter flex items-center gap-2">
            <Award className="text-blue-500" /> 통합 미디어 대시보드
          </h2>
          <p className="text-slate-500 text-sm m-0">AI 편집국에서 생성된 프리미엄 뉴스 자산을 관리합니다.</p>
        </div>
        <div className="d-flex align-items-center gap-3">
           {(activeTab === 'articles' ? articles.length > 0 : images.length > 0) && (
             <button 
               onClick={clearAll} 
               className="btn btn-outline-danger btn-sm rounded-xl px-3 py-2 d-flex align-items-center gap-2 font-bold border-0 bg-red-500/10 hover:bg-red-500/20"
             >
               <AlertTriangle size={14} /> 전체 삭제
             </button>
           )}
           <div className="d-flex gap-2 bg-slate-900/50 p-1.5 rounded-2xl border border-slate-800">
            <button 
              onClick={() => setActiveTab('articles')}
              className={`px-4 py-2 rounded-xl text-xs font-black transition-all border-0 ${activeTab === 'articles' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300 bg-transparent'}`}
            >
              기사 ({articles.length})
            </button>
            <button 
              onClick={() => setActiveTab('images')}
              className={`px-4 py-2 rounded-xl text-xs font-black transition-all border-0 ${activeTab === 'images' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300 bg-transparent'}`}
            >
              이미지 ({images.length})
            </button>
          </div>
        </div>
      </div>

      {activeTab === 'articles' ? (
        <div className="articles-newspaper-layout">
          {articles.length === 0 ? (
            <EmptyState message="저장된 기사가 없습니다. AI Writer에서 첫 번째 기사를 발행해보세요!" icon={<FileText size={48} />} />
          ) : (
            <div className="space-y-8">
              {/* Hero Featured Article (Latest) */}
              {latestArticle && (
                <div 
                  className="hero-article-card group cursor-pointer"
                  onClick={() => setSelectedItem(latestArticle)}
                >
                  <div className="row g-0 bg-slate-900 rounded-[32px] overflow-hidden border border-slate-800 hover:border-blue-500/50 transition-all shadow-2xl">
                    <div className="col-lg-7 position-relative overflow-hidden">
                      {latestArticle.image ? (
                        <img src={latestArticle.image} alt="main" className="w-100 h-100 object-cover group-hover:scale-105 transition-transform duration-1000 min-h-[450px]" />
                      ) : (
                        <div className="w-100 h-100 bg-slate-950 flex items-center justify-center text-slate-800 min-h-[450px]"><FileText size={80} /></div>
                      )}
                      <div className="absolute top-6 left-6 flex gap-2">
                        <span className="bg-red-600 text-white px-3 py-1 rounded-full text-[10px] font-black tracking-widest animate-pulse shadow-lg">LATEST</span>
