                        <Calendar size={14} /> {latestArticle.date}
                      </div>
                      <h1 className="display-4 fw-black text-white tracking-tighter mb-5 group-hover:text-blue-400 transition-colors leading-[1.1]">{latestArticle.title}</h1>
                      <p className="text-slate-400 text-lg leading-relaxed line-clamp-4 mb-8 opacity-70">
