                      <div className="flex items-center justify-between mt-auto pt-8 border-t border-slate-800">
                        <div className="flex items-center gap-3">
                          <span className="bg-green-500/10 text-green-500 text-[10px] font-black px-2 py-1 rounded border border-green-500/20 flex items-center gap-1">
                            <FileCheck size={12} /> AI VERIFIED
                          </span>
                        </div>
                        <button className="text-white font-bold flex items-center gap-2 group-hover:gap-4 transition-all border-0 bg-transparent p-0">
