                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {/* Other Articles Grid */}
              {otherArticles.length > 0 && (
                <div className="row g-4 pt-4">
                  <div className="col-12 mb-2">
                    <h5 className="text-slate-500 font-black uppercase tracking-widest text-xs flex items-center gap-3">
                      <div className="h-[1px] flex-grow bg-slate-800"></div>
