);

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { generateFactBasedArticle, generateImage, generateCoverageSuggestions } from '../services/gemini';
import { Sparkles, Save, Loader2, FileText, Cpu, RefreshCw, AlertCircle, ArrowRight, Link, Trash2, Quote, Maximize2, X, Key, Zap, ShieldAlert, CheckCircle } from 'lucide-react';

interface AIWriterProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

interface Suggestion {
  id: string;
  title: string;
  category: string;
  angle: string;
  urgency: string;
}

const AIWriter: React.FC<AIWriterProps> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState(() => localStorage.getItem('donga_writer_topic') || "");
  const [category, setCategory] = useState(() => localStorage.getItem('donga_writer_category') || "social");
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const [articleData, setArticleData] = useState<any | null>(() => {
    const saved = localStorage.getItem('donga_writer_article');
    try {
      return saved ? JSON.parse(saved) : null;
    } catch {
      return null;
    }
  });
  const [imageResult, setImageResult] = useState<string | null>(() => localStorage.getItem('donga_writer_image'));
  const [loading, setLoading] = useState(false);
  const [statusText, setStatusText] = useState(""); 
  const [errorMsg, setErrorMsg] = useState("");
  const [isZoomed, setIsZoomed] = useState(false);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);
  const [isSaved, setIsSaved] = useState(false);

  // 현재 생성된 기사(articleData.id)가 대시보드(my_articles)에 이미 들어있는지 확인
  const checkIfSaved = useCallback(() => {
    if (!articleData || !articleData.id) {
      setIsSaved(false);
      return;
    }
    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const isAlready = saved.some((a: any) => a.id === articleData.id);
      setIsSaved(isAlready);
    } catch (e) {
      setIsSaved(false);
    }
  }, [articleData]);

  useEffect(() => {
    checkIfSaved();
  }, [checkIfSaved, articleData]);

  // 임시 작업 내용 브라우저 세션 유지
  useEffect(() => {
    try {
      localStorage.setItem('donga_writer_topic', topic);
      localStorage.setItem('donga_writer_category', category);
      if (articleData) {
        localStorage.setItem('donga_writer_article', JSON.stringify(articleData));
      } else {
        localStorage.removeItem('donga_writer_article');
      }
      if (imageResult) {
        localStorage.setItem('donga_writer_image', imageResult);
      } else {
        localStorage.removeItem('donga_writer_image');
      }
    } catch (e) {}
  }, [topic, category, articleData, imageResult]);

  const fetchSuggestions = useCallback(async () => {
    setLoadingSuggestions(true);
    setApiErrorType(null);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data || []);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      if (e.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
    } finally {
      setLoadingSuggestions(false);
    }
  }, [isMockMode]);

  useEffect(() => {
    fetchSuggestions();
  }, [fetchSuggestions]);

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      window.location.reload();
    }
  };

  const handleReset = () => {
    if (window.confirm("작성 중인 내용을 초기화하시겠습니까? (이미 대시보드에 저장된 기사는 삭제되지 않습니다)")) {
      setTopic("");
      setArticleData(null);
      setImageResult(null);
      setIsSaved(false);
      localStorage.removeItem('donga_writer_article');
      localStorage.removeItem('donga_writer_image');
      localStorage.removeItem('donga_writer_topic');
    }
  };

  const handleFullCreation = async () => {
    if (!topic.trim()) {
        alert("기사 주제를 입력해주세요!");
        return;
    }
    setLoading(true);
    setErrorMsg("");
    setApiErrorType(null);
    setIsSaved(false);

    try {
      setStatusText("실시간 데이터 검색 및 팩트체크 중... 🔍");
      const result = await generateFactBasedArticle(topic, category, isMockMode);

      // ✅ [중요] 생성 시마다 완전히 새로운 고유 ID를 부여하여 '누적'이 가능하게 함
      const newArticleId = `art_${Date.now()}_${Math.floor(Math.random() * 10000)}`;

      const newArticleData = {
        id: newArticleId,
        title: result.title || topic,
        summary: result.summary || "",
        content: result.content || "",
        category: result.category || category,
        factCheck: result.factCheck || "AI 정밀 검증 완료",
        sources: result.sources || [],
        searchSources: result.searchSources,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString()
      };

      setArticleData(newArticleData);

      setStatusText("기사 이미지 생성 중... 📸");
      const imgUrl = await generateImage(result.imageKeyword || topic, isMockMode);
      setImageResult(imgUrl);
    } catch (e: any) {
      if (e.message === "QUOTA_EXCEEDED") {
        setApiErrorType("QUOTA");
        setErrorMsg("API 할당량이 초과되었습니다.");
      } else if (e.message === "PERMISSION_DENIED") {
        setApiErrorType("PERMISSION");
        setErrorMsg("API 키 권한 오류가 발생했습니다.");
      } else {
        setErrorMsg("데이터 수집 중 문제가 발생했습니다.");
      }
    } finally {
      setLoading(false);
      setStatusText("");
    }
  };

  const handleSaveToDashboard = () => {
    if (!articleData) return;

    try {
      // ✅ 1. [사용자 제안 방식] 저장소(금고) 문을 열어서 직접 확인합니다. (상태값 의존 배제)
      const savedRaw = localStorage.getItem('my_articles');
      const currentArticles = savedRaw ? JSON.parse(savedRaw) : [];

      // 2. 중복 저장 방지 (이미 같은 ID가 있다면 중단)
      if (currentArticles.some((a: any) => a.id === articleData.id)) {
        alert("이미 대시보드에 저장된 기사입니다.");
        setIsSaved(true);
        return;
      }

      // 3. 현재 기사와 이미지를 합쳐서 최종 데이터 준비
      const newArticleToSave = {
        ...articleData,
        image: imageResult
      };

      // 4. 가져온 목록(currentArticles) 맨 앞에 새 기사를 붙입니다.
      const updatedList = [newArticleToSave, ...currentArticles];

      // 5. 다시 금고에 넣습니다.
      try {
        localStorage.setItem('my_articles', JSON.stringify(updatedList));
        setIsSaved(true);
        alert("✅ 기사가 대시보드에 성공적으로 누적되었습니다!\n기획실(Dashboard)에서 확인하세요.");
      } catch (e: any) {
        if (e.name === 'QuotaExceededError' || e.code === 22) {
          alert("❌ 저장 공간이 가득 찼습니다!\n\n대시보드에서 불필요한 기사를 삭제한 후 다시 시도해 주세요.");
        } else {
          alert("저장 중 알 수 없는 오류가 발생했습니다.");
        }
      }
    } catch (err: any) {
      console.error("Save failed:", err);
    }
  };

  const handleDeleteFromDashboard = () => {
    if (!articleData || !articleData.id) return;
    if (!window.confirm("대시보드에서 이 기사를 영구 삭제하시겠습니까?")) return;

    try {
      const savedRaw = localStorage.getItem('my_articles');
      const saved = savedRaw ? JSON.parse(savedRaw) : [];
      const updated = saved.filter((a: any) => a.id !== articleData.id);
      localStorage.setItem('my_articles', JSON.stringify(updated));
      setIsSaved(false);
      alert("🗑️ 대시보드에서 해당 기사가 삭제되었습니다.");
    } catch (e) {
      console.error(e);
    }
  };

  const handleQuickStart = (item: Suggestion) => {
    setTopic(item.title);
    const cat = item.category.toLowerCase();
    if (cat.includes('it') || cat.includes('tech')) setCategory('tech');
    else if (cat.includes('econ')) setCategory('economy');
    else if (cat.includes('polit')) setCategory('politics');
    else setCategory('social');
    window.scrollTo({ top: 450, behavior: 'smooth' });
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      {isZoomed && imageResult && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-fade-in cursor-zoom-out" onClick={() => setIsZoomed(false)}>
          <button className="absolute top-8 right-8 text-white/50 hover:text-white border-0 bg-transparent"><X size={40} /></button>
          <img src={imageResult} alt="Expanded News" className="max-w-[90vw] max-h-[85vh] object-contain rounded-2xl shadow-2xl animate-scale-up" />
        </div>
      )}

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-400 animate-pulse" />}
            </div>
            <div>
              <p className={`font-bold m-0 text-lg ${apiErrorType === 'PERMISSION' ? 'text-red-200' : 'text-amber-200'}`}>
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : 'AI 서비스 할당량 도달'}
              </p>
              <p className="text-sm m-0 opacity-80">개인 API 키를 설정하거나 데모 모드를 활성화하세요.</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2 border-0`}>
              <Key size={16} /> API 키 설정
            </button>
            <button onClick={() => { setIsMockMode(true); setApiErrorType(null); }} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all border-0">
              데모 모드로 전환
            </button>
          </div>
        </div>
      )}

      <div className="mb-5">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <div className="d-flex align-items-center gap-3">
            <div className="bg-blue-600/30 p-2 rounded-xl border border-blue-500/30"><RefreshCw className={`text-blue-400 ${loadingSuggestions ? 'animate-spin' : ''}`} size={20} /></div>
            <div>
              <h4 className="fw-black m-0 tracking-tighter flex items-center gap-2">실시간 취재 브리핑 <span className="badge bg-red-600 px-2 py-0.5 animate-pulse text-[10px] rounded">HOT</span></h4>
              <p className="text-[11px] text-slate-500 m-0">현재 온라인 트렌드 기반 취재 제안입니다.</p>
            </div>
          </div>
          <button onClick={handleReset} className="btn btn-outline-slate-700 btn-sm text-[10px] fw-bold d-flex align-items-center gap-2 px-3 py-2 rounded-xl"><Trash2 size={14} /> 초기화</button>
        </div>
        <div className="row g-3">
          {loadingSuggestions ? Array.from({ length: 4 }).map((_, i) => <div key={i} className="col-md-3"><div className="glass-card p-4 rounded-2xl border-slate-800 animate-pulse h-[140px]"></div></div>) : suggestions.map((item) => (
            <div key={item.id} className="col-md-3">
              <div className="glass-card p-4 rounded-2xl border-slate-800 h-100 hover:border-blue-500/50 hover:bg-slate-800/60 transition-all cursor-pointer group flex flex-col justify-between shadow-xl" onClick={() => handleQuickStart(item)}>
                <div>
                  <div className="d-flex justify-content-between mb-3"><span className="badge bg-red-600/20 text-red-500 border border-red-500/30 text-[9px] px-2 py-1 font-black uppercase">{item.urgency}</span><span className="text-[10px] text-blue-400 font-black uppercase tracking-widest">{item.category}</span></div>
                  <h6 className="text-white fw-bold text-sm mb-2 group-hover:text-blue-400 leading-snug line-clamp-2">{item.title}</h6>
                </div>
                <div className="pt-3 border-t border-slate-800/50 mt-3 flex justify-between items-center"><span className="text-[10px] text-slate-500 italic">"{item.angle}"</span><ArrowRight size={14} className="text-blue-500 group-hover:translate-x-1 transition-transform" /></div>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl relative overflow-hidden" style={{ background: 'rgba(15, 23, 42, 0.95)' }}>
        <h2 className="fw-black mb-4 tracking-tighter d-flex align-items-center gap-3 text-white"><div className="bg-primary/20 p-2 rounded-xl"><Sparkles className="text-primary" size={24} /></div>AI 팩트체크 리포트 생성</h2>
        <div className="row g-3">
          <div className="col-md-2"><select className="form-select !bg-slate-950 border-slate-800 rounded-xl py-3 text-white" value={category} onChange={(e) => setCategory(e.target.value)}><option value="social">사회</option><option value="politics">정치</option><option value="economy">경제</option><option value="tech">IT/과학</option></select></div>
          <div className="col-md-8"><input className="form-control fs-5 !bg-slate-950 border-slate-800 rounded-xl py-3 px-4 text-white" placeholder="기사 주제를 입력하세요 (예: 한국 반도체 수출 현황...)" value={topic} onChange={(e) => setTopic(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && handleFullCreation()} /></div>
          <div className="col-md-2 pt-1"><button className="btn btn-primary w-100 py-3 rounded-xl fw-black shadow-lg flex items-center justify-center gap-2" onClick={handleFullCreation} disabled={loading}>{loading ? <Loader2 className="animate-spin" size={20}/> : <Cpu size={18}/>}리포트 생성</button></div>
        </div>
        {(loading || errorMsg) && (
            <div className={`mt-5 p-4 rounded-2xl border font-bold text-center animate-fade-in ${errorMsg ? 'bg-red-500/10 border-red-500/30 text-red-400' : 'bg-blue-500/10 border-blue-500/30 text-blue-300'}`}>
                {errorMsg ? <AlertCircle size={20} className="inline me-2"/> : <div className="spinner-border spinner-border-sm me-3"></div>}
                {errorMsg || statusText}
            </div>
        )}
      </div>

      {articleData && (
        <div className="row g-4 animate-fade-in pb-5">
            <div className="col-lg-3">
              <div className="glass-card p-4 rounded-4 border-slate-800 h-100 shadow-xl" style={{ background: '#0f172a' }}>
                <h6 className="text-blue-400 fw-bold mb-4 flex items-center gap-2 text-sm uppercase tracking-widest"><Link size={16} /> 취재 원천 소스</h6>
                <div className="d-flex flex-column gap-3">
                  {articleData.searchSources?.length > 0 ? articleData.searchSources.map((source: any, i: number) => (
                    <a key={i} href={source.uri} target="_blank" rel="noopener noreferrer" className="glass-card p-3 rounded-xl border-slate-800 text-slate-400 text-xs hover:text-blue-400 no-underline transition-all flex flex-col gap-2 group hover:bg-slate-800/50">
                      <div className="text-white font-bold line-clamp-2 group-hover:text-blue-400">{source.title}</div>
                      <div className="text-[9px] opacity-40 truncate flex items-center gap-1"><Link size={10} /> {source.uri}</div>
                    </a>
                  )) : (
                    <div className="text-[10px] text-slate-600 italic">교차 검증된 데이터가 표시됩니다.</div>
                  )}
                </div>
              </div>
            </div>
            <div className="col-lg-6">
                <div className="glass-card p-5 rounded-4 h-100 border-0 shadow-2xl overflow-hidden" style={{ background: '#0f172a' }}>
                    <div className="d-flex justify-content-between align-items-start mb-4">
                      <h1 className="fw-black text-white display-5 tracking-tighter m-0">{articleData.title}</h1>
                      <div className="flex gap-2 shrink-0">
                        {!isSaved ? (
                          <button 
                            onClick={handleSaveToDashboard} 
                            className="btn btn-primary px-4 py-2 rounded-xl font-bold flex items-center gap-2 transition-all shadow-lg border-0"
                          >
                            <Save size={18} /> 대시보드 저장
                          </button>
                        ) : (
                          <div className="flex gap-2">
                             <button 
                                className="btn btn-success px-4 py-2 rounded-xl font-bold flex items-center gap-2 transition-all cursor-default border-0"
                                disabled
                              >
                                <CheckCircle size={18} /> 저장 완료
                              </button>
                              <button 
                                onClick={handleDeleteFromDashboard}
                                className="btn btn-outline-danger px-4 py-2 rounded-xl font-bold flex items-center gap-2 transition-all border-0"
                                title="대시보드에서 삭제"
                              >
                                <Trash2 size={18} />
                              </button>
                          </div>
                        )}
                      </div>
                    </div>
                    <div className="text-slate-200 article-body" style={{ fontSize: '1.2rem', lineHeight: '2.0' }} dangerouslySetInnerHTML={{ __html: articleData.content }} />
                </div>
            </div>
            <div className="col-lg-3">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-4 border-0 shadow-xl" style={{ background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)' }}>
                        <h6 className="text-blue-400 font-black mb-3 flex items-center gap-2 text-xs uppercase tracking-widest"><Quote size={14} /> AI 에디토리얼 요약</h6>
                        <div className="text-slate-300 leading-relaxed text-sm font-medium bg-slate-950/40 p-3 rounded-xl border border-slate-800">{articleData.summary}</div>
                    </div>
                    <div className="glass-card p-4 rounded-4 border-slate-800 shadow-lg overflow-hidden group/img" style={{ background: '#1e293b' }}>
                        <div className="position-relative bg-slate-950 rounded-xl overflow-hidden border border-slate-800 cursor-zoom-in" style={{ aspectRatio: '16/9' }} onClick={() => setIsZoomed(true)}>
                            {imageResult ? <><img src={imageResult} alt="News" className="w-full h-full object-cover group-hover/img:scale-105 transition-all duration-500"/><div className="absolute inset-0 bg-black/0 group-hover/img:bg-black/20 flex items-center justify-center opacity-0 group-hover/img:opacity-100"><Maximize2 size={24} className="text-white" /></div></> : <div className="h-full flex flex-col items-center justify-center opacity-20"><Loader2 className="animate-spin mb-2" size={24}/><p className="text-[9px] font-bold">이미지 생성 대기 중</p></div>}
                        </div>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default AIWriter;

