// Refine initialization to follow SDK guidelines strictly
import { GoogleGenAI, Type, Modality } from "@google/genai";

const extractJson = (text: string) => {
  try {
    let cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBrace = cleanText.indexOf('{');
    const firstBracket = cleanText.indexOf('[');
    let startIdx = -1;
    let endIdx = -1;
    if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
      startIdx = firstBrace;
      endIdx = cleanText.lastIndexOf('}');
    } else if (firstBracket !== -1) {
      startIdx = firstBracket;
      endIdx = cleanText.lastIndexOf(']');
    }
    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      return cleanText.substring(startIdx, endIdx + 1);
    }
    return cleanText;
  } catch (e) {
    return text;
  }
};

/**
 * API 호출 재시도 로직 (지수 백오프)
 */
const callWithRetry = async (fn: () => Promise<any>, maxRetries = 3): Promise<any> => {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorStr = JSON.stringify(error);

      if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED') || errorStr.includes('API_KEY_HTTP_REFERRER_BLOCKED')) {
        throw error;
      }

      if (errorStr.includes('429') || errorStr.includes('RESOURCE_EXHAUSTED')) {
        const delay = Math.pow(2, i) * 1000;
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
};

// 가이드라인 준수: 매 호출마다 새로운 인스턴스를 생성하여 최신 API 키 반영 및 세션 독립성 유지
const createAI = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const handleAIError = (error: any) => {
  console.error("Gemini API Error Detail:", error);
  const errorStr = typeof error === 'string' ? error : JSON.stringify(error);

  if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED') || errorStr.includes('API_KEY_HTTP_REFERRER_BLOCKED')) {
    throw new Error("PERMISSION_DENIED");
