      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="glass-card p-3 rounded-2xl border-slate-800 flex items-center gap-3 bg-slate-900/40">
          <div className="bg-red-500/10 p-2 rounded-lg"><Trash2 size={16} className="text-red-500" /></div>
          <div>
            <p className="text-[10px] text-slate-500 m-0 font-bold">기사 삭제</p>
            <p className="text-xs font-black m-0 text-white">GRANT ALL</p>
          </div>
        </div>
        <div className="glass-card p-3 rounded-2xl border-slate-800 flex items-center gap-3 bg-slate-900/40">
          <div className="bg-blue-500/10 p-2 rounded-lg"><UserX size={16} className="text-blue-500" /></div>
          <div>
            <p className="text-[10px] text-slate-500 m-0 font-bold">회원 관리</p>
            <p className="text-xs font-black m-0 text-white">READY</p>
