import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Image as ImageIcon, Save, Loader2, Zap, LayoutDashboard, Key, ShieldAlert, CheckCircle } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIIllustrator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [prompt, setPrompt] = useState("");
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [apiErrorType, setApiErrorType] = useState<string | null>(null);
  const [isSaved, setIsSaved] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;

    // 1. 시작할 때 로딩 상태 설정
    setLoading(true);
    setApiErrorType(null);
    setIsSaved(false);

    try {
      // 2. 서비스 내부에서 새로운 AI 인스턴스를 통해 생성 (fresh state)
      const imgUrl = await generateImage(prompt, isMockMode);
      setImage(imgUrl);
    } catch (e: any) {
      console.error("이미지 생성 오류:", e);
      if (e.message === "QUOTA_EXCEEDED") setApiErrorType("QUOTA");
      else if (e.message === "PERMISSION_DENIED") setApiErrorType("PERMISSION");
      else alert("이미지 생성 중 오류가 발생했습니다. 다시 시도해 주세요.");
    } finally {
      // ✅ [핵심] 성공/실패 여부와 관계없이 무조건 로딩 해제 (UI 멈춤 방지)
      setLoading(false);
    }
  };

  const handleOpenKeySelector = async () => {
    if (window.aistudio && window.aistudio.openSelectKey) {
      await window.aistudio.openSelectKey();
      window.location.reload();
    }
  };

  const handleSaveToDashboard = () => {
    if (!image) return;
    try {
      // ✅ 금고(LocalStorage) 직접 확인 패턴 (누적 저장 보장 및 용량 관리)
      const savedRaw = localStorage.getItem('my_images');
      let currentList = savedRaw ? JSON.parse(savedRaw) : [];

      const newImage = {
        id: Date.now(),
        prompt: prompt,
        url: image,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      };

      // 1. 최신 이미지를 리스트의 가장 앞에 추가
      let updatedList = [newImage, ...currentList];

      // 2. 이미지 base64는 용량이 매우 크므로 갤러리는 최대 10장으로 엄격히 제한
      if (updatedList.length > 10) {
        updatedList = updatedList.slice(0, 10);
      }

      // 3. 안전하게 저장 시도 (성공할 때까지 재귀적으로 Pruning)
      const attemptSave = (list: any[]): boolean => {
        try {
          localStorage.setItem('my_images', JSON.stringify(list));
          console.log("Image Storage Sync Success! Count:", list.length);
          return true;
        } catch (e: any) {
          if (e.name === 'QuotaExceededError' && list.length > 1) {
            console.warn("Image Quota Exceeded. Pruning oldest image...");
            return attemptSave(list.slice(0, -1)); // 마지막 항목 삭제 후 재시도
          }
          return false;
        }
      };

      const success = attemptSave(updatedList);
      if (success) {
        setIsSaved(true);
        alert("✅ 이미지가 대시보드 포토 갤러리에 추가되었습니다.");
      } else {
        alert("저장 공간이 부족합니다. 대시보드 포토 갤러리에서 오래된 사진을 삭제해주세요.");
      }
    } catch (err: any) {
      alert("저장 중 오류가 발생했습니다.");
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="mb-5">
        <h2 className="fw-black mb-1 tracking-tighter">🎨 AI 일러스트레이터</h2>
        <p className="text-slate-500 text-sm m-0">기사 보충용 고퀄리티 일러스트를 생성합니다.</p>
      </div>

      {apiErrorType && (
        <div className={`glass-card p-4 rounded-2xl mb-5 flex items-center justify-between backdrop-blur-md ${apiErrorType === 'PERMISSION' ? 'bg-red-500/10 border-red-500/50' : 'bg-amber-500/10 border-amber-500/50'}`}>
          <div className="flex items-center gap-4">
            <div className={`p-3 rounded-full ${apiErrorType === 'PERMISSION' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}>
              {apiErrorType === 'PERMISSION' ? <ShieldAlert size={24} className="text-red-500" /> : <Zap size={24} className="text-amber-400" />}
            </div>
            <div>
              <p className={`font-bold m-0 text-lg ${apiErrorType === 'PERMISSION' ? 'text-red-200' : 'text-amber-200'}`}>
                {apiErrorType === 'PERMISSION' ? 'API 접근 권한 오류' : 'AI 할당량 초과'}
              </p>
              <p className="text-sm m-0 opacity-80">개인 API 키를 설정하거나 데모 모드를 활성화하세요.</p>
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleOpenKeySelector} className={`${apiErrorType === 'PERMISSION' ? 'bg-red-600 hover:bg-red-500' : 'bg-amber-500 hover:bg-amber-400'} text-white px-4 py-2 rounded-xl font-bold transition-all flex items-center gap-2 border-0`}>
              <Key size={16} /> API 키 설정
            </button>
            <button onClick={() => { setIsMockMode(true); setApiErrorType(null); }} className="bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all border-0">
              데모 모드로 전환
            </button>
          </div>
        </div>
      )}

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl bg-slate-900/90">
        <label className="text-slate-500 text-[10px] font-black mb-3 block uppercase tracking-widest">일러스트 프롬프트</label>
        <div className="input-group">
          <input 
            type="text" 
            className="form-control !bg-slate-950 border-slate-800 text-white py-3 px-4 rounded-s-xl" 
            placeholder="필요한 이미지를 설명하세요..."
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
          />
          <button className="btn btn-primary px-5 fw-bold rounded-e-xl" onClick={handleGenerate} disabled={loading}>
            {loading ? <Loader2 className="animate-spin" /> : "이미지 생성"}
          </button>
        </div>
      </div>

      <div className="d-flex justify-content-center align-items-center bg-slate-950/50 rounded-4 border border-slate-800 p-5 min-h-[500px] shadow-inner relative overflow-hidden">
        {loading ? (
          <div className="text-center">
            <Loader2 className="animate-spin mb-3 text-blue-500" size={48} />
            <p className="fw-black tracking-widest text-slate-500">생성 중...</p>
          </div>
        ) : image ? (
          <div className="text-center w-100 animate-scale-up">
            <img src={image} alt="Generated" className="img-fluid rounded-4 shadow-2xl mb-4 max-h-[500px] border border-slate-800" />
            <div className="d-flex justify-content-center gap-3">
              <button 
                className={`btn ${isSaved ? 'btn-success' : 'btn-outline-light'} px-5 py-3 rounded-2xl fw-black flex items-center gap-2 transition-all border-0`} 
                onClick={handleSaveToDashboard}
                disabled={isSaved}
              >
                {isSaved ? <CheckCircle size={20} /> : <LayoutDashboard size={20} />}
                {isSaved ? "저장 완료" : "대시보드에 저장"}
              </button>
              <a href={image} download="ai-news-img.png" className="btn btn-outline-slate-700 px-5 py-3 rounded-2xl fw-black flex items-center gap-2">
                다운로드
              </a>
            </div>
          </div>
        ) : (
          <div className="text-center opacity-20">
            <ImageIcon size={80} className="mb-3 mx-auto" />
            <p className="fw-black">프롬프트를 입력하세요</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIIllustrator;

