                    <div className="text-slate-200 article-body" style={{ fontSize: '1.2rem', lineHeight: '2.0' }} dangerouslySetInnerHTML={{ __html: articleData.content }} />
                </div>
            </div>
            <div className="col-lg-3">
                <div className="d-flex flex-column gap-4 h-100">
                    <div className="glass-card p-4 rounded-4 border-0 shadow-xl" style={{ background: 'linear-gradient(135deg, #1e293b 0%, #0f172a 100%)' }}>
                        <h6 className="text-blue-400 font-black mb-3 flex items-center gap-2 text-xs uppercase tracking-widest"><Quote size={14} /> 요약</h6>
                        <div className="text-slate-300 leading-relaxed text-sm font-medium bg-slate-950/40 p-3 rounded-xl border border-slate-800">{articleData.summary}</div>
                    </div>
                    <div className="glass-card p-4 rounded-4 border-slate-800 shadow-lg overflow-hidden group/img" style={{ background: '#1e293b' }}>
                        <div className="position-relative bg-slate-950 rounded-xl overflow-hidden border border-slate-800 cursor-zoom-in" style={{ aspectRatio: '16/9' }} onClick={() => setIsZoomed(true)}>
                            {imageResult ? <><img src={imageResult} alt="News" className="w-full h-full object-cover group-hover/img:scale-105 transition-all duration-500"/><div className="absolute inset-0 bg-black/0 group-hover/img:bg-black/20 flex items-center justify-center opacity-0 group-hover/img:opacity-100"><Maximize2 size={24} className="text-white" /></div></> : <div className="h-full flex flex-col items-center justify-center opacity-20"><Loader2 className="animate-spin mb-2" size={24}/><p className="text-[9px] font-bold">이미지 생성 중</p></div>}
                        </div>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default AIWriter;

import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Image as ImageIcon, Save, Loader2, Zap, LayoutDashboard, Key, ShieldAlert, CheckCircle } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIIllustrator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [prompt, setPrompt] = useState("");
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setIsSaved(false);
    try {
      const imgUrl = await generateImage(prompt, isMockMode);
      setImage(imgUrl);
    } catch (e: any) {
      console.error("이미지 생성 오류:", e);
      alert("이미지 생성 중 오류가 발생했습니다. AI 할당량을 확인해 주세요.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToDashboard = () => {
    if (!image) return;
    try {
      const savedRaw = localStorage.getItem('my_images');
      let currentList = savedRaw ? JSON.parse(savedRaw) : [];
      const newImage = {
        id: Date.now(),
        prompt: prompt,
        url: image,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      };
      let updatedList = [newImage, ...currentList];
      if (updatedList.length > 10) {
        updatedList = updatedList.slice(0, 10);
      }
      const attemptSave = (list: any[]): boolean => {
        try {
          localStorage.setItem('my_images', JSON.stringify(list));
          return true;
        } catch (e: any) {
          if (e.name === 'QuotaExceededError' && list.length > 1) {
            return attemptSave(list.slice(0, -1));
          }
          return false;
        }
      };
      const success = attemptSave(updatedList);
      if (success) {
        setIsSaved(true);
        alert("✅ 이미지가 대시보드 포토 갤러리에 추가되었습니다.");
      } else {
        alert("저장 공간이 부족합니다. 대시보드 포토 갤러리에서 오래된 사진을 삭제해주세요.");
      }
    } catch (err: any) {
      alert("저장 중 오류가 발생했습니다.");
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="mb-5">
        <h2 className="fw-black mb-1 tracking-tighter">🎨 AI 일러스트레이터</h2>
        <p className="text-slate-500 text-sm m-0">기사 보충용 고퀄리티 일러스트를 생성합니다.</p>
      </div>

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl bg-slate-900/90">
        <label className="text-slate-500 text-[10px] font-black mb-3 block uppercase tracking-widest">일러스트 프롬프트</label>
        <div className="input-group">
          <input 
            type="text" 
            className="form-control !bg-slate-950 border-slate-800 text-white py-3 px-4 rounded-s-xl" 
            placeholder="필요한 이미지를 설명하세요..."
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
          />
          <button className="btn btn-primary px-5 fw-bold rounded-e-xl" onClick={handleGenerate} disabled={loading}>
            {loading ? <Loader2 className="animate-spin" /> : "이미지 생성"}
          </button>
        </div>
      </div>

      <div className="d-flex justify-content-center align-items-center bg-slate-950/50 rounded-4 border border-slate-800 p-5 min-h-[500px] shadow-inner relative overflow-hidden">
        {loading ? (
          <div className="text-center">
            <Loader2 className="animate-spin mb-3 text-blue-500" size={48} />
            <p className="fw-black tracking-widest text-slate-500">생성 중...</p>
          </div>
        ) : image ? (
          <div className="text-center w-100 animate-scale-up">
            <img src={image} alt="Generated" className="img-fluid rounded-4 shadow-2xl mb-4 max-h-[500px] border border-slate-800" />
            <div className="d-flex justify-content-center gap-3">
              <button 
                className={`btn ${isSaved ? 'btn-success' : 'btn-outline-light'} px-5 py-3 rounded-2xl fw-black flex items-center gap-2 transition-all border-0`} 
                onClick={handleSaveToDashboard}
                disabled={isSaved}
              >
                {isSaved ? <CheckCircle size={20} /> : <LayoutDashboard size={20} />}
                {isSaved ? "저장 완료" : "대시보드에 저장"}
              </button>
              <a href={image} download="ai-news-img.png" className="btn btn-outline-slate-700 px-5 py-3 rounded-2xl fw-black flex items-center gap-2">
                다운로드
              </a>
            </div>
          </div>
        ) : (
          <div className="text-center opacity-20">
            <ImageIcon size={80} className="mb-3 mx-auto" />
            <p className="fw-black">프롬프트를 입력하세요</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIIllustrator;

import React, { useState, useEffect, useRef } from 'react';
import { generateComments } from '../services/gemini';
import { MessageSquare, Send, Zap, Loader2, AlertCircle } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

interface Reaction {
  user: string;
  comment: string;
  likes: number;
  color?: string;
}

const NetizenSimulator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [topic, setTopic] = useState('');
  const [reactions, setReactions] = useState<Reaction[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const getUserColor = (name: string) => {
    const colors = [
      '#ef4444', '#f59e0b', '#10b981', '#3b82f6', 
      '#8b5cf6', '#ec4899', '#f43f5e', '#06b6d4'
    ];
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = name.charCodeAt(i) + ((hash << 5) - hash);
    }
    return colors[Math.abs(hash) % colors.length];
  };

  const handleGenerate = async () => {
    const targetTopic = topic.trim() || "AI가 기사를 쓰는 미래";
    setIsGenerating(true);
    setReactions([]);

    try {
      const data = await generateComments(targetTopic, isMockMode);
      let index = 0;
      const interval = setInterval(() => {
        if (index >= data.length) {
          clearInterval(interval);
          setIsGenerating(false);
          return;
        }
        const newReaction = {
          ...data[index],
          color: getUserColor(data[index].user)
        };
        setReactions(prev => [...prev, newReaction]);
        index++;
      }, 800);
    } catch (error: any) {
      console.error(error);
      setIsGenerating(false);
      alert("분석 중 오류가 발생했습니다. 다시 시도해 주세요.");
