import React, { useState } from 'react';
import { generateImage } from '../services/gemini';
import { Image as ImageIcon, Save, Loader2, Zap, LayoutDashboard, CheckCircle } from 'lucide-react';

interface Props {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AIIllustrator: React.FC<Props> = ({ isMockMode, setIsMockMode }) => {
  const [prompt, setPrompt] = useState("");
  const [image, setImage] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [isSaved, setIsSaved] = useState(false);

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    setIsSaved(false);
    try {
      const imgUrl = await generateImage(prompt, isMockMode);
      setImage(imgUrl);
    } catch (e: any) {
      console.error("이미지 생성 오류:", e);
      alert("이미지 생성 중 오류가 발생했습니다. AI 할당량을 확인하거나 다시 시도해 주세요.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveToDashboard = () => {
    if (!image) return;
    try {
      const savedRaw = localStorage.getItem('my_images');
      let currentList = savedRaw ? JSON.parse(savedRaw) : [];
      const newImage = {
        id: Date.now(),
        prompt: prompt,
        url: image,
        date: new Date().toLocaleDateString() + " " + new Date().toLocaleTimeString(),
      };
      let updatedList = [newImage, ...currentList];
      if (updatedList.length > 10) {
        updatedList = updatedList.slice(0, 10);
      }
      const attemptSave = (list: any[]): boolean => {
        try {
          localStorage.setItem('my_images', JSON.stringify(list));
          return true;
        } catch (e: any) {
          if (e.name === 'QuotaExceededError' && list.length > 1) {
            return attemptSave(list.slice(0, -1));
          }
          return false;
        }
      };
      const success = attemptSave(updatedList);
      if (success) {
        setIsSaved(true);
        alert("✅ 이미지가 대시보드 포토 갤러리에 추가되었습니다.");
      } else {
        alert("저장 공간이 부족합니다. 대시보드 포토 갤러리에서 오래된 사진을 삭제해주세요.");
      }
    } catch (err: any) {
      alert("저장 중 오류가 발생했습니다.");
    }
  };

  return (
    <div className="h-100 p-2 text-white animate-fade-in">
      <div className="mb-5">
        <h2 className="fw-black mb-1 tracking-tighter">🎨 AI 일러스트레이터</h2>
        <p className="text-slate-500 text-sm m-0">기사 보충용 고퀄리티 일러스트를 생성합니다.</p>
      </div>

      <div className="glass-card p-5 mb-5 rounded-3xl border-0 shadow-2xl bg-slate-900/90">
        <label className="text-slate-500 text-[10px] font-black mb-3 block uppercase tracking-widest">일러스트 프롬프트</label>
        <div className="input-group">
          <input 
            type="text" 
            className="form-control !bg-slate-950 border-slate-800 text-white py-3 px-4 rounded-s-xl" 
            placeholder="필요한 이미지를 설명하세요..."
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleGenerate()}
          />
          <button className="btn btn-primary px-5 fw-bold rounded-e-xl" onClick={handleGenerate} disabled={loading}>
            {loading ? <Loader2 className="animate-spin" /> : "이미지 생성"}
          </button>
        </div>
      </div>

      <div className="d-flex justify-content-center align-items-center bg-slate-950/50 rounded-4 border border-slate-800 p-5 min-h-[500px] shadow-inner relative overflow-hidden">
        {loading ? (
          <div className="text-center">
            <Loader2 className="animate-spin mb-3 text-blue-500" size={48} />
            <p className="fw-black tracking-widest text-slate-500">생성 중...</p>
          </div>
        ) : image ? (
          <div className="text-center w-100 animate-scale-up">
            <img src={image} alt="Generated" className="img-fluid rounded-4 shadow-2xl mb-4 max-h-[500px] border border-slate-800" />
            <div className="d-flex justify-content-center gap-3">
              <button 
                className={`btn ${isSaved ? 'btn-success' : 'btn-outline-light'} px-5 py-3 rounded-2xl fw-black flex items-center gap-2 transition-all border-0`} 
                onClick={handleSaveToDashboard}
                disabled={isSaved}
              >
                {isSaved ? <CheckCircle size={20} /> : <LayoutDashboard size={20} />}
                {isSaved ? "저장 완료" : "대시보드에 저장"}
              </button>
              <a href={image} download="ai-news-img.png" className="btn btn-outline-slate-700 px-5 py-3 rounded-2xl fw-black flex items-center gap-2">
                다운로드
              </a>
            </div>
          </div>
        ) : (
          <div className="text-center opacity-20">
            <ImageIcon size={80} className="mb-3 mx-auto" />
            <p className="fw-black">프롬프트를 입력하세요</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AIIllustrator;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { Send, Loader2, UserX, ShieldCheck, Terminal, AlertCircle, FileText, Trash2 } from 'lucide-react';

interface Message {
  role: 'user' | 'model';
  text: string;
  isSystem?: boolean;
}

const SupabaseAdminChat: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: "안녕하세요. Supabase 및 뉴스룸 대시보드 통합 관리자 AI입니다. 사용자 삭제나 대시보드 기사 관리를 도와드릴까요?" }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const delete_user_by_email = async (args: { email: string }) => {
    console.log(`Deleting user: ${args.email}`);
    return { success: true, message: `Supabase 인증 서버에서 사용자 ${args.email}가 성공적으로 제거되었습니다.` };
  };

  const list_dashboard_articles = async () => {
    try {
      const saved = JSON.parse(localStorage.getItem('dashboard_db') || '[]');
      if (saved.length === 0) return { success: true, articles: [], message: "현재 대시보드에 저장된 기사가 없습니다." };
      const articleList = saved.map((a: any) => ({ id: a.id, title: a.title, date: a.date }));
      return { success: true, articles: articleList };
    } catch (e) {
      return { success: false, message: "기사 목록을 불러오는 중 오류가 발생했습니다." };
    }
  };

  const delete_dashboard_article = async (args: { title: string }) => {
    try {
      const saved = JSON.parse(localStorage.getItem('dashboard_db') || '[]');
      const initialCount = saved.length;
      const filtered = saved.filter((a: any) => !a.title.toLowerCase().includes(args.title.toLowerCase()));

      if (initialCount === filtered.length) {
        return { success: false, message: `제목에 "${args.title}"이(가) 포함된 기사를 대시보드에서 찾을 수 없습니다.` };
      }

      localStorage.setItem('dashboard_db', JSON.stringify(filtered));
      return { 
        success: true, 
        message: `제목에 "${args.title}"이(가) 포함된 기사 ${initialCount - filtered.length}건이 대시보드에서 영구 삭제되었습니다.` 
      };
    } catch (e) {
      return { success: false, message: "기사 삭제 처리 중 오류가 발생했습니다." };
    }
  };

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMessage = input.trim();
    setInput("");
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setLoading(true);

    try {
      // 시스템 API 키를 사용하여 즉시 초기화
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const contents = [
        ...messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
        { role: 'user', parts: [{ text: userMessage }] }
      ];

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents,
        config: {
          systemInstruction: `당신은 Supabase 데이터베이스 및 동아 AI 뉴스룸 대시보드를 관리하는 관리자(Admin) AI입니다.

[보유 권한 및 도구]
1. delete_user_by_email: 사용자의 이메일을 기반으로 인증 서버에서 삭제합니다.
2. list_dashboard_articles: 현재 대시보드에 저장된 모든 기사의 제목과 정보를 확인합니다.
3. delete_dashboard_article: 대시보드에서 특정 제목을 가진 기사를 영구 삭제합니다.

[중요 규칙 - 반드시 지킬 것]
1. 삭제(사용자 또는 기사) 요청이 들어오면, 즉시 도구를 실행하지 마십시오.
