export default AudioNews;

import React, { useState, useRef, useEffect } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Save, Trash2, Headphones, Sparkles, Loader2 } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);

  // Audio Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const ttsBufferRef = useRef<AudioBuffer | null>(null); 
  const bgmBufferRef = useRef<AudioBuffer | null>(null);

  // Constants
  const BGM_URL = "https://www.soundhelix.com/examples/mp3/SoundHelix-Song-2.mp3";

  // Preload BGM to avoid "cuts out" on play
  useEffect(() => {
    const preloadBGM = async () => {
      try {
        if (!audioContextRef.current) {
          audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
        }
        const response = await fetch(BGM_URL);
        const arrayBuffer = await response.arrayBuffer();
        const decoded = await audioContextRef.current.decodeAudioData(arrayBuffer);
        bgmBufferRef.current = decoded;
        console.log("BGM Preloaded successfully");
      } catch (e) {
        console.error("BGM Preload failed:", e);
      }
    };

    preloadBGM();

    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));

    return () => stopPlayback();
  }, []);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (bgmSourceRef.current) {
      try { bgmSourceRef.current.stop(); } catch(e) {}
      bgmSourceRef.current = null;
    }
    setIsPlaying(false);
  };

  const startPlayback = async () => {
    if (!ttsBufferRef.current || !audioContextRef.current) return;

    stopPlayback();

    if (audioContextRef.current.state === 'suspended') {
      await audioContextRef.current.resume();
    }

    // 1. Create Nodes
    const ttsSource = audioContextRef.current.createBufferSource();
    const bgmSource = audioContextRef.current.createBufferSource();
    const bgmGain = audioContextRef.current.createGain();

    // 2. Configure TTS
    ttsSource.buffer = ttsBufferRef.current;
    ttsSource.connect(audioContextRef.current.destination);
    ttsSource.onended = () => {
        // 배경음악도 같이 멈추거나 서서히 줄어들게 할 수 있음
        stopPlayback();
    };

    // 3. Configure BGM (Mixing)
    if (bgmBufferRef.current) {
        bgmSource.buffer = bgmBufferRef.current;
        bgmSource.loop = true;
        bgmGain.gain.value = 0.12; // 배경음악 볼륨 낮춤
        bgmSource.connect(bgmGain);
        bgmGain.connect(audioContextRef.current.destination);
    }

    // 4. Play Together
    ttsSourceRef.current = ttsSource;
    bgmSourceRef.current = bgmSource;

    bgmSource.start(0);
    ttsSource.start(0);
    setIsPlaying(true);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    stopPlayback();
    ttsBufferRef.current = null;

    try {
      // 1. 가사 생성
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // 2. TTS 음성 생성 (가사 생성 직후 연속 진행)
      const audioData = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      const buffer = await decodeAudio(audioData, audioContextRef.current);
      ttsBufferRef.current = buffer; 

      // 3. 즉시 재생
      startPlayback();
    } catch (error: any) {
      console.error(error);
      alert("오디오 생성 중 오류가 발생했습니다. 할당량을 확인해 주세요.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSave = () => {
    if (!lyrics) return;
    const newItem: SavedAudioNews = {
      id: Date.now(),
      title: inputText.split('\n')[0].slice(0, 20) || "제목 없음",
      lyrics: lyrics,
      timestamp: new Date().toLocaleString('ko-KR', { hour12: false }).slice(0, -3)
    };
    const updated = [newItem, ...savedItems];
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
    alert("보관함에 저장되었습니다.");
  };

  const loadSavedItem = async (item: SavedAudioNews) => {
    if (lyrics === item.lyrics && ttsBufferRef.current) {
      startPlayback();
      return;
    }

    setIsLoading(true);
    setLyrics(item.lyrics);
    stopPlayback();
    ttsBufferRef.current = null;

    try {
      const audioData = await speakTrot(item.lyrics, isMockMode);
      if (!audioData) throw new Error("Audio generation failed");
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const buffer = await decodeAudio(audioData, audioContextRef.current);
      ttsBufferRef.current = buffer;
      startPlayback();
    } catch (error: any) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const deleteItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = savedItems.filter(item => item.id !== id);
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      if (ttsBufferRef.current) {
        await startPlayback();
      } else if (lyrics) {
        if (isMockMode) {
            alert("Mock Mode에서는 가사만 생성됩니다.");
        } else {
            loadSavedItem({ id: 0, title: '', lyrics: lyrics, timestamp: '' });
        }
      }
    }
  };

  return (
    <div className="container-fluid py-2 text-white animate-fade-in">
      <div className="row g-4">
        {/* Left: Archive Sidebar */}
        <div className="col-lg-3">
          <div className="glass-card h-100 p-4 d-flex flex-column rounded-[32px] border-slate-800" style={{ minHeight: '80vh', background: '#0f172a' }}>
            <h5 className="text-white fw-bold mb-4 pb-3 border-bottom border-slate-700 d-flex justify-content-between align-items-center">
              <span className="flex items-center gap-2"><Music size={20} className="text-warning"/> 보관함</span>
              <span className="badge bg-slate-800 text-slate-400 px-2">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1 pr-2">
              {savedItems.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                  <Headphones size={48} className="mx-auto mb-3" />
                  <p className="small">저장된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="grid gap-3">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => loadSavedItem(item)}
                      className={`p-4 rounded-2xl transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning bg-warning/5 shadow-lg' : 'border-slate-800 bg-slate-900/40 hover:bg-slate-800'}`}
                    >
                      <h6 className="text-white text-truncate mb-2 fw-bold" style={{ fontSize: '0.95rem' }}>{item.title}</h6>
                      <p className="text-slate-500 m-0" style={{ fontSize: '0.75rem' }}>{item.timestamp}</p>
                      <button 
                        onClick={(e) => deleteItem(e, item.id)}
                        className="btn btn-link text-red-500 p-0 position-absolute top-4 end-4 opacity-0 group-hover:opacity-100 transition-all border-0"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Right: Main Work Area */}
        <div className="col-lg-9">
          <div className="text-center mb-6">
            <h1 className="display-5 fw-black text-white mb-2 tracking-tighter">
              <span className="text-gradient-trot">AI 트로트 뉴스룸</span>
            </h1>
            <p className="text-slate-400">딱딱한 기사를 신나는 트로트 가사와 AI 음성으로 변환합니다.</p>
          </div>

          <div className="row g-4">
            <div className="col-xl-6">
              <div className="glass-card p-5 h-100 d-flex flex-column rounded-[40px] border-slate-800 shadow-2xl" style={{ background: '#0f172a' }}>
                <div className="d-flex justify-content-between align-items-center mb-4">
                    <label className="text-slate-400 fw-bold text-xs uppercase tracking-widest flex items-center gap-2">
                        <Sparkles size={16} className="text-blue-500" /> 기사 텍스트
                    </label>
                    {isMockMode && <span className="badge bg-amber-500/20 text-amber-500 border border-amber-500/30 text-[9px] px-2 py-1 font-black">DEMO</span>}
                </div>
                <textarea
                  className="form-control bg-slate-950 text-white border-slate-800 mb-5 flex-grow-1 p-4 rounded-3xl"
                  style={{ resize: 'none', minHeight: '400px', fontSize: '1.05rem', lineHeight: '1.7', border: '1px solid rgba(255,255,255,0.05)' }}
                  placeholder="트로트로 변환하고 싶은 뉴스 기사를 복사해서 붙여넣으세요..."
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                ></textarea>

                <div className="d-flex gap-3">
                  <button 
                    className="btn btn-warning flex-grow-1 py-4 rounded-2xl fw-black fs-5 shadow-2xl border-0 transition-transform active:scale-95 flex items-center justify-center gap-3"
                    style={{ background: 'linear-gradient(135deg, #F09819 0%, #EDDE5D 100%)', color: '#000' }}
                    onClick={handleConvert}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <><Loader2 className="animate-spin" /> <span>AI 가사 및 음성 합성 중...</span></>
                    ) : (
                      <><Headphones /> 🎤 트로트 뉴스 생성</>
                    )}
                  </button>
                  {lyrics && (
                    <button className="btn btn-outline-slate-700 px-4 rounded-2xl border-slate-800 hover:bg-slate-800 transition-colors" onClick={handleSave} title="보관함에 저장">
                      <Save size={24} />
                    </button>
                  )}
                </div>
              </div>
            </div>

            <div className="col-xl-6">
              <div className="glass-card p-5 h-100 d-flex flex-column align-items-center justify-content-center text-center rounded-[40px] border-slate-800 shadow-2xl" style={{ background: '#020617' }}>
                {!lyrics ? (
                  <div className="py-20 opacity-20">
                    <div className="bg-slate-900 w-32 h-32 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-800">
                        <Music size={60} />
                    </div>
                    <h4 className="fw-black text-slate-500">대기 중</h4>
                    <p className="small">기사를 입력하면 오디오 플레이어가 활성화됩니다.</p>
                  </div>
                ) : (
                  <div className="w-100 animate-fade-in">
                    {/* Vinyl Record Visualizer */}
                    <div className="mb-10 position-relative d-inline-block">
                        <div 
                            className={`rounded-full border-[12px] border-slate-900 mx-auto d-flex align-items-center justify-content-center shadow-3xl ${isPlaying ? 'spin-slow' : ''}`}
                            style={{ 
                                width: '280px', 
                                height: '280px', 
                                background: 'radial-gradient(circle, #334155 10%, #0f172a 40%, #020617 70%)',
                                boxShadow: isPlaying ? '0 0 50px rgba(240, 152, 25, 0.3)' : 'none'
                            }}
                        >
                          <div className="rounded-full bg-warning flex items-center justify-center shadow-inner" style={{ width: '80px', height: '80px', border: '5px solid #000' }}>
                            <div className="w-2 h-2 rounded-full bg-black"></div>
                          </div>
                        </div>
                        <div 
                            className="position-absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 cursor-pointer z-10"
                            onClick={togglePlay}
                        >
                           {isPlaying ? (
                               <Pause size={100} className="text-white fill-white opacity-80 hover:scale-110 transition-transform drop-shadow-2xl" />
                           ) : (
                               <Play size={100} className="text-white fill-white opacity-80 hover:scale-110 transition-transform drop-shadow-2xl translate-x-1" />
                           )}
                        </div>
                    </div>

                    <div className="bg-slate-900/60 rounded-3xl p-5 mb-8 text-start border border-slate-800 custom-scrollbar shadow-inner" style={{ maxHeight: '300px', overflowY: 'auto' }}>
                      <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '1.9', fontSize: '1.15rem', letterSpacing: '-0.3px', fontWeight: '500' }}>
                        {lyrics}
                      </pre>
                    </div>

                    <div className="flex gap-4">
                        <button 
                            className={`btn flex-grow-1 py-4 rounded-2xl fw-black fs-5 transition-all shadow-xl flex items-center justify-center gap-3 ${isPlaying ? 'btn-danger' : 'btn-primary'}`} 
                            onClick={togglePlay}
                            disabled={isLoading}
                        >
                            {isPlaying ? <><Pause /> 재생 중지</> : <><Play /> 다시 듣기</>}
                        </button>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
      <style>{`
        .spin-slow { animation: spin 4s linear infinite; }
        @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
        .text-gradient-trot {
            background: linear-gradient(to right, #F09819, #EDDE5D);
            -webkit-background-clip: text;
            -webkit-text-fill-color: transparent;
        }
        .shadow-3xl { box-shadow: 0 35px 60px -15px rgba(0, 0, 0, 0.6); }
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
      `}</style>
    </div>
  );
};

