import React, { useState, useRef, useEffect, useCallback } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Save, Trash2, Headphones, Sparkles, Loader2, AlertCircle } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isBgmReady, setIsBgmReady] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);

  // Audio Engine Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const ttsBufferRef = useRef<AudioBuffer | null>(null); 
  const bgmBufferRef = useRef<AudioBuffer | null>(null);

  // Reliable BGM URL (Publicly accessible with CORS)
  const BGM_URL = "https://actions.google.com/sounds/v1/science_fiction/future_transition.ogg";

  const initAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContextRef.current;
  };

  const preloadBGM = useCallback(async () => {
    try {
      const ctx = initAudioContext();
      const response = await fetch(BGM_URL);
      if (!response.ok) throw new Error("BGM Fetch Failed");
      const arrayBuffer = await response.arrayBuffer();
      const decoded = await ctx.decodeAudioData(arrayBuffer);
      bgmBufferRef.current = decoded;
      setIsBgmReady(true);
      console.log("BGM Loaded Successfully");
    } catch (e) {
      console.warn("BGM load failed, will play without background music:", e);
      setIsBgmReady(false);
    }
  }, []);

  useEffect(() => {
    preloadBGM();
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));
    return () => stopPlayback();
  }, [preloadBGM]);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (bgmSourceRef.current) {
      try { bgmSourceRef.current.stop(); } catch(e) {}
      bgmSourceRef.current = null;
    }
    setIsPlaying(false);
  };

  const startPlayback = async () => {
    const ctx = initAudioContext();
    if (!ttsBufferRef.current) return;

    stopPlayback();

    // CRITICAL: Browsers require user interaction to resume AudioContext
    if (ctx.state === 'suspended') {
      await ctx.resume();
    }

    const ttsSource = ctx.createBufferSource();
    ttsSource.buffer = ttsBufferRef.current;
    ttsSource.connect(ctx.destination);

    ttsSource.onended = () => {
      stopPlayback();
    };

    if (bgmBufferRef.current) {
      const bgmSource = ctx.createBufferSource();
      const bgmGain = ctx.createGain();
      bgmSource.buffer = bgmBufferRef.current;
      bgmSource.loop = true;
      bgmGain.gain.value = 0.15; // Set BGM volume lower than voice
      bgmSource.connect(bgmGain);
      bgmGain.connect(ctx.destination);

      bgmSourceRef.current = bgmSource;
      bgmSource.start(0);
    }

    ttsSourceRef.current = ttsSource;
    ttsSource.start(0);
    setIsPlaying(true);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("기사를 입력해주세요!");
      return;
    }

    setIsLoading(true);
    stopPlayback();
    ttsBufferRef.current = null;

    try {
      // 1. Generate Lyrics
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // 2. Generate Audio (TTS)
      const audioData = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio data is empty");

      const ctx = initAudioContext();
      const buffer = await decodeAudio(audioData, ctx);
      ttsBufferRef.current = buffer; 

      // 3. Play immediately with BGM mixing
      await startPlayback();
    } catch (error: any) {
      console.error("Audio conversion failed:", error);
      alert("뉴스 생성 중 오류가 발생했습니다. AI 사용량을 확인해 주세요.");
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      if (ttsBufferRef.current) {
        await startPlayback();
      } else if (lyrics && !isMockMode) {
        setIsLoading(true);
        try {
          const audioData = await speakTrot(lyrics, isMockMode);
          if (audioData) {
            const ctx = initAudioContext();
            ttsBufferRef.current = await decodeAudio(audioData, ctx);
            await startPlayback();
          }
        } finally {
          setIsLoading(false);
        }
      }
    }
  };

  const handleSave = () => {
