              <span className="flex items-center gap-2"><Music size={20} className="text-warning"/> 보관함</span>
              <span className="badge bg-slate-800 text-slate-400">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1 pr-2">
              {savedItems.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                  <Headphones size={48} className="mx-auto mb-3" />
                  <p className="small">저장된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="grid gap-3">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => { setLyrics(item.lyrics); setInputText(item.title); }}
                      className={`p-4 rounded-2xl transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning bg-warning/5' : 'border-slate-800 bg-slate-900/40 hover:bg-slate-800'}`}
                    >
