                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="col-lg-9">
          <div className="text-center mb-6">
            <h1 className="display-5 fw-black text-white mb-2 tracking-tighter">
              <span className="text-gradient-trot">AI 트로트 뉴스룸</span>
            </h1>
            <p className="text-slate-400">딱딱한 기사를 신나는 트로트 가사와 음성으로 들어보세요.</p>
