      if (!response.ok) throw new Error("BGM Fetch Failed");
      const arrayBuffer = await response.arrayBuffer();
      const decoded = await ctx.decodeAudioData(arrayBuffer);
      bgmBufferRef.current = decoded;
      setIsBgmReady(true);
