export default AudioNews;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Save, Trash2, Headphones, Sparkles, Loader2, AlertCircle, Volume2 } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isBgmReady, setIsBgmReady] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);

  // Audio Engine Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const bgmSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const ttsBufferRef = useRef<AudioBuffer | null>(null); 
  const bgmBufferRef = useRef<AudioBuffer | null>(null);

  // Reliable BGM URL (CORS friendly, fast loading)
  // 트로트 느낌의 신나는 비트 소스로 교체 (안정적인 Google CDN 소스 사용)
  const BGM_URL = "https://actions.google.com/sounds/v1/foley/beating_drum.ogg";

  const initAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContextRef.current;
  };

  const preloadBGM = useCallback(async () => {
    try {
      const ctx = initAudioContext();
      const response = await fetch(BGM_URL, { mode: 'cors' });
      if (!response.ok) throw new Error("BGM Load Fail");
      const arrayBuffer = await response.arrayBuffer();
      const decoded = await ctx.decodeAudioData(arrayBuffer);
      bgmBufferRef.current = decoded;
      setIsBgmReady(true);
      console.log("BGM Preloaded and Ready");
    } catch (e) {
      console.warn("BGM preloading failed, but playback will still work via TTS:", e);
      setIsBgmReady(false);
    }
  }, []);

  useEffect(() => {
    preloadBGM();
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));
    return () => stopPlayback();
  }, [preloadBGM]);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (bgmSourceRef.current) {
      try { bgmSourceRef.current.stop(); } catch(e) {}
      bgmSourceRef.current = null;
    }
    setIsPlaying(false);
  };

  // 배경음악만 먼저 재생하는 함수 (속도 최우선)
  const startBgmOnly = async () => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (bgmSourceRef.current) return; // 이미 재생 중이면 중복 실행 방지

    if (bgmBufferRef.current) {
      const bgmSource = ctx.createBufferSource();
      const bgmGain = ctx.createGain();
      bgmSource.buffer = bgmBufferRef.current;
      bgmSource.loop = true;
      bgmGain.gain.value = 0.15; // 배경음악 볼륨
      bgmSource.connect(bgmGain);
      bgmGain.connect(ctx.destination);

      bgmSourceRef.current = bgmSource;
      bgmSource.start(0);
      setIsPlaying(true);
    }
  };

  // TTS 음성을 현재 나오는 음악 위에 얹어서 재생하는 함수
  const playTtsOverBgm = async (buffer: AudioBuffer) => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    // 혹시라도 이전에 재생 중이던 TTS가 있다면 정지
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
    }

    const ttsSource = ctx.createBufferSource();
    ttsSource.buffer = buffer;
    ttsSource.connect(ctx.destination);
    ttsSourceRef.current = ttsSource;

    ttsSource.onended = () => {
      // TTS가 끝나면 음악도 함께 정지 (필요에 따라 수정 가능)
      stopPlayback();
    };

    ttsSource.start(0);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("기사를 입력해주세요!");
      return;
    }

    // 1. 즉시 배경음악 시작 (사용자 경험 향상)
    await startBgmOnly();

    setIsLoading(true);
    ttsBufferRef.current = null;
    setLyrics(null);

    try {
      const ctx = initAudioContext();

      // Step 2: 가사 생성
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // Step 3: 음성 생성 (TTS)
      const audioData = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      const buffer = await decodeAudio(audioData, ctx);
      ttsBufferRef.current = buffer; 

      // Step 4: 이미 나오고 있는 배경음악 위에 음성 믹싱
      await playTtsOverBgm(buffer);
    } catch (error: any) {
      console.error(error);
      stopPlayback();
      alert("오디오 처리 중 오류가 발생했습니다. AI 사용량을 확인해 주세요.");
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      if (ttsBufferRef.current) {
        const ctx = initAudioContext();
        await startBgmOnly();
        await playTtsOverBgm(ttsBufferRef.current);
      } else if (lyrics && !isMockMode) {
        handleConvert();
      } else {
        await startBgmOnly();
      }
    }
  };

  const handleSave = () => {
    if (!lyrics) return;
    const newItem: SavedAudioNews = {
      id: Date.now(),
      title: inputText.split('\n')[0].slice(0, 20) || "제목 없음",
      lyrics: lyrics,
      timestamp: new Date().toLocaleString('ko-KR', { hour12: false }).slice(0, -3)
    };
    const updated = [newItem, ...savedItems];
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
    alert("보관함에 저장되었습니다.");
  };

  const deleteItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = savedItems.filter(item => item.id !== id);
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
  };

  return (
    <div className="container-fluid py-2 text-white animate-fade-in">
      <div className="row g-4">
        {/* Archive Sidebar */}
        <div className="col-lg-3">
          <div className="glass-card h-100 p-4 d-flex flex-column rounded-[32px] border-slate-800" style={{ minHeight: '80vh', background: '#0f172a' }}>
            <h5 className="text-white fw-bold mb-4 pb-3 border-bottom border-slate-700 d-flex justify-content-between align-items-center">
              <span className="flex items-center gap-2"><Music size={20} className="text-warning"/> 보관함</span>
              <span className="badge bg-slate-800 text-slate-400 px-2">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1 pr-2">
              {savedItems.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                  <Headphones size={48} className="mx-auto mb-3" />
                  <p className="small">저장된 기사가 없습니다.</p>
                </div>
              ) : (
                <div className="grid gap-3">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => { setLyrics(item.lyrics); setInputText(item.title); }}
                      className={`p-4 rounded-2xl transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning bg-warning/5 shadow-lg' : 'border-slate-800 bg-slate-900/40 hover:bg-slate-800'}`}
                    >
                      <h6 className="text-white text-truncate mb-2 fw-bold" style={{ fontSize: '0.9rem' }}>{item.title}</h6>
                      <p className="text-slate-500 m-0" style={{ fontSize: '0.7rem' }}>{item.timestamp}</p>
                      <button 
                        onClick={(e) => deleteItem(e, item.id)}
                        className="btn btn-link text-red-500 p-0 position-absolute top-4 end-4 opacity-0 group-hover:opacity-100 transition-all border-0 shadow-none"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Studio Main Area */}
        <div className="col-lg-9">
          <div className="text-center mb-6">
            <h1 className="display-5 fw-black text-white mb-2 tracking-tighter">
              <span className="text-gradient-trot">AI 트로트 뉴스룸</span>
            </h1>
            <p className="text-slate-400">버튼을 누르면 신나는 비트와 함께 뉴스가 시작됩니다!</p>
          </div>

          <div className="row g-4">
            <div className="col-xl-6">
              <div className="glass-card p-5 h-100 d-flex flex-column rounded-[40px] border-slate-800 shadow-2xl" style={{ background: '#0f172a' }}>
                <div className="d-flex justify-content-between align-items-center mb-4">
                  <label className="text-slate-400 fw-bold text-xs uppercase tracking-widest flex items-center gap-2">
                    <Sparkles size={16} className="text-blue-500" /> 뉴스 본문 텍스트
                  </label>
                  {!isBgmReady && (
                    <span className="text-[10px] text-slate-600 flex items-center gap-1 animate-pulse">
                      <AlertCircle size={10} /> 오디오 준비 중...
                    </span>
