      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (bgmSourceRef.current) {
      try { bgmSourceRef.current.stop(); } catch(e) {}
      bgmSourceRef.current = null;
    }
    if (fallbackIntervalRef.current) {
      clearInterval(fallbackIntervalRef.current);
      fallbackIntervalRef.current = null;
    }
    setIsPlaying(false);
  };

  // 트로트 특유의 '쿵짝' 비트를 오디오 오실레이터로 합성 (BGM 로드 실패시 대비)
  const playSynthesizedBeat = (ctx: AudioContext) => {
    if (fallbackIntervalRef.current) return;

    let beatCount = 0;
    const tempo = 120; // BPM
    const beatDuration = 60 / tempo;

    fallbackIntervalRef.current = window.setInterval(() => {
      const now = ctx.currentTime;

      // 쿵 (베이스 드럼 효과)
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(60, now);
      osc.frequency.exponentialRampToValueAtTime(0.01, now + 0.1);
      gain.gain.setValueAtTime(0.2, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start(now);
      osc.stop(now + 0.1);

      // 짝 (스네어/클랩 효과) - 엇박자에 추가
      setTimeout(() => {
        const snOsc = ctx.createOscillator();
        const snGain = ctx.createGain();
        snOsc.type = 'square';
        snOsc.frequency.setValueAtTime(150, ctx.currentTime);
        snGain.gain.setValueAtTime(0.05, ctx.currentTime);
        snGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.05);
        snOsc.connect(snGain);
        snGain.connect(ctx.destination);
        snOsc.start(ctx.currentTime);
        snOsc.stop(ctx.currentTime + 0.05);
      }, (beatDuration * 1000) / 2);

      beatCount++;
    }, beatDuration * 1000);
  };

  const startBgmOnly = async () => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (bgmSourceRef.current || fallbackIntervalRef.current) return; 

    if (bgmBufferRef.current) {
      const bgmSource = ctx.createBufferSource();
      const bgmGain = ctx.createGain();
      bgmSource.buffer = bgmBufferRef.current;
      bgmSource.loop = true;
      bgmGain.gain.value = 0.15;
      bgmSource.connect(bgmGain);
      bgmGain.connect(ctx.destination);
      bgmSourceRef.current = bgmSource;
      bgmSource.start(0);
    } else {
      // 파일 로드 안됐으면 합성 비트라도 재생
      playSynthesizedBeat(ctx);
    }
    setIsPlaying(true);
  };

  const playTtsOverBgm = async (buffer: AudioBuffer) => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
    }

    const ttsSource = ctx.createBufferSource();
    ttsSource.buffer = buffer;
    ttsSource.connect(ctx.destination);
    ttsSourceRef.current = ttsSource;

    ttsSource.onended = () => {
      stopPlayback();
    };

    ttsSource.start(0);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("기사를 입력해주세요!");
      return;
    }

    // ★ 즉시 배경음악 시작 (로딩 대기 시간 중 음악 재생)
    await startBgmOnly();

    setIsLoading(true);
    ttsBufferRef.current = null;
    setLyrics(null);

    try {
      const ctx = initAudioContext();
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      const audioData = await speakTrot(trotLyrics, isMockMode);
      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      const buffer = await decodeAudio(audioData, ctx);
      ttsBufferRef.current = buffer; 

      await playTtsOverBgm(buffer);
    } catch (error: any) {
      console.error(error);
      alert("오디오 처리 중 오류가 발생했습니다. AI 사용량을 확인해 주세요.");
    } finally {
