        model: 'gemini-3-flash-preview',
        contents: `기사 내용을 트로트 가사로 바꾸세요: ${article}`,
      });
      return response.text;
    } catch (error) {
      return handleAIError(error);
    }
  });
};

export const speakTrot = async (lyrics: string, isMock: boolean = false) => {
  if (isMock) return null;
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: lyrics }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
        },
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    } catch (error) {
      return handleAIError(error);
    }
  });
};

export const decodeAudio = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // Create an Int16Array from the buffer, ensuring byte alignment
  const dataInt16 = new Int16Array(bytes.buffer, 0, Math.floor(len / 2));
  const buffer = ctx.createBuffer(1, dataInt16.length, 24000);
  const channelData = buffer.getChannelData(0);

  for (let i = 0; i < dataInt16.length; i++) {
    channelData[i] = dataInt16[i] / 32768.0;
  }
  return buffer;
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Save, Trash2, Headphones, Sparkles, Loader2, Volume2, Mic2 } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);

  // Audio Engine Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const beatIntervalRef = useRef<number | null>(null);
  const ttsBufferRef = useRef<AudioBuffer | null>(null); 

  const initAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    return audioContextRef.current;
  };

  useEffect(() => {
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));
    return () => stopPlayback();
  }, []);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (beatIntervalRef.current) {
      clearInterval(beatIntervalRef.current);
      beatIntervalRef.current = null;
    }
    setIsPlaying(false);
  };

  // 신명나는 트로트 '쿵짝' 비트 실시간 합성 엔진
  const startTrotBeat = (ctx: AudioContext) => {
    if (beatIntervalRef.current) return;

    const tempo = 138; // 트로트에 최적화된 빠른 템포 (BPM)
    const beatDuration = 60 / tempo; // 초 단위 한 박자 길이

    beatIntervalRef.current = window.setInterval(() => {
      const now = ctx.currentTime;

      // 1. "쿵" (강한 베이스 드럼 - 정박)
      const bassOsc = ctx.createOscillator();
      const bassGain = ctx.createGain();
      bassOsc.type = 'sine';
      bassOsc.frequency.setValueAtTime(60, now);
      bassOsc.frequency.exponentialRampToValueAtTime(0.01, now + 0.15);
      bassGain.gain.setValueAtTime(0.4, now);
      bassGain.gain.exponentialRampToValueAtTime(0.01, now + 0.15);
      bassOsc.connect(bassGain);
      bassGain.connect(ctx.destination);
      bassOsc.start(now);
      bassOsc.stop(now + 0.15);

      // 2. "짝" (경쾌한 스네어/심벌 - 엇박)
      // 한 박자의 딱 절반 뒤에 연주
      const offBeatTime = now + beatDuration / 2;
      const snareOsc = ctx.createOscillator();
      const snareGain = ctx.createGain();
      const snareFilter = ctx.createBiquadFilter();

      snareOsc.type = 'triangle';
      snareFilter.type = 'highpass';
      snareFilter.frequency.value = 1000;

      snareOsc.frequency.setValueAtTime(200, offBeatTime);
      snareGain.gain.setValueAtTime(0, offBeatTime);
      snareGain.gain.linearRampToValueAtTime(0.15, offBeatTime + 0.01);
      snareGain.gain.exponentialRampToValueAtTime(0.01, offBeatTime + 0.1);

      snareOsc.connect(snareFilter);
      snareFilter.connect(snareGain);
      snareGain.connect(ctx.destination);
      snareOsc.start(offBeatTime);
      snareOsc.stop(offBeatTime + 0.1);

    }, beatDuration * 1000);
  };

  const playTts = async (buffer: AudioBuffer) => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
    }

    const ttsSource = ctx.createBufferSource();
    ttsSource.buffer = buffer;

    // 목소리를 조금 더 트로트풍으로 만들기 위해 피치 조절 노드를 추가할 수도 있지만,
    // 여기서는 자연스러운 전달력을 위해 볼륨만 맞춤
    const voiceGain = ctx.createGain();
    voiceGain.gain.value = 1.2; // 비트보다 목소리가 잘 들리게 강조

    ttsSource.connect(voiceGain);
    voiceGain.connect(ctx.destination);
    ttsSourceRef.current = ttsSource;

    ttsSource.onended = () => {
      // 선택 사항: TTS가 끝나도 비트는 조금 더 나오게 하거나 같이 끄기
      // 여기서는 깔끔하게 같이 종료
      stopPlayback();
    };

    ttsSource.start(ctx.currentTime + 0.1);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    // ★ 즉시 트로트 비트 시작! (흥 돋우기)
    stopPlayback();
    startTrotBeat(ctx);
    setIsPlaying(true);

    setIsLoading(true);
    ttsBufferRef.current = null;
    setLyrics(null);

    try {
      // Step 1: 트로트 가사 생성
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // Step 2: AI 음성 생성
      const audioData = await speakTrot(trotLyrics, isMockMode);
      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioData) throw new Error("Audio generation failed");

      const buffer = await decodeAudio(audioData, ctx);
      ttsBufferRef.current = buffer; 

      // Step 3: 이미 흘러나오는 비트 위에 음성 믹싱 재생
      await playTts(buffer);
    } catch (error: any) {
      console.error(error);
      stopPlayback();
      alert("제작 중 오류가 발생했습니다. 잠시 후 다시 시도해 주세요.");
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      const ctx = initAudioContext();
      await ctx.resume();
      if (ttsBufferRef.current) {
        startTrotBeat(ctx);
        await playTts(ttsBufferRef.current);
        setIsPlaying(true);
      } else if (lyrics && !isMockMode) {
        handleConvert();
      } else {
        startTrotBeat(ctx);
        setIsPlaying(true);
      }
    }
  };

  const handleSave = () => {
