export const speakTrot = async (lyrics: string, isMock: boolean = false) => {
  if (isMock) return null;
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      // Use a more descriptive prompt to trigger "Trot" style in TTS
      const trotPrompt = `Say cheerfully like a Trot singer, very rhythmic and energetic: ${lyrics}`;

      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text: trotPrompt }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          // 'Kore' or 'Zephyr' are often more stable for energetic tones
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
        },
      });
      const audioData = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
      if (!audioData) throw new Error("Empty audio response from API");
      return audioData;
    } catch (error) {
      return handleAIError(error);
    }
  });
};

export const decodeAudio = async (base64: string, ctx: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // Ensure we don't try to read past the end or create odd-sized buffers for S16
  const numSamples = Math.floor(len / 2);
  const buffer = ctx.createBuffer(1, numSamples, 24000);
  const channelData = buffer.getChannelData(0);

  // Use a DataView for safe, byte-aligned access
  const dataView = new DataView(bytes.buffer);
  for (let i = 0; i < numSamples; i++) {
    // Gemini TTS PCM is little-endian 16-bit
    channelData[i] = dataView.getInt16(i * 2, true) / 32768.0;
  }
  return buffer;
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { generateTrotLyrics, speakTrot, decodeAudio } from '../services/gemini';
import { Music, Play, Pause, Save, Trash2, Headphones, Sparkles, Loader2, Volume2, Mic2, AlertCircle } from 'lucide-react';

interface SavedAudioNews {
  id: number;
  title: string;
  lyrics: string;
  timestamp: string;
}

interface AudioNewsProps {
  isMockMode: boolean;
  setIsMockMode: (val: boolean) => void;
}

const AudioNews: React.FC<AudioNewsProps> = ({ isMockMode, setIsMockMode }) => {
  const [inputText, setInputText] = useState(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).text : '';
  });
  const [lyrics, setLyrics] = useState<string | null>(() => {
    const session = localStorage.getItem('donga_audio_session');
    return session ? JSON.parse(session).savedLyrics : null;
  });

  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<SavedAudioNews[]>([]);

  // Audio Engine Refs
  const audioContextRef = useRef<AudioContext | null>(null);
  const ttsSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const beatIntervalRef = useRef<number | null>(null);
  const ttsBufferRef = useRef<AudioBuffer | null>(null); 

  const initAudioContext = () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    return audioContextRef.current;
  };

  useEffect(() => {
    const savedArchive = localStorage.getItem('donga_audio_archive');
    if (savedArchive) setSavedItems(JSON.parse(savedArchive));
    return () => stopPlayback();
  }, []);

  useEffect(() => {
    localStorage.setItem('donga_audio_session', JSON.stringify({
      text: inputText,
      savedLyrics: lyrics
    }));
  }, [inputText, lyrics]);

  const stopPlayback = () => {
    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
      ttsSourceRef.current = null;
    }
    if (beatIntervalRef.current) {
      clearInterval(beatIntervalRef.current);
      beatIntervalRef.current = null;
    }
    setIsPlaying(false);
  };

  const startTrotBeat = (ctx: AudioContext) => {
    if (beatIntervalRef.current) return;

    const tempo = 138; 
    const beatDuration = 60 / tempo;

    beatIntervalRef.current = window.setInterval(() => {
      const now = ctx.currentTime;

      // 1. "쿵" (강한 베이스 드럼 - 정박)
      const bassOsc = ctx.createOscillator();
      const bassGain = ctx.createGain();
      bassOsc.type = 'sine';
      bassOsc.frequency.setValueAtTime(65, now);
      bassOsc.frequency.exponentialRampToValueAtTime(0.01, now + 0.2);
      bassGain.gain.setValueAtTime(0.35, now);
      bassGain.gain.exponentialRampToValueAtTime(0.01, now + 0.2);
      bassOsc.connect(bassGain);
      bassGain.connect(ctx.destination);
      bassOsc.start(now);
      bassOsc.stop(now + 0.2);

      // 2. "짝" (경쾌한 타악기 - 엇박)
      const offBeatTime = now + beatDuration / 2;
      const snareOsc = ctx.createOscillator();
      const snareGain = ctx.createGain();
      const snareFilter = ctx.createBiquadFilter();

      snareOsc.type = 'square';
      snareFilter.type = 'highpass';
      snareFilter.frequency.value = 1200;

      snareOsc.frequency.setValueAtTime(180, offBeatTime);
      snareGain.gain.setValueAtTime(0, offBeatTime);
      snareGain.gain.linearRampToValueAtTime(0.12, offBeatTime + 0.01);
      snareGain.gain.exponentialRampToValueAtTime(0.01, offBeatTime + 0.1);

      snareOsc.connect(snareFilter);
      snareFilter.connect(snareGain);
      snareGain.connect(ctx.destination);
      snareOsc.start(offBeatTime);
      snareOsc.stop(offBeatTime + 0.1);

    }, beatDuration * 1000);
  };

  const playTts = async (buffer: AudioBuffer) => {
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    if (ttsSourceRef.current) {
      try { ttsSourceRef.current.stop(); } catch(e) {}
    }

    const ttsSource = ctx.createBufferSource();
    ttsSource.buffer = buffer;

    const voiceGain = ctx.createGain();
    voiceGain.gain.value = 1.3; 

    ttsSource.connect(voiceGain);
    voiceGain.connect(ctx.destination);
    ttsSourceRef.current = ttsSource;

    ttsSource.onended = () => {
      stopPlayback();
    };

    ttsSource.start(ctx.currentTime + 0.1);
  };

  const handleConvert = async () => {
    if (!inputText.trim()) {
      alert("뉴스를 입력해주세요!");
      return;
    }

    setErrorMessage(null);
    const ctx = initAudioContext();
    if (ctx.state === 'suspended') await ctx.resume();

    stopPlayback();
    startTrotBeat(ctx);
    setIsPlaying(true);

    setIsLoading(true);
    ttsBufferRef.current = null;
    setLyrics(null);

    try {
      // Step 1: 트로트 가사 생성
      const trotLyrics = await generateTrotLyrics(inputText, isMockMode);
      setLyrics(trotLyrics);

      // Step 2: AI 음성 생성
      const audioDataBase64 = await speakTrot(trotLyrics, isMockMode);

      if (isMockMode) {
        setIsLoading(false);
        return;
      }

      if (!audioDataBase64) throw new Error("Audio generation failed");

      const buffer = await decodeAudio(audioDataBase64, ctx);
      ttsBufferRef.current = buffer; 

      // Step 3: 재생
      await playTts(buffer);
    } catch (error: any) {
      console.error(error);
      stopPlayback();
      const msg = error.message === "INTERNAL_SERVER_ERROR" 
        ? "AI 서버 내부 오류(500)가 발생했습니다. 잠시 후 다시 시도해 주세요." 
        : "오디오 제작 중 오류가 발생했습니다. 네트워크 상태를 확인해 주세요.";
      setErrorMessage(msg);
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = async () => {
    if (isPlaying) {
      stopPlayback();
    } else {
      const ctx = initAudioContext();
      await ctx.resume();
      if (ttsBufferRef.current) {
        startTrotBeat(ctx);
        await playTts(ttsBufferRef.current);
        setIsPlaying(true);
      } else if (lyrics && !isMockMode) {
        handleConvert();
      } else {
        startTrotBeat(ctx);
        setIsPlaying(true);
      }
    }
  };

  const handleSave = () => {
    if (!lyrics) return;
    const newItem: SavedAudioNews = {
      id: Date.now(),
      title: inputText.split('\n')[0].slice(0, 20) || "신나는 뉴스",
      lyrics: lyrics,
      timestamp: new Date().toLocaleString('ko-KR', { hour12: false }).slice(0, -3)
    };
    const updated = [newItem, ...savedItems];
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
    alert("보관함에 저장되었습니다.");
  };

  const deleteItem = (e: React.MouseEvent, id: number) => {
    e.stopPropagation();
    const updated = savedItems.filter(item => item.id !== id);
    setSavedItems(updated);
    localStorage.setItem('donga_audio_archive', JSON.stringify(updated));
  };

  return (
    <div className="container-fluid py-2 text-white animate-fade-in">
      <div className="row g-4">
        {/* Sidebar */}
        <div className="col-lg-3">
          <div className="glass-card h-100 p-4 d-flex flex-column rounded-[32px] border-slate-800" style={{ minHeight: '80vh', background: '#0f172a' }}>
            <h5 className="text-white fw-bold mb-4 pb-3 border-bottom border-slate-700 d-flex justify-content-between align-items-center">
              <span className="flex items-center gap-2"><Music size={20} className="text-warning"/> 뉴스 보관함</span>
              <span className="badge bg-slate-800 text-slate-400 px-2">{savedItems.length}</span>
            </h5>
            <div className="overflow-auto custom-scrollbar flex-grow-1 pr-2">
              {savedItems.length === 0 ? (
                <div className="text-center py-10 opacity-30">
                  <Headphones size={48} className="mx-auto mb-3" />
                  <p className="small">제작된 뉴스가 없습니다.</p>
                </div>
              ) : (
                <div className="grid gap-3">
                  {savedItems.map((item) => (
                    <div 
                      key={item.id}
                      onClick={() => { setLyrics(item.lyrics); setInputText(item.title); }}
                      className={`p-4 rounded-2xl transition-all border cursor-pointer position-relative group ${lyrics === item.lyrics ? 'border-warning bg-warning/10 shadow-[0_0_15px_rgba(234,179,8,0.2)]' : 'border-slate-800 bg-slate-900/40 hover:bg-slate-800'}`}
                    >
                      <h6 className="text-white text-truncate mb-2 fw-bold" style={{ fontSize: '0.9rem' }}>{item.title}</h6>
                      <p className="text-slate-500 m-0" style={{ fontSize: '0.7rem' }}>{item.timestamp}</p>
                      <button 
                        onClick={(e) => deleteItem(e, item.id)}
                        className="btn btn-link text-red-500 p-0 position-absolute top-4 end-4 opacity-0 group-hover:opacity-100 transition-all border-0 shadow-none"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Main */}
        <div className="col-lg-9">
          <div className="text-center mb-6">
            <h1 className="display-5 fw-black text-white mb-2 tracking-tighter">
              <span className="text-gradient-trot">DONG-A 트로트 뉴스룸</span>
            </h1>
            <p className="text-slate-400">신명나는 쿵짝 비트와 AI 가수가 전해드리는 특급 뉴스!</p>
          </div>

          <div className="row g-4">
            <div className="col-xl-6">
              <div className="glass-card p-5 h-100 d-flex flex-column rounded-[40px] border-slate-800 shadow-2xl" style={{ background: '#0f172a' }}>
                <div className="d-flex justify-content-between align-items-center mb-4">
                  <label className="text-slate-400 fw-bold text-xs uppercase tracking-widest flex items-center gap-2">
                    <Mic2 size={16} className="text-warning" /> 뉴스 기사 본문
                  </label>
                  <div className="flex gap-1">
                    <span className="w-1 h-4 bg-red-500 animate-[bounce_1s_infinite]"></span>
                    <span className="w-1 h-4 bg-yellow-500 animate-[bounce_1.2s_infinite]"></span>
                    <span className="w-1 h-4 bg-green-500 animate-[bounce_0.8s_infinite]"></span>
                  </div>
                </div>
                <textarea
                  className="form-control bg-slate-950 text-white border-slate-800 mb-5 flex-grow-1 p-4 rounded-3xl shadow-inner custom-scrollbar"
                  style={{ resize: 'none', minHeight: '400px', fontSize: '1rem', lineHeight: '1.7', border: '1px solid rgba(255,255,255,0.05)' }}
                  placeholder="기사를 입력하면 AI가 트로트풍으로 변환해 들려드립니다."
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                ></textarea>

                <div className="d-flex gap-3">
                  <button 
                    className="btn btn-warning flex-grow-1 py-4 rounded-2xl fw-black fs-5 shadow-2xl border-0 transition-transform active:scale-95 flex items-center justify-center gap-3"
                    style={{ background: 'linear-gradient(135deg, #F09819 0%, #EDDE5D 100%)', color: '#000' }}
                    onClick={handleConvert}
                    disabled={isLoading}
                  >
                    {isLoading ? (
                      <><Loader2 className="animate-spin" /> <span>트로트 비트 연주 중...</span></>
                    ) : (
                      <><Play fill="black" /> 🎤 트로트 뉴스 즉시 생성</>
                    )}
                  </button>
                  {lyrics && (
                    <button className="btn btn-outline-slate-700 px-4 rounded-2xl border-slate-800 hover:bg-slate-800 transition-all shadow-lg" onClick={handleSave}>
                      <Save size={24} />
                    </button>
                  )}
                </div>
              </div>
            </div>

            <div className="col-xl-6">
              <div className="glass-card p-5 h-100 d-flex flex-column align-items-center justify-content-center text-center rounded-[40px] border-slate-800 shadow-2xl" style={{ background: '#020617' }}>
                {errorMessage && (
                  <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-2xl text-red-400 text-sm flex items-center gap-3">
                    <AlertCircle size={20} />
                    {errorMessage}
                  </div>
                )}

                {!lyrics && !isLoading ? (
                  <div className="py-20 opacity-20">
                    <div className="bg-slate-900 w-40 h-40 rounded-full flex items-center justify-center mx-auto mb-6 border border-slate-800 shadow-[0_0_50px_rgba(255,255,255,0.05)]">
                      <Music size={80} />
                    </div>
                    <h4 className="fw-black text-slate-500">대기 중</h4>
                    <p className="small">버튼을 누르면 비트가 시작됩니다!</p>
                  </div>
                ) : (
                  <div className="w-100 animate-fade-in">
                    <div className="mb-10 position-relative d-inline-block">
                        <div 
                            className={`rounded-full border-[15px] border-slate-900 mx-auto d-flex align-items-center justify-content-center shadow-3xl ${isPlaying ? 'spin-slow' : ''}`}
                            style={{ 
                                width: '300px', 
                                height: '300px', 
                                background: 'radial-gradient(circle, #334155 10%, #0f172a 40%, #020617 70%)',
                                border: isPlaying ? '15px solid #F0981966' : '15px solid #1e293b',
                                boxShadow: isPlaying ? '0 0 60px rgba(240, 152, 25, 0.3)' : 'none'
                            }}
                        >
                          <div className="rounded-full bg-warning flex items-center justify-center shadow-2xl" style={{ width: '90px', height: '90px', border: '6px solid #000' }}>
                             <Volume2 size={40} className="text-black" />
                          </div>
                        </div>
                        <div className="position-absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 cursor-pointer z-10" onClick={togglePlay}>
                           {isPlaying ? (
                               <Pause size={100} className="text-white fill-white opacity-90 hover:scale-110 transition-all drop-shadow-2xl" />
                           ) : (
                               <Play size={100} className="text-white fill-white opacity-90 hover:scale-110 transition-all translate-x-1 drop-shadow-2xl" />
                           )}
                        </div>
                    </div>

                    <div className="bg-slate-900/60 rounded-3xl p-5 mb-8 text-start border border-slate-800 custom-scrollbar shadow-inner" style={{ maxHeight: '300px', overflowY: 'auto' }}>
                      {isLoading && !lyrics ? (
                        <div className="text-center py-10">
                           <div className="flex justify-center gap-2 mb-4">
                             {[...Array(5)].map((_, i) => (
                               <div key={i} className="w-2 h-8 bg-warning rounded-full animate-[bounce_1s_infinite]" style={{ animationDelay: `${i * 0.1}s` }}></div>
                             ))}
                           </div>
                           <p className="text-warning font-black fs-5">쿵-짝! 쿵-짝! 가사 장전 중...</p>
                           <p className="text-slate-500 small">AI가 트로트 가사를 맛깔나게 쓰고 있습니다.</p>
                        </div>
                      ) : (
                        <pre className="text-white m-0" style={{ fontFamily: 'Pretendard', whiteSpace: 'pre-wrap', lineHeight: '2.0', fontSize: '1.2rem', fontWeight: '600' }}>
                          {lyrics}
                        </pre>
                      )}
                    </div>

