import { GoogleGenAI, Type, Modality } from "@google/genai";

const extractJson = (text: string) => {
  try {
    let cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBrace = cleanText.indexOf('{');
    const firstBracket = cleanText.indexOf('[');
    let startIdx = -1;
    let endIdx = -1;
    if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
      startIdx = firstBrace;
      endIdx = cleanText.lastIndexOf('}');
    } else if (firstBracket !== -1) {
      startIdx = firstBracket;
      endIdx = cleanText.lastIndexOf(']');
    }
    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      return cleanText.substring(startIdx, endIdx + 1);
    }
    return cleanText;
  } catch (e) {
    return text;
  }
};

const handleAIError = (error: any) => {
  console.error("Gemini API Error Details:", error);
  const errorStr = typeof error === 'string' ? error : JSON.stringify(error);
  if (errorStr.includes('429') || errorStr.includes('RESOURCE_EXHAUSTED')) throw new Error("QUOTA_EXCEEDED");
  if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED')) throw new Error("PERMISSION_DENIED");
  if (errorStr.includes('500') || errorStr.includes('INTERNAL')) throw new Error("INTERNAL_SERVER_ERROR");
  throw error;
};

const callWithRetry = async (fn: () => Promise<any>, maxRetries = 3): Promise<any> => {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorStr = JSON.stringify(error);
      if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED')) throw error;
      if (errorStr.includes('429') || errorStr.includes('500') || errorStr.includes('INTERNAL')) {
        const delay = Math.pow(2, i) * 1000;
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
};

const createAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("Critical: API_KEY is missing in the environment.");
  }
  return new GoogleGenAI({ apiKey: apiKey || '' });
};

export const generateCoverageSuggestions = async (isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 800));
    return [
      { id: "1", title: "K-배터리 전고체 전지 로드맵", category: "Tech", angle: "글로벌 점유율 전략", urgency: "High" },
      { id: "2", title: "AI 반도체 수요 폭증과 국내 대응", category: "Economy", angle: "공급망 리스크 분석", urgency: "Medium" },
      { id: "3", title: "디지털 헬스케어와 개인정보 보호", category: "Social", angle: "규제 샌드박스 현황", urgency: "Low" },
      { id: "4", title: "초거대 AI 언어모델의 윤리 기준", category: "Tech", angle: "글로벌 거버넌스", urgency: "High" }
    ];
  }
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `당신은 동아일보의 AI 편집국장입니다. 현재 글로벌 트렌드를 분석하여 실시간으로 취재할 가치가 높은 4가지 아이템을 추천하세요.`,
        config: {
          temperature: 0.2,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                title: { type: Type.STRING },
                category: { type: Type.STRING },
                angle: { type: Type.STRING },
                urgency: { type: Type.STRING }
              },
              required: ["id", "title", "category", "angle", "urgency"]
            }
          }
        }
      });
      return JSON.parse(extractJson(response.text));
    } catch (error) {
      return handleAIError(error);
    }
  });
};

export const generateFactBasedArticle = async (topic: string, category: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 1500));
    return {
      title: `[AI 팩트체크] ${topic}의 실상과 전망`,
      category,
      summary: "1. 이슈 요약 첫 번째 줄입니다.\n2. 데이터 분석 결과입니다.\n3. 향후 전망 요약입니다.",
      content: "<h3>현황 분석</h3><p>현재 <b>주요 지표</b>들은 급격한 변화를 예고하고 있습니다.</p><h3>상세 분석</h3><p>교차 검증 결과 사실로 확인되었습니다.</p>",
      factCheck: "상위 3개 채널 교차 검증 완료",
      sources: ["공식 통계"],
      imageKeyword: topic
    };
  }
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', 
        contents: `주제: "${topic}" (${category})
        당신은 동아일보의 데이터 저널리즘 팀장입니다. 사실을 수집하고 리포트를 작성하세요.`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              category: { type: Type.STRING },
              summary: { type: Type.STRING },
              content: { type: Type.STRING },
              factCheck: { type: Type.STRING },
              sources: { type: Type.ARRAY, items: { type: Type.STRING } },
              imageKeyword: { type: Type.STRING }
            },
            required: ["title", "category", "summary", "content", "factCheck", "sources", "imageKeyword"]
          }
        }
      });
      const parsed = JSON.parse(extractJson(response.text));
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const searchSources = groundingChunks.filter((chunk: any) => chunk.web).map((chunk: any) => ({
        uri: chunk.web.uri,
        title: chunk.web.title
      })).slice(0, 3);
      return { ...parsed, searchSources };
    } catch (error) {
      return handleAIError(error);
    }
  });
};

export const generateImage = async (prompt: string, isMock: boolean = false) => {
  if (isMock) return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: `Professional news photo: ${prompt}. Photorealistic.` }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
      });
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
      }
      return `https://images.unsplash.com/photo-1504711434969-e33886168f5c?auto=format&fit=crop&w=1600&q=80`;
    } catch (error) {
      return handleAIError(error);
    }
  });
};

