import { GoogleGenAI, Type, Modality } from "@google/genai";

const extractJson = (text: string) => {
  try {
    let cleanText = text.replace(/```json/g, "").replace(/```/g, "").trim();
    const firstBrace = cleanText.indexOf('{');
    const firstBracket = cleanText.indexOf('[');
    let startIdx = -1;
    let endIdx = -1;
    if (firstBrace !== -1 && (firstBracket === -1 || firstBrace < firstBracket)) {
      startIdx = firstBrace;
      endIdx = cleanText.lastIndexOf('}');
    } else if (firstBracket !== -1) {
      startIdx = firstBracket;
      endIdx = cleanText.lastIndexOf(']');
    }
    if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
      return cleanText.substring(startIdx, endIdx + 1);
    }
    return cleanText;
  } catch (e) {
    return text;
  }
};

const handleAIError = (error: any) => {
  console.error("Gemini API Error Details:", error);
  const errorStr = typeof error === 'string' ? error : JSON.stringify(error);
  if (errorStr.includes('429') || errorStr.includes('RESOURCE_EXHAUSTED')) throw new Error("QUOTA_EXCEEDED");
  if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED')) throw new Error("PERMISSION_DENIED");
  if (errorStr.includes('500') || errorStr.includes('INTERNAL')) throw new Error("INTERNAL_SERVER_ERROR");
  throw error;
};

const callWithRetry = async (fn: () => Promise<any>, maxRetries = 3): Promise<any> => {
  let lastError: any;
  for (let i = 0; i < maxRetries; i++) {
    try {
      return await fn();
    } catch (error: any) {
      lastError = error;
      const errorStr = JSON.stringify(error);
      if (errorStr.includes('403') || errorStr.includes('PERMISSION_DENIED')) throw error;
      if (errorStr.includes('429') || errorStr.includes('500') || errorStr.includes('INTERNAL')) {
        const delay = Math.pow(2, i) * 1000;
        await new Promise(r => setTimeout(r, delay));
        continue;
      }
      throw error;
    }
  }
  throw lastError;
};

const createAI = () => {
  const apiKey = process.env.API_KEY;
  return new GoogleGenAI({ apiKey: apiKey || '' });
};

