                  </button>
                  {lyrics && !isLoading && (
                    <button className="btn btn-outline-slate-700 px-4 rounded-2xl border-slate-800 hover:bg-slate-800 transition-all shadow-lg text-red-500" title="저장하기" onClick={handleSave}>
