export const generateFactBasedArticle = async (topic: string, category: string, isMock: boolean = false) => {
  if (isMock) {
    await new Promise(resolve => setTimeout(resolve, 1500));
    return {
      title: `[분석] ${topic}의 핵심 포인트`,
      category,
      summary: "AI가 분석한 실시간 핵심 요약 기사입니다.",
      content: "<p>이번 사건은 해당 업계에 큰 파장을 일으키고 있습니다.</p><p>전문가들은 이번 변화가 장기적인 트렌드가 될 것으로 내다보고 있습니다.</p>",
      factCheck: "상위 채널 교차 검증 완료",
      sources: ["관련 공식 발표"],
      imageKeyword: topic
    };
  }
  return callWithRetry(async () => {
    try {
      const ai = createAI();
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview', 
        contents: `주제: "${topic}" (카테고리: ${category})
        당신은 동아일보의 전문 기자입니다. 위 주제와 카테고리에 맞는 심층 기사를 작성하세요.

        [지침]
        1. ###, **, *** 와 같은 마크다운 기호를 절대 사용하지 마세요. (매우 중요)
        2. 기사 본문은 가독성을 위해 <p> 태그를 사용하여 문단을 나누세요.
        3. 소제목은 <h3 style="font-weight: bold; margin-top: 24px; color: white;">제목</h3> 형식을 사용하세요.
        4. 문장 끝에는 마침표를 정확히 찍고 가독성이 좋게 줄바꿈을 처리하세요.`,
        config: {
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              category: { type: Type.STRING },
              summary: { type: Type.STRING },
              content: { type: Type.STRING },
              factCheck: { type: Type.STRING },
              sources: { type: Type.ARRAY, items: { type: Type.STRING } },
              imageKeyword: { type: Type.STRING }
            },
            required: ["title", "category", "summary", "content", "factCheck", "sources", "imageKeyword"]
          }
        }
      });
      const parsed = JSON.parse(extractJson(response.text));
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const searchSources = groundingChunks.filter((chunk: any) => chunk.web).map((chunk: any) => ({
        uri: chunk.web.uri,
        title: chunk.web.title
      })).slice(0, 3);
      return { ...parsed, searchSources };
    } catch (error) {
      return handleAIError(error);
    }
  });
};

