    let cleaned = text.replace(/[#*`_~]{1,}/g, "").trim();
    // 문단 가독성 개선
    if (!cleaned.includes("<p>")) {
      cleaned = cleaned.split('\n\n').map(p => `<p style="margin-bottom: 1.5rem; line-height: 1.8;">${p.trim()}</p>`).join('');
    }
    return cleaned;
  };

  useEffect(() => {
    try {
      localStorage.setItem('donga_writer_topic', topic);
      localStorage.setItem('donga_writer_category', category);
      if (articleData) localStorage.setItem('donga_writer_article', JSON.stringify(articleData));
      if (imageResult) localStorage.setItem('donga_writer_image', imageResult);
    } catch (e) {
      console.warn("Storage limit reached");
    }
  }, [topic, category, articleData, imageResult]);

  const fetchSuggestions = useCallback(async () => {
    setLoadingSuggestions(true);
    try {
      const data = await generateCoverageSuggestions(isMockMode);
      setSuggestions(data || []);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingSuggestions(false);
    }
  }, [isMockMode]);

  useEffect(() => {
    fetchSuggestions();
  }, [fetchSuggestions]);

  const saveToDashboard = (newArticle: any) => {
    try {
      const saved = localStorage.getItem('dashboard_db');
      let list = saved ? JSON.parse(saved) : [];
