          <button onClick={() => { setTopic(""); setArticleData(null); setImageResult(null); }} className="btn btn-link text-slate-500 text-xs no-underline"><Trash2 size={14}/> 초기화</button>
        </div>
        <div className="row g-3">
          {suggestions.map(item => (
