              <div onClick={() => { setTopic(item.title); setCategory(item.category.toLowerCase()); window.scrollTo({top: 400, behavior:'smooth'}); }} className="glass-card p-4 rounded-2xl border-slate-800 hover:border-blue-500/50 transition-all cursor-pointer h-100 flex flex-col justify-between">
                <div>
                  <div className="flex justify-between items-center mb-2"><span className="text-[9px] font-black px-2 py-0.5 rounded bg-red-500/10 text-red-500 uppercase">{item.urgency}</span><span className="text-[10px] text-blue-400 uppercase">{item.category}</span></div>
