          </div>
          <div className="col-md-8"><input className="form-control py-3 px-4 text-lg" placeholder="기사 주제를 입력하세요..." value={topic} onChange={e => setTopic(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleCreate()}/></div>
          <div className="col-md-2"><button className="btn btn-primary w-100 py-3 font-black flex items-center justify-center gap-2" onClick={handleCreate} disabled={loading}>{loading ? <Loader2 className="animate-spin" size={20}/> : <Cpu size={18}/>} 생성</button></div>
        </div>
        {(loading || errorMsg) && (
          <div className={`mt-5 p-5 rounded-3xl text-center animate-fade-in ${errorMsg ? 'bg-red-500/10' : 'bg-blue-500/10'}`}>
            {errorMsg ? <AlertCircle size={40} className="mx-auto mb-3 text-red-500"/> : <Loader2 size={40} className="mx-auto mb-3 animate-spin text-blue-400"/>}
            <h5 className="font-black">{errorMsg || statusText}</h5>
            {showQuotaPrompt && <button onClick={() => { setIsMockMode(true); setTimeout(handleCreate, 100); }} className="btn btn-amber-500 mt-4 px-10 rounded-xl font-bold bg-amber-600 text-white border-0"><Zap size={16}/> 데모 모드로 전환</button>}
          </div>
        )}
      </div>

      {articleData && (
        <div className="row g-4 animate-fade-in">
          <div className="col-lg-9">
            <div className="glass-card p-5 rounded-4 bg-slate-900">
              <div className="flex justify-between items-start mb-4">
                {isEditMode ? <input className="form-control fs-2 font-black" value={editTitle} onChange={e => setEditTitle(e.target.value)}/> : <h1 className="font-black display-6">{articleData.title}</h1>}
                <div className="flex gap-2">
                  {isEditMode ? <button className="btn btn-primary px-4 py-2" onClick={saveEdit}>저장</button> : (
                    <>
                      <button className="btn btn-outline-slate-700 text-slate-400" onClick={startEdit}><Edit3 size={18}/></button>
                      <button className="btn btn-outline-blue-500 text-blue-400" onClick={handleCopy}><Copy size={18}/></button>
                    </>
                  )}
                </div>
              </div>
              {isEditMode ? <textarea className="form-control" style={{minHeight:'400px'}} value={editContent} onChange={e => setEditContent(e.target.value)}/> : <div className="text-slate-300 text-xl leading-relaxed" dangerouslySetInnerHTML={{__html: articleData.content}}/>}
            </div>
          </div>
          <div className="col-lg-3">
            <div className="glass-card p-4 rounded-4 mb-4 border-slate-800" style={{aspectRatio:'16/9'}} onClick={() => setIsZoomed(true)}>
              {imageResult ? <img src={imageResult} className="w-100 h-100 object-cover rounded-xl" /> : <div className="h-100 flex items-center justify-center opacity-20"><ImageIcon size={40}/></div>}
            </div>
            <div className="glass-card p-4 rounded-4 mb-4 border-slate-800 bg-blue-600/5">
              <h6 className="text-blue-400 font-black text-xs uppercase mb-3"><Quote size={14}/> 요약</h6>
              <p className="text-sm m-0 leading-relaxed text-slate-300">{articleData.summary}</p>
            </div>
            <div className="glass-card p-4 rounded-4 border-slate-800 bg-green-600/5">
              <h6 className="text-green-400 font-black text-xs uppercase mb-2"><ShieldAlert size={14}/> 팩트체크</h6>
              <p className="text-xs m-0 text-slate-500">{articleData.factCheck}</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AIWriter;
